import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  ADMIN = 'ADMIN',
  MANAGER = 'MANAGER',
  EMPLOYEE = 'EMPLOYEE',
}

export interface Store {
  id: string;
  name: string;
  category: string;
  logoUrl: string;
  coverUrl: string;
  floor: string;
}

export interface Coupon {
  id: string;
  storeId: string;
  title: string;
  description: string;
  discountType: 'PERCENTAGE' | 'FIXED';
  discountValue: number;
  expiryDate: string;
  rules: string[];
  category: string;
  availableQuantity: number;
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  storeId?: string;
  avatarUrl?: string;
}

export interface Redemption {
  id: string;
  couponId: string;
  userId: string;
  code: string;
  status: 'PENDING' | 'USED' | 'EXPIRED';
  redeemedAt: string;
}

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false, 
  className = '',
  ...props 
}) => {
  const baseStyles = "font-semibold py-3 px-6 rounded-xl transition-all duration-200 flex items-center justify-center gap-2 active:scale-95 disabled:opacity-50 disabled:pointer-events-none";

  const variants = {
    primary: "bg-primary-600 text-white shadow-lg shadow-primary-200 hover:bg-primary-700 hover:shadow-xl",
    secondary: "bg-gray-100 text-gray-800 hover:bg-gray-200",
    outline: "border-2 border-primary-600 text-primary-600 hover:bg-primary-50",
    ghost: "text-gray-500 hover:text-gray-800 hover:bg-gray-50"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React from 'react';
import { Coupon, Store } from '../types';
import { Button } from './Button';

interface CouponCardProps {
  coupon: Coupon;
  store: Store;
  onClick: () => void;
}

export const CouponCard: React.FC<CouponCardProps> = ({ coupon, store, onClick }) => {
  // Determine gradient based on category for visual variety
  const getGradient = (cat: string) => {
    switch(cat) {
      case 'Alimentação': return 'from-orange-400/20 to-red-400/20';
      case 'Moda': return 'from-purple-400/20 to-pink-400/20';
      case 'Esportes': return 'from-blue-400/20 to-cyan-400/20';
      default: return 'from-gray-200 to-gray-100';
    }
  };

  return (
    <div 
      className="group bg-white rounded-2xl overflow-hidden border border-gray-100 shadow-sm hover:shadow-xl transition-all duration-300 flex flex-col h-full cursor-pointer relative"
      onClick={onClick}
    >
      {/* Discount Badge */}
      <div className="absolute top-3 right-3 z-10">
        <div className="bg-white/90 backdrop-blur-sm px-3 py-1 rounded-full shadow-sm border border-gray-100">
          <span className="text-primary-700 font-bold text-sm">
            {coupon.discountType === 'PERCENTAGE' 
              ? `${coupon.discountValue}% OFF` 
              : `R$ ${coupon.discountValue} OFF`}
          </span>
        </div>
      </div>

      {/* Image Section */}
      <div className="relative h-40 overflow-hidden">
        <div className={`absolute inset-0 bg-gradient-to-br ${getGradient(store.category)} mix-blend-multiply opacity-50 z-0`} />
        <img 
          src={store.coverUrl} 
          alt={store.name} 
          className="w-full h-full object-cover transform group-hover:scale-105 transition-transform duration-500"
        />
        {/* Logo overlay */}
        <div className="absolute -bottom-6 left-4 bg-white p-1 rounded-xl shadow-md border border-gray-100 w-16 h-16 flex items-center justify-center z-10">
           {/* Fallback if logo fails, though real apps use real logos */}
           <div className="w-full h-full rounded-lg overflow-hidden bg-white flex items-center justify-center">
             {store.logoUrl.includes('http') ? (
                <img src={store.logoUrl} alt="logo" className="w-full h-full object-contain" />
             ) : (
                <span className="text-xs font-bold text-gray-400">{store.name.substring(0,2)}</span>
             )}
           </div>
        </div>
      </div>

      {/* Content Section */}
      <div className="p-4 pt-8 flex-1 flex flex-col">
        <div className="flex justify-between items-start mb-1">
          <span className="text-xs font-semibold text-gray-500 uppercase tracking-wide">
            {store.category} • {store.floor}
          </span>
        </div>

        <h3 className="text-lg font-bold text-gray-800 leading-tight mb-2 line-clamp-2">
          {coupon.title}
        </h3>

        <p className="text-gray-500 text-sm mb-4 line-clamp-2 flex-1">
          {coupon.description}
        </p>

        <div className="flex items-center justify-between mt-auto pt-4 border-t border-gray-50">
          <div className="text-xs text-gray-400">
            Válido até <br/>
            <span className="text-gray-600 font-medium">
              {new Date(coupon.expiryDate).toLocaleDateString('pt-BR')}
            </span>
          </div>

          <Button 
            variant="outline" 
            className="!py-2 !px-4 !text-sm !rounded-lg group-hover:bg-primary-600 group-hover:text-white group-hover:border-primary-600"
            onClick={(e) => {
              e.stopPropagation();
              onClick();
            }}
          >
            Ver Cupom
          </Button>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect } from 'react';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  children: React.ReactNode;
}

export const Modal: React.FC<ModalProps> = ({ isOpen, onClose, children }) => {
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => {
      document.body.style.overflow = 'unset';
    };
  }, [isOpen]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-gray-900/60 backdrop-blur-sm transition-opacity" 
        onClick={onClose}
      />

      {/* Content */}
      <div className="relative bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden max-h-[90vh] overflow-y-auto animate-fade-in-up">
        <button 
          onClick={onClose}
          className="absolute top-4 right-4 z-10 bg-white/50 backdrop-blur rounded-full p-2 hover:bg-white text-gray-700 transition-colors"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
        {children}
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { STORES, COUPONS, CATEGORIES, CURRENT_USER } from './constants';
import { Coupon, Store, User } from './types';
import { CouponCard } from './components/CouponCard';
import { Button } from './components/Button';
import { Modal } from './components/Modal';

// Icons
const SearchIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
  </svg>
);

const UserIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
  </svg>
);

const TicketIcon = () => (
  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 5v2m0 4v2m0 4v2M5 5a2 2 0 00-2 2v3a2 2 0 110 4v3a2 2 0 002 2h14a2 2 0 002-2v-3a2 2 0 110-4V7a2 2 0 00-2-2H5z" />
  </svg>
);

export default function App() {
  const [selectedCategory, setSelectedCategory] = useState('Todos');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCoupon, setSelectedCoupon] = useState<{coupon: Coupon, store: Store} | null>(null);
  const [isRedeeming, setIsRedeeming] = useState(false);
  const [redemptionCode, setRedemptionCode] = useState<string | null>(null);

  // Filter Logic
  const filteredCoupons = useMemo(() => {
    return COUPONS.filter(coupon => {
      const store = STORES.find(s => s.id === coupon.storeId);
      if (!store) return false;

      const matchesCategory = selectedCategory === 'Todos' || coupon.category === selectedCategory;
      const matchesSearch = 
        coupon.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        store.name.toLowerCase().includes(searchQuery.toLowerCase());

      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery]);

  // Handlers
  const handleOpenCoupon = (coupon: Coupon) => {
    const store = STORES.find(s => s.id === coupon.storeId);
    if (store) {
      setSelectedCoupon({ coupon, store });
      setIsRedeeming(false);
      setRedemptionCode(null);
    }
  };

  const handleRedeem = () => {
    setIsRedeeming(true);
    // Simulate API Call
    setTimeout(() => {
      setRedemptionCode(`CPN-${Math.random().toString(36).substr(2, 6).toUpperCase()}`);
      setIsRedeeming(false);
    }, 1500);
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      {/* Header / Navbar */}
      <nav className="bg-white sticky top-0 z-30 border-b border-gray-100/50 backdrop-blur-md bg-white/80">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center gap-2">
              <div className="bg-primary-600 rounded-lg p-1.5">
                <TicketIcon className="text-white w-5 h-5" /> {/* Fixed JSX issue with icon */}
              </div>
              <span className="font-bold text-xl tracking-tight text-gray-900">ShopPerks</span>
            </div>

            <div className="flex items-center gap-4">
               <div className="hidden md:flex flex-col items-end mr-2">
                 <span className="text-sm font-semibold text-gray-700">{CURRENT_USER.name}</span>
                 <span className="text-xs text-gray-500">Loja: {STORES.find(s => s.id === CURRENT_USER.storeId)?.name}</span>
               </div>
               <img 
                 src={CURRENT_USER.avatarUrl} 
                 alt="User" 
                 className="w-9 h-9 rounded-full border-2 border-primary-100"
               />
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 pt-8">

        {/* Hero / Welcome */}
        <div className="mb-10">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">
            Olá, {CURRENT_USER.name.split(' ')[0]}! 👋
          </h1>
          <p className="text-gray-500">
            Confira as vantagens exclusivas que seus colegas prepararam para você hoje.
          </p>
        </div>

        {/* Search & Filter */}
        <div className="flex flex-col md:flex-row gap-4 mb-8 sticky top-20 z-20 md:static">
          <div className="relative flex-1">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
              <SearchIcon />
            </div>
            <input
              type="text"
              placeholder="Busque por loja ou desconto..."
              className="block w-full pl-10 pr-3 py-3 border border-gray-200 rounded-xl leading-5 bg-white placeholder-gray-400 focus:outline-none focus:border-primary-500 focus:ring-2 focus:ring-primary-200 sm:text-sm shadow-sm transition-all"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>

          <div className="flex gap-2 overflow-x-auto pb-2 md:pb-0 no-scrollbar">
            {CATEGORIES.map(cat => (
              <button
                key={cat}
                onClick={() => setSelectedCategory(cat)}
                className={`
                  whitespace-nowrap px-4 py-2.5 rounded-xl text-sm font-medium transition-all
                  ${selectedCategory === cat 
                    ? 'bg-gray-900 text-white shadow-lg' 
                    : 'bg-white text-gray-600 border border-gray-200 hover:bg-gray-50'}
                `}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        {/* Coupons Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredCoupons.map(coupon => {
            const store = STORES.find(s => s.id === coupon.storeId);
            if (!store) return null;
            return (
              <CouponCard 
                key={coupon.id} 
                coupon={coupon} 
                store={store} 
                onClick={() => handleOpenCoupon(coupon)}
              />
            );
          })}
        </div>

        {filteredCoupons.length === 0 && (
          <div className="text-center py-20">
             <div className="bg-gray-100 rounded-full w-16 h-16 flex items-center justify-center mx-auto mb-4">
                <SearchIcon />
             </div>
             <h3 className="text-lg font-medium text-gray-900">Nenhum cupom encontrado</h3>
             <p className="text-gray-500 mt-1">Tente ajustar sua busca ou filtros.</p>
          </div>
        )}
      </main>

      {/* Coupon Detail Modal */}
      {selectedCoupon && (
        <Modal isOpen={!!selectedCoupon} onClose={() => setSelectedCoupon(null)}>
          <div className="relative">
            {/* Header Image */}
            <div className="h-48 relative">
              <img 
                src={selectedCoupon.store.coverUrl} 
                className="w-full h-full object-cover" 
                alt="Cover" 
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
              <div className="absolute bottom-4 left-6 flex items-center gap-3">
                 <div className="w-12 h-12 bg-white rounded-lg p-1">
                    <img src={selectedCoupon.store.logoUrl} className="w-full h-full object-contain" alt="logo"/>
                 </div>
                 <div className="text-white">
                   <p className="font-bold text-lg">{selectedCoupon.store.name}</p>
                   <p className="text-xs opacity-90">{selectedCoupon.store.floor}</p>
                 </div>
              </div>
            </div>

            {/* Content */}
            <div className="p-6">
              {!redemptionCode ? (
                <>
                  <div className="mb-6">
                    <h2 className="text-2xl font-bold text-gray-900 mb-2">{selectedCoupon.coupon.title}</h2>
                    <p className="text-gray-600 leading-relaxed">{selectedCoupon.coupon.description}</p>
                  </div>

                  <div className="bg-gray-50 rounded-xl p-4 mb-6 border border-gray-100">
                    <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-3">Regras de Uso</h4>
                    <ul className="space-y-2">
                      {selectedCoupon.coupon.rules.map((rule, idx) => (
                        <li key={idx} className="flex items-start gap-2 text-sm text-gray-600">
                          <span className="text-primary-500 font-bold">•</span>
                          {rule}
                        </li>
                      ))}
                    </ul>
                  </div>

                  <div className="flex items-center justify-between text-sm text-gray-500 mb-6 px-1">
                    <span>Validade: {new Date(selectedCoupon.coupon.expiryDate).toLocaleDateString()}</span>
                    <span>Restantes: {selectedCoupon.coupon.availableQuantity}</span>
                  </div>

                  <Button 
                    fullWidth 
                    onClick={handleRedeem}
                    disabled={isRedeeming}
                  >
                    {isRedeeming ? 'Gerando Código...' : 'Resgatar Cupom'}
                  </Button>
                </>
              ) : (
                <div className="flex flex-col items-center justify-center py-8 animate-fade-in">
                  <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-4">
                    <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                    </svg>
                  </div>
                  <h3 className="text-xl font-bold text-gray-900 mb-2">Resgatado com Sucesso!</h3>
                  <p className="text-gray-500 text-center text-sm mb-6 px-8">
                    Apresente este código ao caixa da {selectedCoupon.store.name} para validar seu desconto.
                  </p>

                  <div className="bg-gray-900 text-white text-2xl font-mono font-bold py-4 px-8 rounded-xl tracking-widest mb-6 border-2 border-dashed border-gray-600">
                    {redemptionCode}
                  </div>

                  {/* QR Code Placeholder */}
                  <div className="w-40 h-40 bg-white border-2 border-gray-200 rounded-xl p-2 mb-6">
                    <img src={`https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=${redemptionCode}`} alt="QR Code" className="w-full h-full" />
                  </div>

                  <p className="text-xs text-center text-gray-400">
                    Este código expira em 24 horas.
                  </p>
                </div>
              )}
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { STORES, COUPONS, CATEGORIES, CURRENT_USER, MY_REDEMPTIONS } from './constants';
import { Coupon, Store, User, Redemption } from './types';
import { CouponCard } from './components/CouponCard';
import { Button } from './components/Button';
import { Modal } from './components/Modal';

// Icons
const SearchIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
  </svg>
);

const UserIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
  </svg>
);

const TicketIcon = () => (
  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 5v2m0 4v2m0 4v2M5 5a2 2 0 00-2 2v3a2 2 0 110 4v3a2 2 0 002 2h14a2 2 0 002-2v-3a2 2 0 110-4V7a2 2 0 00-2-2H5z" />
  </svg>
);

const ClockIcon = () => (
  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
  </svg>
);

export default function App() {
  const [currentView, setCurrentView] = useState<'home' | 'my-coupons'>('home');
  const [selectedCategory, setSelectedCategory] = useState('Todos');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCoupon, setSelectedCoupon] = useState<{coupon: Coupon, store: Store} | null>(null);
  const [isRedeeming, setIsRedeeming] = useState(false);
  const [redemptionCode, setRedemptionCode] = useState<string | null>(null);
  const [myRedemptions, setMyRedemptions] = useState<Redemption[]>(MY_REDEMPTIONS);

  // Filter Logic
  const filteredCoupons = useMemo(() => {
    return COUPONS.filter(coupon => {
      const store = STORES.find(s => s.id === coupon.storeId);
      if (!store) return false;

      const matchesCategory = selectedCategory === 'Todos' || coupon.category === selectedCategory;
      const matchesSearch = 
        coupon.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        store.name.toLowerCase().includes(searchQuery.toLowerCase());

      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery]);

  // Handlers
  const handleOpenCoupon = (coupon: Coupon) => {
    const store = STORES.find(s => s.id === coupon.storeId);
    if (store) {
      setSelectedCoupon({ coupon, store });
      setIsRedeeming(false);
      setRedemptionCode(null);
    }
  };

  const handleRedeem = () => {
    if (!selectedCoupon) return;
    setIsRedeeming(true);

    // Simulate API Call
    setTimeout(() => {
      const code = `CPN-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;
      setRedemptionCode(code);

      // Add to local redemptions history
      const newRedemption: Redemption = {
        id: Math.random().toString(36),
        couponId: selectedCoupon.coupon.id,
        userId: CURRENT_USER.id,
        code: code,
        status: 'PENDING',
        redeemedAt: new Date().toISOString()
      };

      setMyRedemptions(prev => [newRedemption, ...prev]);
      setIsRedeeming(false);
    }, 1500);
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      {/* Header / Navbar */}
      <nav className="bg-white sticky top-0 z-30 border-b border-gray-100/50 backdrop-blur-md bg-white/80">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div 
              className="flex items-center gap-2 cursor-pointer" 
              onClick={() => setCurrentView('home')}
            >
              <div className="bg-primary-600 rounded-lg p-1.5">
                <TicketIcon />
              </div>
              <span className="font-bold text-xl tracking-tight text-gray-900 hidden sm:block">ShopPerks</span>
            </div>

            <div className="flex items-center gap-6">
               <div className="flex items-center bg-gray-100 p-1 rounded-xl">
                 <button 
                   onClick={() => setCurrentView('home')}
                   className={`px-4 py-1.5 rounded-lg text-sm font-semibold transition-all ${currentView === 'home' ? 'bg-white text-primary-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                 >
                   Início
                 </button>
                 <button 
                   onClick={() => setCurrentView('my-coupons')}
                   className={`px-4 py-1.5 rounded-lg text-sm font-semibold transition-all ${currentView === 'my-coupons' ? 'bg-white text-primary-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                 >
                   Meus Cupons
                 </button>
               </div>

               <div className="flex items-center gap-3 border-l border-gray-200 pl-6">
                 <div className="hidden md:flex flex-col items-end">
                   <span className="text-sm font-semibold text-gray-700">{CURRENT_USER.name}</span>
                 </div>
                 <img 
                   src={CURRENT_USER.avatarUrl} 
                   alt="User" 
                   className="w-9 h-9 rounded-full border-2 border-primary-100"
                 />
               </div>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 pt-8">

        {currentView === 'home' ? (
          <>
            {/* Hero / Welcome */}
            <div className="mb-10 animate-fade-in-up">
              <h1 className="text-3xl font-bold text-gray-900 mb-2">
                Olá, {CURRENT_USER.name.split(' ')[0]}! 👋
              </h1>
              <p className="text-gray-500">
                Confira as vantagens exclusivas que seus colegas prepararam para você hoje.
              </p>
            </div>

            {/* Search & Filter */}
            <div className="flex flex-col md:flex-row gap-4 mb-8 sticky top-20 z-20 md:static">
              <div className="relative flex-1">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                  <SearchIcon />
                </div>
                <input
                  type="text"
                  placeholder="Busque por loja ou desconto..."
                  className="block w-full pl-10 pr-3 py-3 border border-gray-200 rounded-xl leading-5 bg-white placeholder-gray-400 focus:outline-none focus:border-primary-500 focus:ring-2 focus:ring-primary-200 sm:text-sm shadow-sm transition-all"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>

              <div className="flex gap-2 overflow-x-auto pb-2 md:pb-0 no-scrollbar">
                {CATEGORIES.map(cat => (
                  <button
                    key={cat}
                    onClick={() => setSelectedCategory(cat)}
                    className={`
                      whitespace-nowrap px-4 py-2.5 rounded-xl text-sm font-medium transition-all
                      ${selectedCategory === cat 
                        ? 'bg-gray-900 text-white shadow-lg' 
                        : 'bg-white text-gray-600 border border-gray-200 hover:bg-gray-50'}
                    `}
                  >
                    {cat}
                  </button>
                ))}
              </div>
            </div>

            {/* Coupons Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {filteredCoupons.map(coupon => {
                const store = STORES.find(s => s.id === coupon.storeId);
                if (!store) return null;
                return (
                  <CouponCard 
                    key={coupon.id} 
                    coupon={coupon} 
                    store={store} 
                    onClick={() => handleOpenCoupon(coupon)}
                  />
                );
              })}
            </div>

            {filteredCoupons.length === 0 && (
              <div className="text-center py-20">
                 <div className="bg-gray-100 rounded-full w-16 h-16 flex items-center justify-center mx-auto mb-4">
                    <SearchIcon />
                 </div>
                 <h3 className="text-lg font-medium text-gray-900">Nenhum cupom encontrado</h3>
                 <p className="text-gray-500 mt-1">Tente ajustar sua busca ou filtros.</p>
              </div>
            )}
          </>
        ) : (
          /* MY COUPONS VIEW */
          <div className="max-w-2xl mx-auto animate-fade-in-up">
            <h2 className="text-2xl font-bold text-gray-900 mb-6 flex items-center gap-2">
              <TicketIcon /> Meus Cupons Resgatados
            </h2>

            <div className="space-y-4">
              {myRedemptions.length === 0 ? (
                <div className="text-center py-12 bg-white rounded-3xl border border-gray-100 shadow-sm">
                   <div className="bg-gray-50 rounded-full w-16 h-16 flex items-center justify-center mx-auto mb-4 text-gray-400">
                      <TicketIcon />
                   </div>
                   <h3 className="text-lg font-medium text-gray-900">Você ainda não tem cupons</h3>
                   <p className="text-gray-500 mt-1 mb-6">Explore o shopping e resgate descontos!</p>
                   <Button onClick={() => setCurrentView('home')}>Explorar Cupons</Button>
                </div>
              ) : (
                myRedemptions.map(redemption => {
                  const coupon = COUPONS.find(c => c.id === redemption.couponId);
                  const store = STORES.find(s => s.id === coupon?.storeId);
                  if (!coupon || !store) return null;

                  const statusConfig = {
                    PENDING: { color: 'bg-green-100 text-green-700 border-green-200', text: 'Disponível' },
                    USED: { color: 'bg-gray-100 text-gray-600 border-gray-200', text: 'Utilizado' },
                    EXPIRED: { color: 'bg-red-100 text-red-600 border-red-200', text: 'Expirado' }
                  };

                  const status = statusConfig[redemption.status];

                  return (
                    <div key={redemption.id} className="bg-white rounded-2xl p-4 border border-gray-100 shadow-sm hover:shadow-md transition-shadow flex flex-col sm:flex-row gap-4 items-start sm:items-center">
                      <div className="w-16 h-16 rounded-xl border border-gray-100 p-1 flex-shrink-0">
                         <img src={store.logoUrl} alt={store.name} className="w-full h-full object-contain rounded-lg" />
                      </div>

                      <div className="flex-1">
                        <div className="flex justify-between items-start">
                          <div>
                            <p className="text-xs font-semibold text-gray-500 uppercase">{store.name}</p>
                            <h3 className="font-bold text-gray-900">{coupon.title}</h3>
                          </div>
                        </div>
                        <div className="mt-2 flex items-center gap-4 text-xs text-gray-500">
                          <span className="flex items-center gap-1">
                             <ClockIcon /> {new Date(redemption.redeemedAt).toLocaleDateString()}
                          </span>
                          <span className="font-mono bg-gray-50 px-2 py-1 rounded border border-gray-200 text-gray-700">
                            {redemption.code}
                          </span>
                        </div>
                      </div>

                      <div className={`px-3 py-1 rounded-full text-xs font-bold border ${status.color} self-start sm:self-center`}>
                        {status.text}
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        )}
      </main>

      {/* Coupon Detail Modal */}
      {selectedCoupon && (
        <Modal isOpen={!!selectedCoupon} onClose={() => setSelectedCoupon(null)}>
          <div className="relative">
            {/* Header Image */}
            <div className="h-48 relative">
              <img 
                src={selectedCoupon.store.coverUrl} 
                className="w-full h-full object-cover" 
                alt="Cover" 
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
              <div className="absolute bottom-4 left-6 flex items-center gap-3">
                 <div className="w-12 h-12 bg-white rounded-lg p-1">
                    <img src={selectedCoupon.store.logoUrl} className="w-full h-full object-contain" alt="logo"/>
                 </div>
                 <div className="text-white">
                   <p className="font-bold text-lg">{selectedCoupon.store.name}</p>
                   <p className="text-xs opacity-90">{selectedCoupon.store.floor}</p>
                 </div>
              </div>
            </div>

            {/* Content */}
            <div className="p-6">
              {!redemptionCode ? (
                <>
                  <div className="mb-6">
                    <h2 className="text-2xl font-bold text-gray-900 mb-2">{selectedCoupon.coupon.title}</h2>
                    <p className="text-gray-600 leading-relaxed">{selectedCoupon.coupon.description}</p>
                  </div>

                  <div className="bg-gray-50 rounded-xl p-4 mb-6 border border-gray-100">
                    <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-3">Regras de Uso</h4>
                    <ul className="space-y-2">
                      {selectedCoupon.coupon.rules.map((rule, idx) => (
                        <li key={idx} className="flex items-start gap-2 text-sm text-gray-600">
                          <span className="text-primary-500 font-bold">•</span>
                          {rule}
                        </li>
                      ))}
                    </ul>
                  </div>

                  <div className="flex items-center justify-between text-sm text-gray-500 mb-6 px-1">
                    <span>Validade: {new Date(selectedCoupon.coupon.expiryDate).toLocaleDateString()}</span>
                    <span>Restantes: {selectedCoupon.coupon.availableQuantity}</span>
                  </div>

                  <Button 
                    fullWidth 
                    onClick={handleRedeem}
                    disabled={isRedeeming}
                  >
                    {isRedeeming ? 'Gerando Código...' : 'Resgatar Cupom'}
                  </Button>
                </>
              ) : (
                <div className="flex flex-col items-center justify-center py-8 animate-fade-in">
                  <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-4">
                    <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                    </svg>
                  </div>
                  <h3 className="text-xl font-bold text-gray-900 mb-2">Resgatado com Sucesso!</h3>
                  <p className="text-gray-500 text-center text-sm mb-6 px-8">
                    Apresente este código ao caixa da {selectedCoupon.store.name} para validar seu desconto.
                  </p>

                  <div className="bg-gray-900 text-white text-2xl font-mono font-bold py-4 px-8 rounded-xl tracking-widest mb-6 border-2 border-dashed border-gray-600">
                    {redemptionCode}
                  </div>

                  {/* QR Code Placeholder */}
                  <div className="w-40 h-40 bg-white border-2 border-gray-200 rounded-xl p-2 mb-6">
                    <img src={`https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=${redemptionCode}`} alt="QR Code" className="w-full h-full" />
                  </div>

                  <p className="text-xs text-center text-gray-400">
                    Este código expira em 24 horas.
                  </p>

                  <Button variant="secondary" onClick={() => setSelectedCoupon(null)} className="mt-4">
                    Fechar e Voltar
                  </Button>
                </div>
              )}
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
}

export enum UserRole {
  ADMIN = 'ADMIN',
  MANAGER = 'MANAGER',
  EMPLOYEE = 'EMPLOYEE',
}

export interface Store {
  id: string;
  name: string;
  category: string;
  logoUrl: string;
  coverUrl: string;
  floor: string;
}

export interface Coupon {
  id: string;
  storeId: string;
  title: string;
  description: string;
  discountType: 'PERCENTAGE' | 'FIXED';
  discountValue: number;
  expiryDate: string;
  rules: string[];
  category: string;
  availableQuantity: number;
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  storeId?: string;
  avatarUrl?: string;
}

export interface Redemption {
  id: string;
  couponId: string;
  userId: string;
  code: string;
  status: 'PENDING' | 'USED' | 'EXPIRED';
  redeemedAt: string;
  validatedBy?: string; // Name of the store manager/employee who validated it
  validatedAt?: string;
}

import React, { useState, useMemo } from 'react';
import { STORES, COUPONS, CATEGORIES, CURRENT_USER, MY_REDEMPTIONS } from './constants';
import { Coupon, Store, User, Redemption } from './types';
import { CouponCard } from './components/CouponCard';
import { Button } from './components/Button';
import { Modal } from './components/Modal';

// Icons
const SearchIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
  </svg>
);

const FilterIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" />
  </svg>
);

const BellIcon = () => (
  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
  </svg>
);

const TicketIcon = () => (
  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 5v2m0 4v2m0 4v2M5 5a2 2 0 00-2 2v3a2 2 0 110 4v3a2 2 0 002 2h14a2 2 0 002-2v-3a2 2 0 110-4V7a2 2 0 00-2-2H5z" />
  </svg>
);

const ClockIcon = () => (
  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
  </svg>
);

export default function App() {
  const [currentView, setCurrentView] = useState<'home' | 'my-coupons'>('home');
  const [selectedCategory, setSelectedCategory] = useState('Todos');
  const [searchQuery, setSearchQuery] = useState('');

  // Advanced Filter State
  const [showFilters, setShowFilters] = useState(false);
  const [sortBy, setSortBy] = useState<'newest' | 'expiring' | 'discount'>('newest');
  const [selectedStoreFilter, setSelectedStoreFilter] = useState<string>('all');

  // Modal State
  const [selectedCoupon, setSelectedCoupon] = useState<{coupon: Coupon, store: Store} | null>(null);
  const [selectedRedemption, setSelectedRedemption] = useState<Redemption | null>(null);

  // Action State
  const [isRedeeming, setIsRedeeming] = useState(false);
  const [redemptionCode, setRedemptionCode] = useState<string | null>(null);
  const [myRedemptions, setMyRedemptions] = useState<Redemption[]>(MY_REDEMPTIONS);

  // Notification State
  const [showNotifications, setShowNotifications] = useState(false);

  // Notifications Logic
  const notifications = useMemo(() => {
    const today = new Date();
    const alerts: { id: string, message: string, daysLeft: number, type: 'urgent' | 'warning' | 'info' }[] = [];

    COUPONS.forEach(coupon => {
      const expiry = new Date(coupon.expiryDate);
      const diffTime = expiry.getTime() - today.getTime();
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (diffDays === 1) {
        alerts.push({ id: coupon.id, message: `O cupom "${coupon.title}" expira amanhã!`, daysLeft: 1, type: 'urgent' });
      } else if (diffDays === 3) {
        alerts.push({ id: coupon.id, message: `"${coupon.title}" expira em 3 dias.`, daysLeft: 3, type: 'warning' });
      } else if (diffDays === 7) {
        alerts.push({ id: coupon.id, message: `"${coupon.title}" expira na próxima semana.`, daysLeft: 7, type: 'info' });
      }
    });

    return alerts.sort((a, b) => a.daysLeft - b.daysLeft);
  }, []);

  // Filter Logic
  const filteredCoupons = useMemo(() => {
    let result = COUPONS.filter(coupon => {
      const store = STORES.find(s => s.id === coupon.storeId);
      if (!store) return false;

      const matchesCategory = selectedCategory === 'Todos' || coupon.category === selectedCategory;
      const matchesSearch = 
        coupon.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        store.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesStore = selectedStoreFilter === 'all' || coupon.storeId === selectedStoreFilter;

      return matchesCategory && matchesSearch && matchesStore;
    });

    // Sort Logic
    result = result.sort((a, b) => {
      if (sortBy === 'expiring') {
        return new Date(a.expiryDate).getTime() - new Date(b.expiryDate).getTime();
      } else if (sortBy === 'discount') {
        return b.discountValue - a.discountValue; // Simply sort by value
      }
      return 0; // Default order (as defined in array)
    });

    return result;
  }, [selectedCategory, searchQuery, sortBy, selectedStoreFilter]);

  // Handlers
  const handleOpenCoupon = (coupon: Coupon) => {
    const store = STORES.find(s => s.id === coupon.storeId);
    if (store) {
      setSelectedCoupon({ coupon, store });
      setIsRedeeming(false);
      setRedemptionCode(null);
    }
  };

  const handleOpenRedemption = (redemption: Redemption) => {
    setSelectedRedemption(redemption);
  };

  const handleRedeem = () => {
    if (!selectedCoupon) return;
    setIsRedeeming(true);

    // Simulate API Call
    setTimeout(() => {
      const code = `CPN-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;
      setRedemptionCode(code);

      // Add to local redemptions history
      const newRedemption: Redemption = {
        id: Math.random().toString(36),
        couponId: selectedCoupon.coupon.id,
        userId: CURRENT_USER.id,
        code: code,
        status: 'PENDING',
        redeemedAt: new Date().toISOString()
      };

      setMyRedemptions(prev => [newRedemption, ...prev]);
      setIsRedeeming(false);
    }, 1500);
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-20 font-sans">
      {/* Header / Navbar */}
      <nav className="bg-white sticky top-0 z-30 border-b border-gray-100/50 backdrop-blur-md bg-white/80">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div 
              className="flex items-center gap-2 cursor-pointer transition-transform hover:scale-105 active:scale-95" 
              onClick={() => setCurrentView('home')}
            >
              <div className="bg-primary-600 rounded-lg p-1.5 shadow-lg shadow-primary-200">
                <TicketIcon />
              </div>
              <span className="font-bold text-xl tracking-tight text-gray-900 hidden sm:block">ShopPerks</span>
            </div>

            <div className="flex items-center gap-6">
               <div className="hidden sm:flex items-center bg-gray-100 p-1 rounded-xl">
                 <button 
                   onClick={() => setCurrentView('home')}
                   className={`px-4 py-1.5 rounded-lg text-sm font-semibold transition-all duration-300 ${currentView === 'home' ? 'bg-white text-primary-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                 >
                   Início
                 </button>
                 <button 
                   onClick={() => setCurrentView('my-coupons')}
                   className={`px-4 py-1.5 rounded-lg text-sm font-semibold transition-all duration-300 ${currentView === 'my-coupons' ? 'bg-white text-primary-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                 >
                   Meus Cupons
                 </button>
               </div>

               <div className="flex items-center gap-4 border-l border-gray-200 pl-4 md:pl-6 relative">
                 {/* Notifications Bell */}
                 <button 
                    className="relative text-gray-400 hover:text-primary-600 transition-colors"
                    onClick={() => setShowNotifications(!showNotifications)}
                 >
                   <BellIcon />
                   {notifications.length > 0 && (
                     <span className="absolute -top-1 -right-1 flex h-4 w-4 items-center justify-center rounded-full bg-red-500 text-[10px] font-bold text-white ring-2 ring-white animate-pulse">
                       {notifications.length}
                     </span>
                   )}
                 </button>

                 {/* Notifications Dropdown */}
                 {showNotifications && (
                   <div className="absolute right-0 top-12 w-80 bg-white rounded-2xl shadow-xl border border-gray-100 p-2 z-50 animate-pop-in origin-top-right">
                     <h3 className="text-sm font-bold text-gray-900 px-4 py-2 border-b border-gray-50">Notificações</h3>
                     <div className="max-h-64 overflow-y-auto">
                       {notifications.length === 0 ? (
                         <p className="text-sm text-gray-400 p-4 text-center">Nenhuma notificação nova.</p>
                       ) : (
                         notifications.map(notif => (
                           <div key={notif.id} className="p-3 hover:bg-gray-50 rounded-xl transition-colors cursor-pointer border-b border-gray-50 last:border-0">
                             <div className="flex items-start gap-3">
                               <div className={`w-2 h-2 mt-1.5 rounded-full flex-shrink-0 ${notif.type === 'urgent' ? 'bg-red-500' : notif.type === 'warning' ? 'bg-orange-400' : 'bg-blue-400'}`} />
                               <p className="text-sm text-gray-600 leading-snug">{notif.message}</p>
                             </div>
                           </div>
                         ))
                       )}
                     </div>
                   </div>
                 )}

                 <div className="hidden md:flex flex-col items-end">
                   <span className="text-sm font-semibold text-gray-700">{CURRENT_USER.name}</span>
                 </div>
                 <img 
                   src={CURRENT_USER.avatarUrl} 
                   alt="User" 
                   className="w-9 h-9 rounded-full border-2 border-primary-100 hover:border-primary-300 transition-colors"
                 />
               </div>
            </div>
          </div>
        </div>
      </nav>

      {/* Mobile Bottom Nav for quick View Switch */}
      <div className="sm:hidden fixed bottom-0 inset-x-0 bg-white border-t border-gray-200 flex justify-around p-3 z-40">
        <button onClick={() => setCurrentView('home')} className={`flex flex-col items-center ${currentView === 'home' ? 'text-primary-600' : 'text-gray-400'}`}>
          <TicketIcon />
          <span className="text-xs font-medium mt-1">Explorar</span>
        </button>
        <button onClick={() => setCurrentView('my-coupons')} className={`flex flex-col items-center ${currentView === 'my-coupons' ? 'text-primary-600' : 'text-gray-400'}`}>
           {/* Custom Icon for wallet */}
           <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z" /></svg>
          <span className="text-xs font-medium mt-1">Carteira</span>
        </button>
      </div>

      <main className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 pt-8">

        {currentView === 'home' ? (
          <>
            {/* Hero / Welcome */}
            <div className="mb-10 animate-fade-in-up" style={{ animationDelay: '0ms' }}>
              <h1 className="text-3xl font-bold text-gray-900 mb-2">
                Olá, {CURRENT_USER.name.split(' ')[0]}! 👋
              </h1>
              <p className="text-gray-500">
                Confira as vantagens exclusivas que seus colegas prepararam para você hoje.
              </p>
            </div>

            {/* Search & Filter */}
            <div className="mb-8 sticky top-20 z-20 md:static animate-fade-in-up" style={{ animationDelay: '100ms' }}>
              <div className="flex flex-col md:flex-row gap-3">
                <div className="relative flex-1 group">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 group-focus-within:text-primary-500 transition-colors">
                    <SearchIcon />
                  </div>
                  <input
                    type="text"
                    placeholder="Busque por loja ou desconto..."
                    className="block w-full pl-10 pr-3 py-3 border border-gray-200 rounded-xl leading-5 bg-white placeholder-gray-400 focus:outline-none focus:border-primary-500 focus:ring-2 focus:ring-primary-200 sm:text-sm shadow-sm transition-all"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                </div>

                <button 
                  onClick={() => setShowFilters(!showFilters)}
                  className={`flex items-center gap-2 px-5 py-3 rounded-xl border transition-all ${showFilters ? 'bg-primary-50 border-primary-200 text-primary-700' : 'bg-white border-gray-200 text-gray-600 hover:bg-gray-50'}`}
                >
                  <FilterIcon />
                  <span className="font-medium text-sm">Filtros</span>
                </button>
              </div>

              {/* Advanced Filter Panel */}
              {showFilters && (
                <div className="mt-4 bg-white p-4 rounded-2xl border border-gray-100 shadow-sm animate-pop-in">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
