                            </div>
                            <div className="font-mono text-2xl font-bold text-gray-800 tracking-widest">{selectedRedemption.code}</div>
                            <p className="text-xs text-gray-400 mt-2">Válido até {new Date(coupon.expiryDate).toLocaleDateString()}</p>
                          </div>
                       ) : (
                          <div className="text-left space-y-4 animate-fade-in-up">
                             <div className="flex justify-between border-b border-gray-200 pb-2">
                                <span className="text-gray-500 text-sm">Status</span>
                                <span className="font-semibold text-gray-800">{isUsed ? 'Resgatado' : 'Expirado'}</span>
                             </div>

                             <div className="flex justify-between border-b border-gray-200 pb-2">
                                <span className="text-gray-500 text-sm">Código</span>
                                <span className="font-mono font-medium text-gray-800">{selectedRedemption.code}</span>
                             </div>

                             {selectedRedemption.validatedAt && (
                               <div className="flex justify-between border-b border-gray-200 pb-2">
                                  <span className="text-gray-500 text-sm">Data de Uso</span>
                                  <span className="font-medium text-gray-800">
                                    {new Date(selectedRedemption.validatedAt).toLocaleString('pt-BR', { dateStyle: 'short', timeStyle: 'short' })}
                                  </span>
                               </div>
                             )}

                             {selectedRedemption.validatedBy && (
                               <div className="flex justify-between items-center pt-1">
                                  <span className="text-gray-500 text-sm">Validado por</span>
                                  <div className="text-right">
                                    <span className="block font-medium text-gray-800 text-sm">{selectedRedemption.validatedBy}</span>
                                    <span className="text-xs text-primary-600">Loja Verificada</span>
                                  </div>
                               </div>
                             )}
                          </div>
                       )}
                    </div>

                    <div className="mt-8">
                      <Button variant="secondary" fullWidth onClick={() => setSelectedRedemption(null)}>
                        Fechar
                      </Button>
                    </div>
                 </div>
              </div>
             );
          })()}
        </Modal>
      )}
    </div>
  );
}

import React, { useEffect, useState } from 'react';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  children: React.ReactNode;
}

export const Modal: React.FC<ModalProps> = ({ isOpen, onClose, children }) => {
  const [isClosing, setIsClosing] = useState(false);

  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => {
      document.body.style.overflow = 'unset';
    };
  }, [isOpen]);

  // Handle the closing animation sequence
  const handleClose = () => {
    setIsClosing(true);
    // Wait for animation (0.2s = 200ms) to finish before actually closing
    setTimeout(() => {
      onClose();
      setIsClosing(false); 
    }, 200);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      {/* Backdrop */}
      <div 
        className={`absolute inset-0 bg-gray-900/60 backdrop-blur-sm ${isClosing ? 'animate-fade-out' : 'animate-fade-in'}`} 
        onClick={handleClose}
      />

      {/* Content */}
      <div 
        className={`relative bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden max-h-[90vh] overflow-y-auto ${isClosing ? 'animate-scale-out' : 'animate-pop-in'}`}
      >
        <button 
          onClick={handleClose}
          className="absolute top-4 right-4 z-10 bg-white/50 backdrop-blur rounded-full p-2 hover:bg-white text-gray-700 transition-colors"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
        {children}
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Coupon, Store, User, Redemption } from '../types';
import { CouponCard } from './CouponCard';
import { Button } from './Button';
import { Modal } from './Modal';
import { CATEGORIES } from '../constants';

// Icons need to be redefined here or imported if we had a shared icon file. 
// For now, I'll inline them to keep it self-contained in the XML response logic.
const SearchIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>;
const FilterIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" /></svg>;
const TicketIcon = () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 5v2m0 4v2m0 4v2M5 5a2 2 0 00-2 2v3a2 2 0 110 4v3a2 2 0 002 2h14a2 2 0 002-2v-3a2 2 0 110-4V7a2 2 0 00-2-2H5z" /></svg>;
const ClockIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>;

interface EmployeeDashboardProps {
  user: User;
  stores: Store[];
  coupons: Coupon[];
  redemptions: Redemption[];
  onRedeem: (couponId: string) => Promise<string>;
}

export const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({ 
  user, stores, coupons, redemptions, onRedeem 
}) => {
  const [currentView, setCurrentView] = useState<'home' | 'my-coupons'>('home');
  const [selectedCategory, setSelectedCategory] = useState('Todos');
  const [searchQuery, setSearchQuery] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [sortBy, setSortBy] = useState<'newest' | 'expiring' | 'discount'>('newest');

  // Modal State
  const [selectedCoupon, setSelectedCoupon] = useState<{coupon: Coupon, store: Store} | null>(null);
  const [selectedRedemption, setSelectedRedemption] = useState<Redemption | null>(null);
  const [isRedeeming, setIsRedeeming] = useState(false);
  const [redemptionCode, setRedemptionCode] = useState<string | null>(null);

  // Filter Logic
  const filteredCoupons = useMemo(() => {
    let result = coupons.filter(coupon => {
      const store = stores.find(s => s.id === coupon.storeId);
      if (!store) return false;

      const matchesCategory = selectedCategory === 'Todos' || coupon.category === selectedCategory;
      const matchesSearch = 
        coupon.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        store.name.toLowerCase().includes(searchQuery.toLowerCase());

      return matchesCategory && matchesSearch;
    });

    result = result.sort((a, b) => {
      if (sortBy === 'expiring') return new Date(a.expiryDate).getTime() - new Date(b.expiryDate).getTime();
      if (sortBy === 'discount') return b.discountValue - a.discountValue;
      return 0;
    });

    return result;
  }, [coupons, stores, selectedCategory, searchQuery, sortBy]);

  const handleOpenCoupon = (coupon: Coupon) => {
    const store = stores.find(s => s.id === coupon.storeId);
    if (store) {
      setSelectedCoupon({ coupon, store });
      setIsRedeeming(false);
      setRedemptionCode(null);
    }
  };

  const executeRedeem = async () => {
    if (!selectedCoupon) return;
    setIsRedeeming(true);
    try {
      const code = await onRedeem(selectedCoupon.coupon.id);
      setRedemptionCode(code);
    } catch (e) {
      alert("Erro ao resgatar");
    } finally {
      setIsRedeeming(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 pt-8">
      {/* Tab Switcher */}
      <div className="flex justify-center mb-8">
        <div className="bg-white p-1 rounded-xl shadow-sm border border-gray-200 flex">
           <button 
             onClick={() => setCurrentView('home')}
             className={`px-6 py-2 rounded-lg text-sm font-semibold transition-all ${currentView === 'home' ? 'bg-primary-50 text-primary-700' : 'text-gray-500 hover:text-gray-700'}`}
           >
             Cupons
           </button>
           <button 
             onClick={() => setCurrentView('my-coupons')}
             className={`px-6 py-2 rounded-lg text-sm font-semibold transition-all ${currentView === 'my-coupons' ? 'bg-primary-50 text-primary-700' : 'text-gray-500 hover:text-gray-700'}`}
           >
             Carteira
           </button>
        </div>
      </div>

      {currentView === 'home' ? (
        <>
          {/* Welcome */}
          <div className="mb-8 animate-fade-in-up">
            <h1 className="text-3xl font-bold text-gray-900 mb-2">Olá, {user.name.split(' ')[0]}!</h1>
            <p className="text-gray-500">Explore os descontos disponíveis no shopping hoje.</p>
          </div>

          {/* Filters */}
          <div className="mb-8 sticky top-20 z-20 md:static animate-fade-in-up" style={{ animationDelay: '100ms' }}>
              <div className="flex flex-col md:flex-row gap-3">
                <div className="relative flex-1 group">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <SearchIcon />
                  </div>
                  <input
                    type="text"
                    placeholder="Busque por loja..."
                    className="block w-full pl-10 pr-3 py-3 border border-gray-200 rounded-xl leading-5 bg-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-primary-200 focus:border-primary-500 transition-all"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                </div>
                <button 
                  onClick={() => setShowFilters(!showFilters)}
                  className={`flex items-center gap-2 px-5 py-3 rounded-xl border transition-all ${showFilters ? 'bg-primary-50 border-primary-200 text-primary-700' : 'bg-white border-gray-200 text-gray-600 hover:bg-gray-50'}`}
                >
                  <FilterIcon />
                  <span className="font-medium text-sm">Filtros</span>
                </button>
              </div>

              {showFilters && (
                <div className="mt-4 bg-white p-4 rounded-2xl border border-gray-100 shadow-sm animate-pop-in">
                   <div className="flex gap-2">
                       <button onClick={() => setSortBy('newest')} className={`px-3 py-1.5 text-sm rounded-lg border ${sortBy === 'newest' ? 'bg-primary-600 text-white border-primary-600' : 'bg-white text-gray-600 border-gray-200'}`}>Recentes</button>
                       <button onClick={() => setSortBy('discount')} className={`px-3 py-1.5 text-sm rounded-lg border ${sortBy === 'discount' ? 'bg-primary-600 text-white border-primary-600' : 'bg-white text-gray-600 border-gray-200'}`}>Maior Desconto</button>
                   </div>
                </div>
              )}
