              const store = stores.find(s => s.id === coupon.storeId);
              if (!store) return null;
              return (
                <div key={coupon.id} style={{ animationDelay: `${200 + (idx * 50)}ms` }} className="animate-fade-in-up">
                  <CouponCard coupon={coupon} store={store} onClick={() => handleOpenCoupon(coupon)} />
                </div>
              );
            })}
          </div>
        </>
      ) : (
        /* My Redemptions */
        <div className="max-w-2xl mx-auto animate-fade-in-up">
           <h2 className="text-2xl font-bold text-gray-900 mb-6 flex items-center gap-2"><TicketIcon /> Meus Resgates</h2>
           <div className="space-y-4">
             {redemptions.map(r => {
                const coupon = coupons.find(c => c.id === r.couponId);
                const store = stores.find(s => s.id === coupon?.storeId);
                if(!coupon || !store) return null;
                return (
                  <div key={r.id} onClick={() => setSelectedRedemption(r)} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm flex items-center gap-4 cursor-pointer hover:shadow-md transition-all">
                    <img src={store.logoUrl} className="w-12 h-12 object-contain rounded-lg border border-gray-100" alt={store.name} />
                    <div className="flex-1">
                      <h4 className="font-bold text-gray-900">{coupon.title}</h4>
                      <p className="text-xs text-gray-500">{store.name}</p>
                    </div>
                    <span className={`px-3 py-1 rounded-full text-xs font-bold ${r.status === 'PENDING' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500'}`}>
                      {r.status === 'PENDING' ? 'Ativo' : 'Usado'}
                    </span>
                  </div>
                );
             })}
           </div>
        </div>
      )}

      {/* Coupon Modal */}
      {selectedCoupon && (
        <Modal isOpen={!!selectedCoupon} onClose={() => setSelectedCoupon(null)}>
           <div className="h-48 relative">
              <img src={selectedCoupon.store.coverUrl} className="w-full h-full object-cover" alt="Cover" />
              <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
              <div className="absolute bottom-4 left-6 flex items-center gap-3 text-white">
                 <img src={selectedCoupon.store.logoUrl} className="w-12 h-12 rounded-lg bg-white p-1 object-contain" alt="logo"/>
                 <div><p className="font-bold text-lg">{selectedCoupon.store.name}</p></div>
              </div>
           </div>
           <div className="p-6">
              {!redemptionCode ? (
                <>
                  <h2 className="text-2xl font-bold text-gray-900 mb-2">{selectedCoupon.coupon.title}</h2>
                  <p className="text-gray-600 mb-6">{selectedCoupon.coupon.description}</p>
                  <Button fullWidth onClick={executeRedeem} disabled={isRedeeming}>{isRedeeming ? 'Gerando...' : 'Resgatar'}</Button>
                </>
              ) : (
                <div className="text-center py-6">
                   <div className="bg-gray-900 text-white text-2xl font-mono p-4 rounded-xl mb-4">{redemptionCode}</div>
                   <p className="text-sm text-gray-500">Apresente este código na loja.</p>
                </div>
              )}
           </div>
        </Modal>
      )}

      {/* Redemption Detail Modal */}
      {selectedRedemption && (
         <Modal isOpen={!!selectedRedemption} onClose={() => setSelectedRedemption(null)}>
            <div className="p-8 text-center">
               <h2 className="text-2xl font-mono font-bold text-gray-900 mb-2">{selectedRedemption.code}</h2>
               <div className="flex justify-center my-6">
                 <img src={`https://api.qrserver.com/v1/create-qr-code/?size=180x180&data=${selectedRedemption.code}`} alt="QR" className="mix-blend-multiply" />
               </div>
               <p className="text-sm text-gray-500">{selectedRedemption.status === 'PENDING' ? 'Apresente ao caixa' : 'Este cupom já foi utilizado'}</p>
            </div>
         </Modal>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { User, Store, Coupon, Redemption } from '../types';
