         <div className="flex gap-4 text-center">
            <div className="px-6 py-2 bg-gray-50 rounded-xl">
               <p className="text-2xl font-bold text-primary-600">{activeCoupons}</p>
               <p className="text-xs text-gray-500 uppercase font-bold">Cupons Ativos</p>
            </div>
            <div className="px-6 py-2 bg-gray-50 rounded-xl">
               <p className="text-2xl font-bold text-accent-500">{totalRedemptions}</p>
               <p className="text-xs text-gray-500 uppercase font-bold">Resgates</p>
            </div>
         </div>
      </div>

