      <div className="flex gap-4 border-b border-gray-200 mb-8">
         <button onClick={() => setView('coupons')} className={`pb-3 px-2 text-sm font-semibold transition-colors ${view === 'coupons' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-gray-400'}`}>Gerenciar Cupons</button>
