interface EmployeeDashboardProps {
  user: User;
  stores: Store[];
  coupons: Coupon[];
  redemptions: Redemption[];
  onRedeem: (couponId: string) => Promise<string>;
}

export const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({ 
  user, stores, coupons, redemptions, onRedeem 
}) => {
  const [currentView, setCurrentView] = useState<'home' | 'my-coupons'>('home');
  const [selectedCategory, setSelectedCategory] = useState('Todos');
  const [searchQuery, setSearchQuery] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [sortBy, setSortBy] = useState<'newest' | 'expiring' | 'discount'>('newest');

  // Modal State
  const [selectedCoupon, setSelectedCoupon] = useState<{coupon: Coupon, store: Store} | null>(null);
  const [selectedRedemption, setSelectedRedemption] = useState<Redemption | null>(null);
  const [isRedeeming, setIsRedeeming] = useState(false);
  const [redemptionCode, setRedemptionCode] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  // Notifications Logic (Expiring Redemptions)
  const expiringRedemptionsCount = useMemo(() => {
    const today = new Date();
    return redemptions.filter(r => {
      if (r.status !== 'PENDING') return false;
      const coupon = coupons.find(c => c.id === r.couponId);
      if (!coupon) return false;

      const expiry = new Date(coupon.expiryDate);
      const diffTime = expiry.getTime() - today.getTime();
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      return diffDays <= 7 && diffDays >= 0;
    }).length;
  }, [redemptions, coupons]);

  // Filter Logic
  const filteredCoupons = useMemo(() => {
    let result = coupons.filter(coupon => {
      const store = stores.find(s => s.id === coupon.storeId);
      if (!store) return false;

      const matchesCategory = selectedCategory === 'Todos' || coupon.category === selectedCategory;
      const matchesSearch = 
        coupon.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        store.name.toLowerCase().includes(searchQuery.toLowerCase());

      return matchesCategory && matchesSearch;
    });

    result = result.sort((a, b) => {
      if (sortBy === 'expiring') return new Date(a.expiryDate).getTime() - new Date(b.expiryDate).getTime();
      if (sortBy === 'discount') return b.discountValue - a.discountValue;
      // newest logic (mocked by array order or created_at if existed, using default)
      return 0; 
    });

    return result;
  }, [coupons, stores, selectedCategory, searchQuery, sortBy]);

  const handleOpenCoupon = (coupon: Coupon) => {
    const store = stores.find(s => s.id === coupon.storeId);
    if (store) {
      setSelectedCoupon({ coupon, store });
      setIsRedeeming(false);
      setRedemptionCode(null);
    }
  };

  const executeRedeem = async () => {
    if (!selectedCoupon) return;
    setIsRedeeming(true);
    try {
      const code = await onRedeem(selectedCoupon.coupon.id);
      setRedemptionCode(code);
    } catch (e) {
      alert("Erro ao resgatar");
    } finally {
      setIsRedeeming(false);
    }
  };

  const handleCopyCode = (code: string) => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 pt-8 pb-20">
      {/* Tab Switcher */}
      <div className="flex justify-center mb-8">
        <div className="bg-white p-1 rounded-xl shadow-sm border border-gray-200 flex relative">
           <button 
             onClick={() => setCurrentView('home')}
             className={`px-6 py-2 rounded-lg text-sm font-semibold transition-all ${currentView === 'home' ? 'bg-primary-50 text-primary-700' : 'text-gray-500 hover:text-gray-700'}`}
           >
             Cupons
           </button>
           <button 
             onClick={() => setCurrentView('my-coupons')}
             className={`px-6 py-2 rounded-lg text-sm font-semibold transition-all relative ${currentView === 'my-coupons' ? 'bg-primary-50 text-primary-700' : 'text-gray-500 hover:text-gray-700'}`}
           >
             Carteira
             {expiringRedemptionsCount > 0 && (
               <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-bold w-4 h-4 rounded-full flex items-center justify-center shadow-sm">
                 {expiringRedemptionsCount}
               </span>
             )}
           </button>
        </div>
      </div>

      {currentView === 'home' ? (
        <>
          {/* Welcome */}
          <div className="mb-8 animate-fade-in-up">
            <h1 className="text-3xl font-bold text-gray-900 mb-2">Olá, {user.name.split(' ')[0]}!</h1>
            <p className="text-gray-500">Explore os descontos disponíveis no shopping hoje.</p>
          </div>

          {/* Filters */}
          <div className="mb-8 sticky top-20 z-20 md:static animate-fade-in-up" style={{ animationDelay: '100ms' }}>
              <div className="flex flex-col md:flex-row gap-3">
                <div className="relative flex-1 group">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <SearchIcon />
                  </div>
                  <input
                    type="text"
                    placeholder="Busque por loja..."
                    className="block w-full pl-10 pr-3 py-3 border border-gray-200 rounded-xl leading-5 bg-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-primary-200 focus:border-primary-500 transition-all"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                </div>
                <button 
                  onClick={() => setShowFilters(!showFilters)}
                  className={`flex items-center gap-2 px-5 py-3 rounded-xl border transition-all ${showFilters ? 'bg-primary-50 border-primary-200 text-primary-700' : 'bg-white border-gray-200 text-gray-600 hover:bg-gray-50'}`}
                >
                  <FilterIcon />
                  <span className="font-medium text-sm">Filtros</span>
                </button>
              </div>

              {showFilters && (
                <div className="mt-4 bg-white p-5 rounded-2xl border border-gray-100 shadow-sm animate-pop-in space-y-4">
                   <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      <div>
                        <label className="block text-xs font-bold text-gray-400 uppercase mb-2">Ordenar Por</label>
                        <div className="flex flex-wrap gap-2">
                           {[
                             { id: 'newest', label: 'Mais Recentes' },
                             { id: 'expiring', label: 'Vai Expirar' },
                             { id: 'discount', label: 'Maior Desconto' }
                           ].map((opt) => (
                             <button 
                               key={opt.id}
                               onClick={() => setSortBy(opt.id as any)} 
                               className={`px-3 py-2 text-xs font-semibold rounded-lg border transition-colors ${sortBy === opt.id ? 'bg-primary-600 text-white border-primary-600' : 'bg-white text-gray-600 border-gray-200 hover:border-gray-300'}`}
                             >
                               {opt.label}
                             </button>
                           ))}
                        </div>
                      </div>
                      <div>
                        <label className="block text-xs font-bold text-gray-400 uppercase mb-2">Categoria</label>
                        <div className="relative">
                          <select 
                            value={selectedCategory}
                            onChange={(e) => setSelectedCategory(e.target.value)}
                            className="block w-full pl-3 pr-10 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-200 bg-white"
                          >
                            {CATEGORIES.map(cat => (
                              <option key={cat} value={cat}>{cat}</option>
                            ))}
                          </select>
                        </div>
                      </div>
                   </div>
                </div>
              )}
          </div>

          {/* Grid */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 animate-fade-in-up" style={{ animationDelay: '200ms' }}>
            {filteredCoupons.map((coupon, idx) => {
              const store = stores.find(s => s.id === coupon.storeId);
              if (!store) return null;
              return (
                <div key={coupon.id} style={{ animationDelay: `${200 + (idx * 50)}ms` }} className="animate-fade-in-up">
                  <CouponCard coupon={coupon} store={store} onClick={() => handleOpenCoupon(coupon)} />
                </div>
              );
            })}
          </div>
        </>
      ) : (
        /* My Redemptions */
        <div className="max-w-2xl mx-auto animate-fade-in-up">
           <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-bold text-gray-900 flex items-center gap-2"><TicketIcon /> Meus Resgates</h2>
           </div>

           {expiringRedemptionsCount > 0 && (
             <div className="mb-6 bg-orange-50 border border-orange-100 p-4 rounded-xl flex items-start gap-3">
                <svg className="w-5 h-5 text-orange-500 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                <div>
                   <h4 className="text-sm font-bold text-orange-800">Atenção!</h4>
                   <p className="text-xs text-orange-700 mt-1">Você tem {expiringRedemptionsCount} cupons expirando em breve (menos de 7 dias). Utilize-os antes que percam a validade.</p>
                </div>
             </div>
           )}

           <div className="space-y-4">
             {redemptions.length === 0 ? (
               <div className="text-center py-10 text-gray-400">
                 <p>Nenhum cupom resgatado ainda.</p>
               </div>
             ) : (
               redemptions.map(r => {
                  const coupon = coupons.find(c => c.id === r.couponId);
                  const store = stores.find(s => s.id === coupon?.storeId);
                  if(!coupon || !store) return null;

                  // Calculate days left
                  const expiry = new Date(coupon.expiryDate);
                  const daysLeft = Math.ceil((expiry.getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24));
                  const isExpiring = r.status === 'PENDING' && daysLeft <= 7 && daysLeft >= 0;

                  return (
                    <div key={r.id} onClick={() => setSelectedRedemption(r)} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm flex items-center gap-4 cursor-pointer hover:shadow-md hover:border-primary-100 transition-all group relative overflow-hidden">
                      {isExpiring && <div className="absolute top-0 left-0 w-1 h-full bg-orange-400"></div>}
                      <img src={store.logoUrl} className="w-12 h-12 object-contain rounded-lg border border-gray-100 bg-gray-50 p-1" alt={store.name} />
                      <div className="flex-1">
                        <h4 className="font-bold text-gray-900 group-hover:text-primary-600 transition-colors">{coupon.title}</h4>
                        <div className="flex items-center gap-2 mt-1">
                          <span className="text-xs text-gray-500 font-medium">{store.name}</span>
                          {isExpiring && <span className="text-[10px] bg-orange-100 text-orange-700 px-2 py-0.5 rounded-full font-bold">Expira em {daysLeft} dias</span>}
                        </div>
                      </div>
                      <span className={`px-3 py-1 rounded-full text-xs font-bold border ${
                        r.status === 'PENDING' ? 'bg-green-50 text-green-700 border-green-100' : 
                        r.status === 'USED' ? 'bg-gray-100 text-gray-500 border-gray-200' :
                        'bg-red-50 text-red-600 border-red-100'
                      }`}>
                        {r.status === 'PENDING' ? 'Ativo' : r.status === 'USED' ? 'Usado' : 'Expirado'}
                      </span>
                    </div>
                  );
               })
             )}
           </div>
        </div>
      )}

      {/* Coupon Details Modal (Pre-Redemption) */}
      {selectedCoupon && (
        <Modal isOpen={!!selectedCoupon} onClose={() => setSelectedCoupon(null)}>
           <div className="h-48 relative">
              <img src={selectedCoupon.store.coverUrl} className="w-full h-full object-cover" alt="Cover" />
              <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
              <div className="absolute bottom-4 left-6 flex items-center gap-3 text-white">
                 <div className="bg-white p-1 rounded-lg shadow-lg">
                   <img src={selectedCoupon.store.logoUrl} className="w-10 h-10 object-contain" alt="logo"/>
                 </div>
                 <div>
                   <p className="font-bold text-lg leading-none">{selectedCoupon.store.name}</p>
                   <p className="text-xs opacity-80 mt-1">{selectedCoupon.store.category}</p>
                 </div>
              </div>
           </div>
           <div className="p-6">
              {!redemptionCode ? (
                <>
                  <h2 className="text-2xl font-bold text-gray-900 mb-2">{selectedCoupon.coupon.title}</h2>
                  <p className="text-gray-600 mb-6 leading-relaxed">{selectedCoupon.coupon.description}</p>

                  <div className="bg-gray-50 rounded-xl p-4 mb-6">
                    <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Regras</h4>
                    <ul className="text-sm text-gray-600 space-y-1">
                      {selectedCoupon.coupon.rules.map((rule, i) => (
                        <li key={i} className="flex items-start gap-2">
                           <span className="text-primary-500 mt-1">•</span>
                           <span>{rule}</span>
                        </li>
                      ))}
                    </ul>
                  </div>

                  <Button fullWidth onClick={executeRedeem} disabled={isRedeeming}>
                    {isRedeeming ? 'Gerando...' : 'Resgatar Cupom'}
                  </Button>
                </>
              ) : (
                <div className="text-center py-6 animate-pop-in">
                   <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                      <CheckIcon />
                   </div>
                   <h3 className="text-xl font-bold text-gray-900 mb-2">Resgate Realizado!</h3>
                   <div className="bg-gray-900 text-white text-2xl font-mono p-4 rounded-xl mb-4 tracking-widest border-2 border-dashed border-gray-600">
                     {redemptionCode}
                   </div>
                   <p className="text-sm text-gray-500 mb-6">O código foi salvo na sua carteira.</p>
                   <Button variant="secondary" onClick={() => setSelectedCoupon(null)}>Fechar</Button>
                </div>
              )}
           </div>
        </Modal>
      )}

      {/* Redemption Status Modal (Post-Redemption / Wallet) */}
      {selectedRedemption && (
         <Modal isOpen={!!selectedRedemption} onClose={() => setSelectedRedemption(null)}>
            {(() => {
               const coupon = coupons.find(c => c.id === selectedRedemption.couponId);
               const store = stores.find(s => s.id === coupon?.storeId);
               if (!coupon || !store) return null;

               const isUsed = selectedRedemption.status === 'USED';
               const isExpired = selectedRedemption.status === 'EXPIRED';
               const statusColor = isUsed ? 'text-gray-500 bg-gray-100' : isExpired ? 'text-red-600 bg-red-50' : 'text-green-700 bg-green-50';

               return (
                 <div className="p-0">
                    <div className="bg-gradient-to-br from-primary-600 to-primary-800 p-6 text-white text-center relative overflow-hidden">
                       <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>
                       <h2 className="text-xl font-bold relative z-10">{store.name}</h2>
                       <p className="text-primary-100 text-sm relative z-10">{coupon.title}</p>
                    </div>

                    <div className="p-6">
                       {/* QR Code Section */}
                       <div className="flex justify-center mb-6">
                         <div className="p-3 bg-white border border-gray-200 rounded-xl shadow-sm">
                            {isUsed || isExpired ? (
                               <div className="w-40 h-40 flex items-center justify-center bg-gray-50 rounded-lg">
                                  <span className="text-gray-400 font-bold opacity-50 text-xl rotate-45 border-4 border-gray-300 p-2 rounded-lg">
                                    {isUsed ? 'UTILIZADO' : 'EXPIRADO'}
                                  </span>
                               </div>
                            ) : (
                               <img 
                                 src={`https://api.qrserver.com/v1/create-qr-code/?size=160x160&data=${selectedRedemption.code}`} 
                                 alt="QR Code" 
                                 className="w-40 h-40 mix-blend-multiply" 
                               />
                            )}
                         </div>
                       </div>

                       {/* Code & Copy */}
                       <div className="flex items-center gap-2 mb-6">
                          <div className="flex-1 bg-gray-50 border border-gray-200 rounded-lg py-3 px-4 text-center">
                             <span className="font-mono text-xl font-bold text-gray-800 tracking-widest">{selectedRedemption.code}</span>
                          </div>
                          <button 
                            onClick={() => handleCopyCode(selectedRedemption.code)}
                            className="bg-primary-50 text-primary-600 p-3.5 rounded-lg hover:bg-primary-100 transition-colors border border-primary-100"
                            title="Copiar código"
                          >
                            {copied ? <CheckIcon /> : <CopyIcon />}
                          </button>
                       </div>

                       {/* Details List */}
                       <div className="space-y-3 text-sm border-t border-gray-100 pt-4">
                          <div className="flex justify-between">
                             <span className="text-gray-500">Status</span>
                             <span className={`px-2 py-0.5 rounded text-xs font-bold uppercase ${statusColor}`}>
                               {selectedRedemption.status === 'PENDING' ? 'Disponível' : selectedRedemption.status === 'USED' ? 'Utilizado' : 'Expirado'}
                             </span>
                          </div>

                          {isUsed ? (
                             <>
                               <div className="flex justify-between">
                                  <span className="text-gray-500">Validado por</span>
                                  <span className="font-medium text-gray-900">{selectedRedemption.validatedBy || 'Loja'}</span>
                               </div>
                               <div className="flex justify-between">
                                  <span className="text-gray-500">Data de Uso</span>
                                  <span className="font-medium text-gray-900">
                                    {selectedRedemption.validatedAt ? new Date(selectedRedemption.validatedAt).toLocaleString('pt-BR') : '-'}
                                  </span>
                               </div>
                             </>
                          ) : (
                             <>
                               <div className="flex justify-between">
                                  <span className="text-gray-500">Resgatado em</span>
                                  <span className="font-medium text-gray-900">{new Date(selectedRedemption.redeemedAt).toLocaleDateString('pt-BR')}</span>
                               </div>
                               <div className="flex justify-between">
                                  <span className="text-gray-500">Válido até</span>
                                  <span className="font-medium text-red-600">{new Date(coupon.expiryDate).toLocaleDateString('pt-BR')}</span>
                               </div>
                             </>
                          )}
                       </div>

                       <div className="mt-8">
                         <Button fullWidth variant="secondary" onClick={() => setSelectedRedemption(null)}>Fechar</Button>
                       </div>
                    </div>
                 </div>
               );
            })()}
         </Modal>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Coupon, Store, User, Redemption } from '../types';
import { CouponCard } from './CouponCard';
import { Button } from './Button';
import { Modal } from './Modal';
import { CATEGORIES } from '../constants';

const SearchIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>;
const FilterIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" /></svg>;
const TicketIcon = () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 5v2m0 4v2m0 4v2M5 5a2 2 0 00-2 2v3a2 2 0 110 4v3a2 2 0 002 2h14a2 2 0 002-2v-3a2 2 0 110-4V7a2 2 0 00-2-2H5z" /></svg>;
const CopyIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" /></svg>;
const CheckIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>;
const BellIcon = () => (
  <svg className="w-6 h-6 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
  </svg>
);

interface EmployeeDashboardProps {
  user: User;
  stores: Store[];
  coupons: Coupon[];
  redemptions: Redemption[];
  onRedeem: (couponId: string) => Promise<string>;
}

export const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({ 
  user, stores, coupons, redemptions, onRedeem 
}) => {
  const [currentView, setCurrentView] = useState<'home' | 'my-coupons'>('home');
  const [selectedCategory, setSelectedCategory] = useState('Todos');
  const [searchQuery, setSearchQuery] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [sortBy, setSortBy] = useState<'newest' | 'expiring' | 'discount'>('newest');

  // Notification State
  const [showNotifications, setShowNotifications] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);

  // Modal State
  const [selectedCoupon, setSelectedCoupon] = useState<{coupon: Coupon, store: Store} | null>(null);
  const [selectedRedemption, setSelectedRedemption] = useState<Redemption | null>(null);
  const [isRedeeming, setIsRedeeming] = useState(false);
  const [redemptionCode, setRedemptionCode] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  // Close notifications when clicking outside
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Notifications Logic (Expiring Redemptions)
  const notifications = useMemo(() => {
    const today = new Date();
    const alerts: Array<{id: string, title: string, message: string, daysLeft: number}> = [];

    redemptions.forEach(r => {
      if (r.status !== 'PENDING') return;
      const coupon = coupons.find(c => c.id === r.couponId);
      if (!coupon) return;

      const expiry = new Date(coupon.expiryDate);
      const diffTime = expiry.getTime() - today.getTime();
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      // Trigger notifications for 7 days or less (covers 7, 3, 1 requirements)
      if (diffDays <= 7 && diffDays >= 0) {
        alerts.push({
          id: r.id,
          title: 'Cupom Expirando',
          message: `"${coupon.title}" expira em ${diffDays === 0 ? 'menos de 24h' : diffDays + ' dias'}.`,
          daysLeft: diffDays
        });
      }
    });

    return alerts.sort((a, b) => a.daysLeft - b.daysLeft);
  }, [redemptions, coupons]);

  // Filter Logic
  const filteredCoupons = useMemo(() => {
    let result = coupons.filter(coupon => {
      const store = stores.find(s => s.id === coupon.storeId);
      if (!store) return false;

      const matchesCategory = selectedCategory === 'Todos' || coupon.category === selectedCategory;
      const matchesSearch = 
        coupon.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        store.name.toLowerCase().includes(searchQuery.toLowerCase());

      return matchesCategory && matchesSearch;
    });

    result = result.sort((a, b) => {
      if (sortBy === 'expiring') return new Date(a.expiryDate).getTime() - new Date(b.expiryDate).getTime();
      if (sortBy === 'discount') return b.discountValue - a.discountValue;
      return 0; 
    });

    return result;
  }, [coupons, stores, selectedCategory, searchQuery, sortBy]);

  const handleOpenCoupon = (coupon: Coupon) => {
    const store = stores.find(s => s.id === coupon.storeId);
    if (store) {
      setSelectedCoupon({ coupon, store });
      setIsRedeeming(false);
      setRedemptionCode(null);
    }
  };

  const executeRedeem = async () => {
    if (!selectedCoupon) return;
    setIsRedeeming(true);
    try {
      const code = await onRedeem(selectedCoupon.coupon.id);
      setRedemptionCode(code);
    } catch (e) {
      alert("Erro ao resgatar");
    } finally {
      setIsRedeeming(false);
    }
  };

  const handleCopyCode = (code: string) => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 pt-8 pb-20">
      {/* Header & Notifications */}
      <div className="flex justify-between items-start mb-8 animate-fade-in-up">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 mb-2">Olá, {user.name.split(' ')[0]}!</h1>
          <p className="text-gray-500">Explore os descontos disponíveis no shopping hoje.</p>
        </div>

        {/* Notification Bell */}
        <div className="relative" ref={notificationRef}>
          <button 
            onClick={() => setShowNotifications(!showNotifications)} 
            className={`p-3 rounded-xl border shadow-sm transition-all duration-200 relative ${showNotifications ? 'bg-primary-50 border-primary-200' : 'bg-white border-gray-100 hover:bg-gray-50'}`}
          >
            <BellIcon />
            {notifications.length > 0 && (
               <span className="absolute top-2.5 right-3 flex h-2.5 w-2.5">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2.5 w-2.5 bg-red-500 border-2 border-white"></span>
               </span>
            )}
          </button>

          {showNotifications && (
            <div className="absolute right-0 top-full mt-2 w-80 bg-white rounded-2xl shadow-xl border border-gray-100 p-0 z-50 animate-pop-in overflow-hidden">
               <div className="p-4 border-b border-gray-50 bg-gray-50/50">
                 <h3 className="font-bold text-gray-900 text-sm">Notificações</h3>
               </div>
               {notifications.length === 0 ? (
                 <div className="p-8 text-center">
                    <p className="text-sm text-gray-400">Tudo limpo por aqui! ✨</p>
                 </div>
               ) : (
                 <div className="max-h-80 overflow-y-auto">
                    {notifications.map((notif) => (
                      <div 
                        key={notif.id} 
                        className="flex gap-3 items-start p-4 hover:bg-gray-50 transition-colors border-b border-gray-50 last:border-0 cursor-pointer"
                        onClick={() => {
                           const r = redemptions.find(x => x.id === notif.id);
                           if (r) setSelectedRedemption(r);
                           setShowNotifications(false);
                        }}
                      >
                        <div className={`w-2 h-2 mt-1.5 rounded-full shrink-0 ${notif.daysLeft <= 1 ? 'bg-red-500' : 'bg-orange-400'}`} />
                        <div>
                           <p className="text-sm font-bold text-gray-800">{notif.title}</p>
                           <p className="text-xs text-gray-500 mt-0.5 leading-relaxed">{notif.message}</p>
                        </div>
                      </div>
                    ))}
                 </div>
               )}
            </div>
          )}
        </div>
      </div>

      {/* Tab Switcher */}
      <div className="flex justify-center mb-8">
        <div className="bg-white p-1 rounded-xl shadow-sm border border-gray-200 flex relative">
           <button 
             onClick={() => setCurrentView('home')}
             className={`px-6 py-2 rounded-lg text-sm font-semibold transition-all ${currentView === 'home' ? 'bg-primary-50 text-primary-700' : 'text-gray-500 hover:text-gray-700'}`}
           >
             Cupons
           </button>
           <button 
             onClick={() => setCurrentView('my-coupons')}
             className={`px-6 py-2 rounded-lg text-sm font-semibold transition-all relative ${currentView === 'my-coupons' ? 'bg-primary-50 text-primary-700' : 'text-gray-500 hover:text-gray-700'}`}
           >
             Carteira
           </button>
        </div>
      </div>

      {currentView === 'home' ? (
        <>
          {/* Filters */}
          <div className="mb-8 sticky top-20 z-20 md:static animate-fade-in-up" style={{ animationDelay: '100ms' }}>
              <div className="flex flex-col md:flex-row gap-3">
                <div className="relative flex-1 group">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <SearchIcon />
                  </div>
                  <input
                    type="text"
                    placeholder="Busque por loja..."
                    className="block w-full pl-10 pr-3 py-3 border border-gray-200 rounded-xl leading-5 bg-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-primary-200 focus:border-primary-500 transition-all"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                </div>
                <button 
                  onClick={() => setShowFilters(!showFilters)}
                  className={`flex items-center gap-2 px-5 py-3 rounded-xl border transition-all ${showFilters ? 'bg-primary-50 border-primary-200 text-primary-700' : 'bg-white border-gray-200 text-gray-600 hover:bg-gray-50'}`}
                >
                  <FilterIcon />
                  <span className="font-medium text-sm">Filtros</span>
                </button>
              </div>

              {showFilters && (
                <div className="mt-4 bg-white p-5 rounded-2xl border border-gray-100 shadow-sm animate-pop-in space-y-4">
                   <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      <div>
                        <label className="block text-xs font-bold text-gray-400 uppercase mb-2">Ordenar Por</label>
                        <div className="flex flex-wrap gap-2">
                           {[
                             { id: 'newest', label: 'Mais Recentes' },
                             { id: 'expiring', label: 'Vai Expirar' },
                             { id: 'discount', label: 'Maior Desconto' }
                           ].map((opt) => (
                             <button 
                               key={opt.id}
                               onClick={() => setSortBy(opt.id as any)} 
                               className={`px-3 py-2 text-xs font-semibold rounded-lg border transition-colors ${sortBy === opt.id ? 'bg-primary-600 text-white border-primary-600' : 'bg-white text-gray-600 border-gray-200 hover:border-gray-300'}`}
                             >
                               {opt.label}
                             </button>
                           ))}
                        </div>
                      </div>
                      <div>
                        <label className="block text-xs font-bold text-gray-400 uppercase mb-2">Categoria</label>
                        <div className="relative">
                          <select 
                            value={selectedCategory}
                            onChange={(e) => setSelectedCategory(e.target.value)}
                            className="block w-full pl-3 pr-10 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-200 bg-white"
                          >
                            {CATEGORIES.map(cat => (
                              <option key={cat} value={cat}>{cat}</option>
                            ))}
                          </select>
                        </div>
                      </div>
                   </div>
                </div>
              )}
          </div>

          {/* Grid */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 animate-fade-in-up" style={{ animationDelay: '200ms' }}>
            {filteredCoupons.map((coupon, idx) => {
              const store = stores.find(s => s.id === coupon.storeId);
              if (!store) return null;
              return (
                <div key={coupon.id} style={{ animationDelay: `${200 + (idx * 50)}ms` }} className="animate-fade-in-up">
                  <CouponCard coupon={coupon} store={store} onClick={() => handleOpenCoupon(coupon)} />
                </div>
              );
            })}
          </div>
        </>
      ) : (
        /* My Redemptions */
        <div className="max-w-2xl mx-auto animate-fade-in-up">
           <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-bold text-gray-900 flex items-center gap-2"><TicketIcon /> Meus Resgates</h2>
           </div>

           <div className="space-y-4">
             {redemptions.length === 0 ? (
               <div className="text-center py-10 text-gray-400">
                 <p>Nenhum cupom resgatado ainda.</p>
               </div>
             ) : (
               redemptions.map(r => {
                  const coupon = coupons.find(c => c.id === r.couponId);
                  const store = stores.find(s => s.id === coupon?.storeId);
                  if(!coupon || !store) return null;

                  // Calculate days left
                  const expiry = new Date(coupon.expiryDate);
                  const daysLeft = Math.ceil((expiry.getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24));
                  const isExpiring = r.status === 'PENDING' && daysLeft <= 7 && daysLeft >= 0;

                  return (
                    <div key={r.id} onClick={() => setSelectedRedemption(r)} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm flex items-center gap-4 cursor-pointer hover:shadow-md hover:border-primary-100 transition-all group relative overflow-hidden">
                      {isExpiring && <div className="absolute top-0 left-0 w-1 h-full bg-orange-400"></div>}
                      <img src={store.logoUrl} className="w-12 h-12 object-contain rounded-lg border border-gray-100 bg-gray-50 p-1" alt={store.name} />
                      <div className="flex-1">
                        <h4 className="font-bold text-gray-900 group-hover:text-primary-600 transition-colors">{coupon.title}</h4>
                        <div className="flex items-center gap-2 mt-1">
                          <span className="text-xs text-gray-500 font-medium">{store.name}</span>
                          {isExpiring && <span className="text-[10px] bg-orange-100 text-orange-700 px-2 py-0.5 rounded-full font-bold">Expira em {daysLeft} dias</span>}
                        </div>
                      </div>
                      <span className={`px-3 py-1 rounded-full text-xs font-bold border ${
                        r.status === 'PENDING' ? 'bg-green-50 text-green-700 border-green-100' : 
                        r.status === 'USED' ? 'bg-gray-100 text-gray-500 border-gray-200' :
                        'bg-red-50 text-red-600 border-red-100'
                      }`}>
                        {r.status === 'PENDING' ? 'Ativo' : r.status === 'USED' ? 'Usado' : 'Expirado'}
                      </span>
                    </div>
                  );
               })
             )}
           </div>
        </div>
      )}

      {/* Coupon Details Modal (Pre-Redemption) */}
      {selectedCoupon && (
        <Modal isOpen={!!selectedCoupon} onClose={() => setSelectedCoupon(null)}>
           <div className="h-48 relative">
              <img src={selectedCoupon.store.coverUrl} className="w-full h-full object-cover" alt="Cover" />
              <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
              <div className="absolute bottom-4 left-6 flex items-center gap-3 text-white">
                 <div className="bg-white p-1 rounded-lg shadow-lg">
                   <img src={selectedCoupon.store.logoUrl} className="w-10 h-10 object-contain" alt="logo"/>
                 </div>
                 <div>
                   <p className="font-bold text-lg leading-none">{selectedCoupon.store.name}</p>
                   <p className="text-xs opacity-80 mt-1">{selectedCoupon.store.category}</p>
                 </div>
              </div>
           </div>
           <div className="p-6">
              {!redemptionCode ? (
                <>
                  <h2 className="text-2xl font-bold text-gray-900 mb-2">{selectedCoupon.coupon.title}</h2>
                  <p className="text-gray-600 mb-6 leading-relaxed">{selectedCoupon.coupon.description}</p>

                  <div className="bg-gray-50 rounded-xl p-4 mb-6">
                    <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Regras</h4>
                    <ul className="text-sm text-gray-600 space-y-1">
                      {selectedCoupon.coupon.rules.map((rule, i) => (
                        <li key={i} className="flex items-start gap-2">
                           <span className="text-primary-500 mt-1">•</span>
                           <span>{rule}</span>
                        </li>
                      ))}
                    </ul>
                  </div>

                  <Button fullWidth onClick={executeRedeem} disabled={isRedeeming}>
                    {isRedeeming ? 'Gerando...' : 'Resgatar Cupom'}
                  </Button>
                </>
              ) : (
                <div className="text-center py-6 animate-pop-in">
                   <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                      <CheckIcon />
                   </div>
                   <h3 className="text-xl font-bold text-gray-900 mb-2">Resgate Realizado!</h3>
                   <div className="bg-gray-900 text-white text-2xl font-mono p-4 rounded-xl mb-4 tracking-widest border-2 border-dashed border-gray-600">
                     {redemptionCode}
                   </div>
                   <p className="text-sm text-gray-500 mb-6">O código foi salvo na sua carteira.</p>
                   <Button variant="secondary" onClick={() => setSelectedCoupon(null)}>Fechar</Button>
                </div>
              )}
           </div>
        </Modal>
      )}

      {/* Redemption Status Modal (Post-Redemption / Wallet) */}
      {selectedRedemption && (
         <Modal isOpen={!!selectedRedemption} onClose={() => setSelectedRedemption(null)}>
            {(() => {
               const coupon = coupons.find(c => c.id === selectedRedemption.couponId);
               const store = stores.find(s => s.id === coupon?.storeId);
               if (!coupon || !store) return null;

               const isUsed = selectedRedemption.status === 'USED';
               const isExpired = selectedRedemption.status === 'EXPIRED';
               const statusColor = isUsed ? 'text-gray-500 bg-gray-100' : isExpired ? 'text-red-600 bg-red-50' : 'text-green-700 bg-green-50';

               return (
                 <div className="p-0">
                    <div className="bg-gradient-to-br from-primary-600 to-primary-800 p-6 text-white text-center relative overflow-hidden">
                       <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>
                       <h2 className="text-xl font-bold relative z-10">{store.name}</h2>
                       <p className="text-primary-100 text-sm relative z-10">{coupon.title}</p>
                    </div>

                    <div className="p-6">
                       {/* QR Code Section */}
                       <div className="flex justify-center mb-6">
                         <div className="p-3 bg-white border border-gray-200 rounded-xl shadow-sm">
                            {isUsed || isExpired ? (
                               <div className="w-40 h-40 flex items-center justify-center bg-gray-50 rounded-lg">
                                  <span className="text-gray-400 font-bold opacity-50 text-xl rotate-45 border-4 border-gray-300 p-2 rounded-lg">
                                    {isUsed ? 'UTILIZADO' : 'EXPIRADO'}
                                  </span>
                               </div>
                            ) : (
                               <img 
                                 src={`https://api.qrserver.com/v1/create-qr-code/?size=160x160&data=${selectedRedemption.code}`} 
                                 alt="QR Code" 
                                 className="w-40 h-40 mix-blend-multiply" 
                               />
                            )}
                         </div>
                       </div>

                       {/* Code & Copy */}
                       <div className="flex items-center gap-2 mb-6">
                          <div className="flex-1 bg-gray-50 border border-gray-200 rounded-lg py-3 px-4 text-center">
                             <span className="font-mono text-xl font-bold text-gray-800 tracking-widest">{selectedRedemption.code}</span>
                          </div>
                          <button 
                            onClick={() => handleCopyCode(selectedRedemption.code)}
                            className="bg-primary-50 text-primary-600 p-3.5 rounded-lg hover:bg-primary-100 transition-colors border border-primary-100"
                            title="Copiar código"
                          >
                            {copied ? <CheckIcon /> : <CopyIcon />}
                          </button>
                       </div>

                       {/* Details List */}
                       <div className="space-y-3 text-sm border-t border-gray-100 pt-4">
                          <div className="flex justify-between">
                             <span className="text-gray-500">Status</span>
                             <span className={`px-2 py-0.5 rounded text-xs font-bold uppercase ${statusColor}`}>
                               {selectedRedemption.status === 'PENDING' ? 'Disponível' : selectedRedemption.status === 'USED' ? 'Utilizado' : 'Expirado'}
                             </span>
                          </div>

                          {isUsed ? (
                             <>
                               <div className="flex justify-between">
                                  <span className="text-gray-500">Validado por</span>
                                  <span className="font-medium text-gray-900">{selectedRedemption.validatedBy || 'Loja'}</span>
                               </div>
                               <div className="flex justify-between">
                                  <span className="text-gray-500">Data de Uso</span>
                                  <span className="font-medium text-gray-900">
                                    {selectedRedemption.validatedAt ? new Date(selectedRedemption.validatedAt).toLocaleString('pt-BR') : '-'}
                                  </span>
                               </div>
                             </>
                          ) : (
                             <>
                               <div className="flex justify-between">
                                  <span className="text-gray-500">Resgatado em</span>
                                  <span className="font-medium text-gray-900">{new Date(selectedRedemption.redeemedAt).toLocaleDateString('pt-BR')}</span>
                               </div>
                               <div className="flex justify-between">
                                  <span className="text-gray-500">Válido até</span>
                                  <span className="font-medium text-red-600">{new Date(coupon.expiryDate).toLocaleDateString('pt-BR')}</span>
                               </div>
                             </>
                          )}
                       </div>

                       <div className="mt-8">
                         <Button fullWidth variant="secondary" onClick={() => setSelectedRedemption(null)}>Fechar</Button>
                       </div>
                    </div>
                 </div>
               );
            })()}
         </Modal>
      )}
    </div>
  );
};

{
  "name": "ShopPerks",
  "description": "Sistema premium de cupons inter-lojas para funcionários de shopping, com interface moderna e fluida.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React, { useState, useEffect } from 'react';
import { User, Store, Coupon, Redemption } from '../types';
import { Button } from './Button';
import { Modal } from './Modal';
import { Html5QrcodeScanner } from 'html5-qrcode';

interface ManagerDashboardProps {
  user: User;
  store: Store;
  coupons: Coupon[];
  redemptions: Redemption[]; // Global redemptions
  onCreateCoupon: (coupon: Omit<Coupon, 'id'>) => void;
  onValidateRedemption: (code: string) => boolean;
}

export const ManagerDashboard: React.FC<ManagerDashboardProps> = ({
  user, store, coupons, redemptions, onCreateCoupon, onValidateRedemption
}) => {
  const [view, setView] = useState<'coupons' | 'validate'>('coupons');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Validation State
  const [validationCode, setValidationCode] = useState('');
  const [validationResult, setValidationResult] = useState<'idle' | 'success' | 'error'>('idle');
  const [validationMessage, setValidationMessage] = useState('');

  // Scanner State
  const [isScannerOpen, setIsScannerOpen] = useState(false);

  // Form State
  const [newCoupon, setNewCoupon] = useState({
    title: '', description: '', discountValue: 0, quantity: 100
  });

  const myCoupons = coupons.filter(c => c.storeId === store.id);
  const myRedemptions = redemptions.filter(r => myCoupons.find(c => c.id === r.couponId));
  const totalRedemptions = myRedemptions.length;
  const activeCoupons = myCoupons.length;

  // Scanner Logic
  useEffect(() => {
    let scanner: any = null;
    let timer: any = null;

    if (isScannerOpen) {
      // Small delay to ensure the modal DOM is rendered
      timer = setTimeout(() => {
        try {
          scanner = new Html5QrcodeScanner(
            "reader",
            { 
              fps: 10, 
              qrbox: { width: 250, height: 250 },
              aspectRatio: 1.0,
              showTorchButtonIfSupported: true 
            },
            false
          );

          scanner.render(
            (decodedText: string) => {
              // On Success
              setValidationCode(decodedText);
              setIsScannerOpen(false); // This will trigger cleanup
              // Optional: Play a beep sound here
            },
            (error: any) => {
              // Ignore errors during scanning (e.g. no QR code found in frame)
            }
          );
        } catch (err) {
          console.error("Error initializing scanner:", err);
        }
      }, 100);
    }

    return () => {
      if (timer) clearTimeout(timer);
      if (scanner) {
        scanner.clear().catch((error: any) => {
          console.error("Failed to clear html5-qrcode scanner. ", error);
        });
      }
    };
  }, [isScannerOpen]);

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onCreateCoupon({
      storeId: store.id,
      title: newCoupon.title,
      description: newCoupon.description,
      discountType: 'PERCENTAGE', // Simplification
      discountValue: newCoupon.discountValue,
      expiryDate: new Date(Date.now() + 86400000 * 30).toISOString(), // 30 days
      category: store.category,
      availableQuantity: newCoupon.quantity,
      rules: ['Regra padrão']
    });
    setIsModalOpen(false);
  };

  const handleValidate = (e: React.FormEvent) => {
    e.preventDefault();
    const success = onValidateRedemption(validationCode);
    if (success) {
      setValidationResult('success');
      setValidationMessage('Cupom validado com sucesso!');
    } else {
      setValidationResult('error');
      setValidationMessage('Código inválido ou já utilizado.');
    }
  };

  return (
    <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 pt-8 pb-20">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-10 bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
         <div className="flex items-center gap-4 mb-4 md:mb-0">
            <img src={store.logoUrl} className="w-16 h-16 rounded-xl border border-gray-100 p-1 object-contain" alt="logo" />
            <div>
              <h1 className="text-2xl font-bold text-gray-900">{store.name}</h1>
              <p className="text-gray-500 text-sm">Painel do Gerente • {user.name}</p>
            </div>
         </div>
         <div className="flex gap-4 text-center">
            <div className="px-6 py-2 bg-gray-50 rounded-xl">
               <p className="text-2xl font-bold text-primary-600">{activeCoupons}</p>
               <p className="text-xs text-gray-500 uppercase font-bold">Cupons Ativos</p>
            </div>
            <div className="px-6 py-2 bg-gray-50 rounded-xl">
               <p className="text-2xl font-bold text-accent-500">{totalRedemptions}</p>
               <p className="text-xs text-gray-500 uppercase font-bold">Resgates</p>
            </div>
         </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-4 border-b border-gray-200 mb-8">
         <button onClick={() => setView('coupons')} className={`pb-3 px-2 text-sm font-semibold transition-colors ${view === 'coupons' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-gray-400'}`}>Gerenciar Cupons</button>
         <button onClick={() => setView('validate')} className={`pb-3 px-2 text-sm font-semibold transition-colors ${view === 'validate' ? 'text-primary-600 border-b-2 border-primary-600' : 'text-gray-400'}`}>Validar Resgates</button>
      </div>

      {view === 'coupons' && (
        <div className="animate-fade-in-up">
           <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-bold text-gray-800">Seus Cupons Publicados</h2>
              <Button onClick={() => setIsModalOpen(true)}>+ Criar Cupom</Button>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {myCoupons.map(coupon => (
                 <div key={coupon.id} className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-all">
                    <h3 className="font-bold text-gray-900 mb-2">{coupon.title}</h3>
                    <div className="flex justify-between text-sm text-gray-500 mt-4">
                       <span>{coupon.availableQuantity} restantes</span>
                       <span className="text-primary-600 font-semibold">{coupon.discountValue}% OFF</span>
                    </div>
                 </div>
              ))}
           </div>
        </div>
      )}

      {view === 'validate' && (
        <div className="max-w-md mx-auto bg-white p-8 rounded-3xl shadow-lg border border-gray-100 animate-pop-in">
           <h2 className="text-xl font-bold text-gray-900 mb-6 text-center">Validar Cupom</h2>

           <div className="mb-6 flex justify-center">
              <button 
                type="button"
                onClick={() => setIsScannerOpen(true)}
                className="flex flex-col items-center justify-center w-full py-6 border-2 border-dashed border-primary-200 rounded-2xl bg-primary-50 hover:bg-primary-100 transition-colors group"
              >
                <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-sm mb-2 group-hover:scale-110 transition-transform">
                   <svg className="w-6 h-6 text-primary-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
