interface ProfileModalProps {
  user: User;
  isOpen: boolean;
  onClose: () => void;
  onUpdateUser: (updatedData: Partial<User> & { password?: string }) => void;
}

export const ProfileModal: React.FC<ProfileModalProps> = ({ user, isOpen, onClose, onUpdateUser }) => {
  const [formData, setFormData] = useState({
    name: user.name,
    avatarUrl: user.avatarUrl || '',
    password: '',
    confirmPassword: ''
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (formData.password && formData.password !== formData.confirmPassword) {
      setError('As senhas não coincidem.');
      return;
    }

    setLoading(true);
    // Simulate API call
    setTimeout(() => {
      onUpdateUser({
        name: formData.name,
        avatarUrl: formData.avatarUrl,
        ...(formData.password ? { password: formData.password } : {})
      });
      setLoading(false);
      onClose();
    }, 1000);
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose}>
      <div className="p-6">
        <h2 className="text-xl font-bold text-gray-900 mb-6">Meu Perfil</h2>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="flex justify-center mb-6">
             <div className="relative">
               <img 
                 src={formData.avatarUrl || `https://ui-avatars.com/api/?name=${formData.name}`} 
                 className="w-24 h-24 rounded-full border-4 border-gray-50 shadow-md object-cover" 
                 alt="Avatar"
               />
               <div className="absolute bottom-0 right-0 bg-primary-600 p-1.5 rounded-full text-white shadow-sm border-2 border-white">
                 <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
               </div>
             </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Nome Completo</label>
            <input 
              required 
              className="w-full border border-gray-300 p-3 rounded-xl focus:ring-2 focus:ring-primary-500 focus:outline-none transition-all" 
              value={formData.name} 
              onChange={e => setFormData({...formData, name: e.target.value})} 
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">URL do Avatar</label>
            <input 
              className="w-full border border-gray-300 p-3 rounded-xl focus:ring-2 focus:ring-primary-500 focus:outline-none transition-all text-sm text-gray-600" 
              value={formData.avatarUrl} 
              onChange={e => setFormData({...formData, avatarUrl: e.target.value})} 
              placeholder="https://..."
            />
          </div>

          <div className="pt-4 border-t border-gray-100 mt-4">
            <h3 className="text-sm font-bold text-gray-900 mb-3">Alterar Senha</h3>
            <div className="space-y-3">
              <div>
                <label className="block text-xs font-medium text-gray-500 mb-1">Nova Senha</label>
                <input 
                  type="password"
                  className="w-full border border-gray-300 p-3 rounded-xl focus:ring-2 focus:ring-primary-500 focus:outline-none transition-all" 
                  value={formData.password} 
                  onChange={e => setFormData({...formData, password: e.target.value})} 
                  placeholder="Deixe em branco para manter"
                />
              </div>
              <div>
                <label className="block text-xs font-medium text-gray-500 mb-1">Confirmar Nova Senha</label>
                <input 
                  type="password"
                  className="w-full border border-gray-300 p-3 rounded-xl focus:ring-2 focus:ring-primary-500 focus:outline-none transition-all" 
                  value={formData.confirmPassword} 
                  onChange={e => setFormData({...formData, confirmPassword: e.target.value})} 
                />
              </div>
            </div>
            {error && <p className="text-red-500 text-sm mt-2">{error}</p>}
          </div>

          <div className="pt-4 flex gap-3">
            <Button type="button" variant="secondary" onClick={onClose} fullWidth>Cancelar</Button>
            <Button type="submit" fullWidth disabled={loading}>
              {loading ? 'Salvando...' : 'Salvar Alterações'}
            </Button>
          </div>
        </form>
      </div>
    </Modal>
  );
};

