import React, { useState } from 'react';
import { STORES, COUPONS, MY_REDEMPTIONS, USERS } from './constants';
import { Coupon, Store, User, UserRole, Redemption } from './types';
import { LoginScreen } from './components/LoginScreen';
import { EmployeeDashboard } from './components/EmployeeDashboard';
import { ManagerDashboard } from './components/ManagerDashboard';
import { AdminDashboard } from './components/AdminDashboard';
import { ProfileModal } from './components/ProfileModal';

export default function App() {
  const [user, setUser] = useState<User | null>(null);

  // Global Data State
  const [coupons, setCoupons] = useState<Coupon[]>(COUPONS);
  const [redemptions, setRedemptions] = useState<Redemption[]>(MY_REDEMPTIONS);
  const [stores, setStores] = useState<Store[]>(STORES);
  const [users, setUsers] = useState<User[]>(USERS);

  // UI State
  const [isProfileOpen, setIsProfileOpen] = useState(false);

  const handleLogin = (identifier: string) => {
    const id = identifier.toLowerCase();
    // Simplified login logic based on email simulation
    const foundUser = users.find(u => u.email === id);

    if (foundUser) {
      setUser(foundUser);
    } else {
      // Fallback for demo ease if exact email isn't typed
      if (id.includes('admin')) setUser(users.find(u => u.role === UserRole.ADMIN) || null);
      else if (id.includes('zara')) setUser(users.find(u => u.role === UserRole.MANAGER) || null);
      else setUser(users.find(u => u.role === UserRole.EMPLOYEE) || null);
    }
  };

  const handleLogout = () => setUser(null);

  // Store Management Actions
  const handleAddStore = (newStoreData: Omit<Store, 'id'>) => {
    const newStore: Store = { ...newStoreData, id: `s${Date.now()}` };
    setStores([...stores, newStore]);
  };

  const handleUpdateStore = (updatedStore: Store) => {
    setStores(stores.map(s => s.id === updatedStore.id ? updatedStore : s));
  };

  const handleDeleteStore = (storeId: string) => {
    setStores(stores.filter(s => s.id !== storeId));
  };

  // User Management Actions
  const handleAddUser = (newUserData: Omit<User, 'id'>) => {
    const newUser: User = { ...newUserData, id: `u${Date.now()}` };
    setUsers([...users, newUser]);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(users.map(u => u.id === updatedUser.id ? updatedUser : u));
    // If updating current user (admin editing self), update local state
    if (user && user.id === updatedUser.id) {
       setUser(updatedUser);
    }
  };

  const handleDeleteUser = (userId: string) => {
    setUsers(users.filter(u => u.id !== userId));
  };

  // Profile Update Action
  const handleProfileUpdate = (data: Partial<User> & { password?: string }) => {
    if (!user) return;
    const updatedUser = { ...user, ...data };
    delete (updatedUser as any).password; // Don't store password in user object in frontend state

    // Update global users list
    setUsers(users.map(u => u.id === user.id ? updatedUser : u));
    setUser(updatedUser);

    // Logic to handle password change (mock) would go here
    if(data.password) {
      console.log("Password updated for user", user.id);
    }
  };

  // Coupon & Redemption Actions
  const handleCreateCoupon = (couponData: Omit<Coupon, 'id'>) => {
    const newCoupon: Coupon = {
      ...couponData,
      id: `new_${Date.now()}`
    };
    setCoupons(prev => [newCoupon, ...prev]);
  };

  const handleRedeem = async (couponId: string): Promise<string> => {
    return new Promise((resolve) => {
      setTimeout(() => {
        const code = `CPN-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;
        if (user) {
          setRedemptions(prev => [{
            id: `r_${Date.now()}`,
            couponId,
            userId: user.id,
            code,
            status: 'PENDING',
            redeemedAt: new Date().toISOString()
          }, ...prev]);
        }
        resolve(code);
      }, 1500);
    });
  };

  const handleValidateRedemption = (code: string): boolean => {
    const redemption = redemptions.find(r => r.code === code && r.status === 'PENDING');
    if (redemption) {
      setRedemptions(prev => prev.map(r => 
        r.id === redemption.id ? { ...r, status: 'USED', validatedAt: new Date().toISOString(), validatedBy: user?.name } : r
      ));
      return true;
    }
    return false;
  };

  if (!user) {
    return <LoginScreen onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Global Navbar */}
      <nav className="bg-white sticky top-0 z-30 border-b border-gray-100 shadow-sm">
        <div className="max-w-6xl mx-auto px-4 h-16 flex justify-between items-center">
           <div className="flex items-center gap-2 cursor-pointer hover:opacity-80 transition-opacity" onClick={() => {/* Optional: Reset state logic if needed */}}>
              <div className="w-8 h-8 bg-primary-600 rounded-lg flex items-center justify-center text-white font-bold shadow-lg shadow-primary-200">SP</div>
              <span className="font-bold text-gray-900 tracking-tight hidden sm:block">ShopPerks</span>
           </div>
           <div className="flex items-center gap-4">
              <span className="text-sm text-gray-500 hidden sm:block bg-gray-50 px-3 py-1 rounded-full border border-gray-100">
                 {user.role === 'ADMIN' ? 'Administrador' : user.role === 'MANAGER' ? 'Gerente' : 'Funcionário'}
              </span>

              <div className="flex items-center gap-3 pl-3 border-l border-gray-100">
                <button onClick={() => setIsProfileOpen(true)} className="flex items-center gap-2 group">
                   <img src={user.avatarUrl || `https://ui-avatars.com/api/?name=${user.name}&background=820AD1&color=fff`} className="w-9 h-9 rounded-full border-2 border-white shadow-sm transition-transform group-hover:scale-105" alt="avatar" />
                   <span className="text-sm font-medium text-gray-700 hidden md:block group-hover:text-primary-600">{user.name.split(' ')[0]}</span>
                </button>
                <button onClick={handleLogout} className="text-sm font-semibold text-gray-400 hover:text-red-500 transition-colors ml-2" title="Sair">
                   <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
                </button>
              </div>
           </div>
        </div>
      </nav>

      {user.role === UserRole.EMPLOYEE && (
        <EmployeeDashboard 
          user={user} 
          stores={stores} 
          coupons={coupons} 
          redemptions={redemptions.filter(r => r.userId === user.id)}
          onRedeem={handleRedeem} 
        />
      )}

      {user.role === UserRole.MANAGER && user.storeId && (
        <ManagerDashboard 
          user={user}
          store={stores.find(s => s.id === user.storeId)!}
          coupons={coupons}
          redemptions={redemptions}
          onCreateCoupon={handleCreateCoupon}
          onValidateRedemption={handleValidateRedemption}
        />
      )}

      {user.role === UserRole.ADMIN && (
        <AdminDashboard 
          stores={stores} 
          users={users} 
          onAddStore={handleAddStore}
          onUpdateStore={handleUpdateStore}
          onDeleteStore={handleDeleteStore}
          onAddUser={handleAddUser}
          onUpdateUser={handleUpdateUser}
          onDeleteUser={handleDeleteUser}
        />
      )}

      {/* Profile Modal */}
      {user && (
        <ProfileModal 
          user={user} 
          isOpen={isProfileOpen} 
          onClose={() => setIsProfileOpen(false)} 
          onUpdateUser={handleProfileUpdate}
        />
      )}
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { Store, User, UserRole } from '../types';
import { Button } from './Button';
import { Modal } from './Modal';
import { CATEGORIES } from '../constants';

interface AdminDashboardProps {
  stores: Store[];
  users: User[];
  onAddStore: (store: Omit<Store, 'id'>) => void;
  onUpdateStore: (store: Store) => void;
  onDeleteStore: (storeId: string) => void;
  onAddUser: (user: Omit<User, 'id'>) => void;
  onUpdateUser: (user: User) => void;
  onDeleteUser: (userId: string) => void;
}

// Icons
const EditIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>;
const TrashIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>;
const SearchIcon = () => <svg className="w-5 h-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>;
const StoreIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>;
const UserIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>;
const ChevronDownIcon = () => <svg className="w-4 h-4 text-gray-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>;

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  stores, users, onAddStore, onUpdateStore, onDeleteStore, onAddUser, onUpdateUser, onDeleteUser 
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'stores' | 'users'>('overview');
  const [searchQuery, setSearchQuery] = useState('');

  // Store Modal State
  const [isStoreModalOpen, setIsStoreModalOpen] = useState(false);
  const [editingStore, setEditingStore] = useState<Store | null>(null);
  const [storeFormData, setStoreFormData] = useState<Partial<Store>>({ name: '', category: 'Moda', floor: '', logoUrl: '', coverUrl: '' });

  // User Modal State
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [userFormData, setUserFormData] = useState<Partial<User>>({ name: '', email: '', role: UserRole.EMPLOYEE, storeId: '' });

  // Filtering
  const filteredStores = useMemo(() => {
    return stores.filter(s => s.name.toLowerCase().includes(searchQuery.toLowerCase()) || s.category.toLowerCase().includes(searchQuery.toLowerCase()));
  }, [stores, searchQuery]);

  const filteredUsers = useMemo(() => {
    return users.filter(u => u.name.toLowerCase().includes(searchQuery.toLowerCase()) || u.email.toLowerCase().includes(searchQuery.toLowerCase()));
  }, [users, searchQuery]);

  // Handlers - Stores
  const handleOpenAddStore = () => {
    setEditingStore(null);
    setStoreFormData({ name: '', category: 'Moda', floor: '', logoUrl: '', coverUrl: '' });
    setIsStoreModalOpen(true);
  };

  const handleOpenEditStore = (store: Store) => {
    setEditingStore(store);
    setStoreFormData(store);
    setIsStoreModalOpen(true);
  };

  const handleSubmitStore = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingStore) {
      onUpdateStore({ ...editingStore, ...storeFormData } as Store);
    } else {
      onAddStore(storeFormData as Omit<Store, 'id'>);
    }
    setIsStoreModalOpen(false);
  };

  // Handlers - Users
  const handleOpenAddUser = () => {
    setEditingUser(null);
    setUserFormData({ name: '', email: '', role: UserRole.EMPLOYEE, storeId: stores[0]?.id || '' });
    setIsUserModalOpen(true);
  };

  const handleOpenEditUser = (user: User) => {
    setEditingUser(user);
    setUserFormData(user);
    setIsUserModalOpen(true);
  };

  const handleSubmitUser = (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
       ...userFormData,
       // If role is admin, clear storeId
       storeId: userFormData.role === UserRole.ADMIN ? undefined : userFormData.storeId
    };

    if (editingUser) {
      onUpdateUser({ ...editingUser, ...payload } as User);
    } else {
      onAddUser(payload as Omit<User, 'id'>);
    }
    setIsUserModalOpen(false);
  };

  const inputClasses = "w-full border border-gray-300 p-3 rounded-xl focus:ring-2 focus:ring-primary-500 focus:outline-none transition-all bg-white";
  const selectClasses = "w-full border border-gray-300 p-3 rounded-xl focus:ring-2 focus:ring-primary-500 focus:outline-none transition-all bg-white appearance-none";

  return (
    <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 pt-8 pb-20">
       <div className="flex flex-col md:flex-row justify-between items-end md:items-center mb-8 gap-4">
         <div>
            <h1 className="text-3xl font-bold text-gray-900">Painel do Administrador</h1>
            <p className="text-gray-500 mt-1">Gerencie a estrutura e o acesso do shopping.</p>
         </div>
         <div className="flex bg-white rounded-xl p-1.5 border border-gray-200 shadow-sm">
            <button 
              onClick={() => setActiveTab('overview')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all ${activeTab === 'overview' ? 'bg-primary-50 text-primary-700 shadow-sm' : 'text-gray-500 hover:text-gray-900 hover:bg-gray-50'}`}
            >
              Visão Geral
            </button>
            <button 
              onClick={() => setActiveTab('stores')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all flex items-center gap-2 ${activeTab === 'stores' ? 'bg-primary-50 text-primary-700 shadow-sm' : 'text-gray-500 hover:text-gray-900 hover:bg-gray-50'}`}
            >
              <StoreIcon /> Lojas
            </button>
            <button 
              onClick={() => setActiveTab('users')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all flex items-center gap-2 ${activeTab === 'users' ? 'bg-primary-50 text-primary-700 shadow-sm' : 'text-gray-500 hover:text-gray-900 hover:bg-gray-50'}`}
            >
              <UserIcon /> Usuários
            </button>
         </div>
       </div>

       {/* Search Bar (Shared for Stores and Users tabs) */}
       {activeTab !== 'overview' && (
         <div className="mb-6 flex gap-4 animate-fade-in">
           <div className="relative flex-1">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
               <SearchIcon />
             </div>
             <input
               type="text"
               placeholder={activeTab === 'stores' ? "Buscar loja..." : "Buscar usuário..."}
               className="block w-full pl-10 pr-3 py-3 border border-gray-200 rounded-xl leading-5 bg-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-primary-200 focus:border-primary-500 transition-all shadow-sm"
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
             />
           </div>
           <Button onClick={activeTab === 'stores' ? handleOpenAddStore : handleOpenAddUser} className="shrink-0">
             {activeTab === 'stores' ? '+ Nova Loja' : '+ Novo Usuário'}
           </Button>
         </div>
       )}

       {activeTab === 'overview' && (
         <div className="grid grid-cols-1 md:grid-cols-2 gap-8 animate-fade-in-up">
            {/* Quick Stats */}
            <div className="col-span-1 md:col-span-2 grid grid-cols-1 sm:grid-cols-3 gap-6 mb-4">
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col justify-between h-32 hover:shadow-md transition-shadow">
                 <div className="flex justify-between items-start">
                    <p className="text-gray-500 text-xs font-bold uppercase tracking-wider">Total de Lojas</p>
