                 </div>
                 <p className="text-4xl font-extrabold text-gray-900">{stores.length}</p>
              </div>
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col justify-between h-32 hover:shadow-md transition-shadow">
                 <div className="flex justify-between items-start">
                    <p className="text-gray-500 text-xs font-bold uppercase tracking-wider">Usuários Ativos</p>
                    <div className="p-2 bg-accent-50 text-accent-600 rounded-lg"><UserIcon /></div>
                 </div>
                 <p className="text-4xl font-extrabold text-gray-900">{users.length}</p>
              </div>
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col justify-between h-32 hover:shadow-md transition-shadow">
