       )}

       {activeTab === 'stores' && (
         <div className="animate-fade-in-up space-y-6">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
               {filteredStores.map(store => (
                  <div key={store.id} className="bg-white rounded-2xl p-5 border border-gray-100 shadow-sm hover:shadow-lg transition-all group flex flex-col">
                     <div className="flex items-center gap-4 mb-4">
                        <img src={store.logoUrl} className="w-14 h-14 rounded-xl object-contain bg-gray-50 border border-gray-100" alt={store.name} />
                        <div>
                           <h3 className="font-bold text-gray-900 text-lg leading-tight">{store.name}</h3>
                           <span className="inline-block mt-1 px-2 py-0.5 rounded text-xs font-medium bg-gray-100 text-gray-600">
                             {store.category}
