                        </div>
                     </div>
                     <div className="mt-auto flex items-center justify-between pt-4 border-t border-gray-50">
                        <span className="text-sm text-gray-400 font-medium">Piso {store.floor}</span>
                        <div className="flex gap-2 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity">
                           <button onClick={() => handleOpenEditStore(store)} className="p-2 text-primary-600 hover:bg-primary-50 rounded-lg transition-colors" title="Editar">
                              <EditIcon />
                           </button>
                           <button onClick={() => onDeleteStore(store.id)} className="p-2 text-red-500 hover:bg-red-50 rounded-lg transition-colors" title="Remover">
                              <TrashIcon />
                           </button>
                        </div>
                     </div>
                  </div>
               ))}
            </div>
            {filteredStores.length === 0 && <div className="text-center py-12 text-gray-400">Nenhuma loja encontrada.</div>}
         </div>
       )}

       {activeTab === 'users' && (
         <div className="animate-fade-in-up">
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
               <div className="overflow-x-auto">
                 <table className="w-full text-left border-collapse">
                    <thead className="bg-gray-50 text-gray-400 text-xs uppercase font-semibold">
                       <tr>
                          <th className="px-6 py-4">Usuário</th>
                          <th className="px-6 py-4">Função</th>
                          <th className="px-6 py-4">Loja Associada</th>
                          <th className="px-6 py-4 text-right">Ações</th>
                       </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100 text-sm">
                       {filteredUsers.map(u => {
                          const userStore = stores.find(s => s.id === u.storeId);
                          return (
                            <tr key={u.id} className="hover:bg-gray-50 transition-colors">
                               <td className="px-6 py-4">
                                  <div className="flex items-center gap-3">
                                     <div className="w-9 h-9 rounded-full bg-primary-100 text-primary-700 flex items-center justify-center font-bold text-xs">
                                       {u.avatarUrl ? <img src={u.avatarUrl} className="w-full h-full rounded-full object-cover" /> : u.name.substring(0,2).toUpperCase()}
                                     </div>
                                     <div>
                                       <p className="font-bold text-gray-900">{u.name}</p>
                                       <p className="text-gray-500 text-xs">{u.email}</p>
                                     </div>
                                  </div>
                               </td>
                               <td className="px-6 py-4">
                                  <span className={`px-2 py-1 rounded-md text-xs font-bold ${
                                    u.role === UserRole.ADMIN ? 'bg-purple-100 text-purple-700' :
                                    u.role === UserRole.MANAGER ? 'bg-blue-100 text-blue-700' :
                                    'bg-green-100 text-green-700'
                                  }`}>
                                    {u.role === UserRole.ADMIN ? 'Administrador' : u.role === UserRole.MANAGER ? 'Gerente' : 'Funcionário'}
                                  </span>
                               </td>
                               <td className="px-6 py-4 text-gray-600">
                                  {userStore ? (
                                    <div className="flex items-center gap-2">
                                       <img src={userStore.logoUrl} className="w-5 h-5 rounded object-contain" />
                                       <span>{userStore.name}</span>
