                          );
                       })}
                    </tbody>
                 </table>
               </div>
            </div>
         </div>
       )}

       {/* Store Modal */}
       <Modal isOpen={isStoreModalOpen} onClose={() => setIsStoreModalOpen(false)}>
          <div className="p-6">
             <h2 className="text-xl font-bold mb-6 text-gray-900">{editingStore ? 'Editar Loja' : 'Nova Loja'}</h2>
             <form onSubmit={handleSubmitStore} className="space-y-4">
