import React, { useState } from 'react';
import { STORES, COUPONS, MY_REDEMPTIONS, USERS } from './constants';
import { Coupon, Store, User, UserRole, Redemption } from './types';
import { LoginScreen } from './components/LoginScreen';
import { EmployeeDashboard } from './components/EmployeeDashboard';
import { ManagerDashboard } from './components/ManagerDashboard';
import { AdminDashboard } from './components/AdminDashboard';
import { ProfileModal } from './components/ProfileModal';

export default function App() {
  const [user, setUser] = useState<User | null>(null);

  // Global Data State
  const [coupons, setCoupons] = useState<Coupon[]>(COUPONS);
  const [redemptions, setRedemptions] = useState<Redemption[]>(MY_REDEMPTIONS);
  const [stores, setStores] = useState<Store[]>(STORES);
  const [users, setUsers] = useState<User[]>(USERS);

  // UI State
  const [isProfileOpen, setIsProfileOpen] = useState(false);

  const handleLogin = (identifier: string) => {
    const id = identifier.toLowerCase();
    // Simplified login logic based on email simulation
    const foundUser = users.find(u => u.email === id);

    if (foundUser) {
      setUser(foundUser);
    } else {
      // Fallback for demo ease if exact email isn't typed
      if (id.includes('admin')) setUser(users.find(u => u.role === UserRole.ADMIN) || null);
      else if (id.includes('zara')) setUser(users.find(u => u.role === UserRole.MANAGER) || null);
      else setUser(users.find(u => u.role === UserRole.EMPLOYEE) || null);
    }
  };

  const handleLogout = () => setUser(null);

  // Store Management Actions
  const handleAddStore = (newStoreData: Omit<Store, 'id'>) => {
    const newStore: Store = { ...newStoreData, id: `s${Date.now()}` };
    setStores([...stores, newStore]);
  };

  const handleUpdateStore = (updatedStore: Store) => {
    setStores(stores.map(s => s.id === updatedStore.id ? updatedStore : s));
  };

  const handleDeleteStore = (storeId: string) => {
    setStores(stores.filter(s => s.id !== storeId));
  };

  // User Management Actions
  const handleAddUser = (newUserData: Omit<User, 'id'>) => {
    const newUser: User = { ...newUserData, id: `u${Date.now()}` };
    setUsers([...users, newUser]);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(users.map(u => u.id === updatedUser.id ? updatedUser : u));
    // If updating current user (admin editing self), update local state
    if (user && user.id === updatedUser.id) {
       setUser(updatedUser);
    }
  };

  const handleDeleteUser = (userId: string) => {
    setUsers(users.filter(u => u.id !== userId));
  };

  // Profile Update Action
  const handleProfileUpdate = (data: Partial<User> & { password?: string }) => {
    if (!user) return;
    const updatedUser = { ...user, ...data };
    delete (updatedUser as any).password; // Don't store password in user object in frontend state

    // Update global users list
    setUsers(users.map(u => u.id === user.id ? updatedUser : u));
    setUser(updatedUser);

    // Logic to handle password change (mock) would go here
    if(data.password) {
      console.log("Password updated for user", user.id);
    }
  };

  // Coupon & Redemption Actions
  const handleCreateCoupon = (couponData: Omit<Coupon, 'id'>) => {
    const newCoupon: Coupon = {
      ...couponData,
      id: `new_${Date.now()}`
    };
    setCoupons(prev => [newCoupon, ...prev]);
  };

  const handleRedeem = async (couponId: string): Promise<string> => {
    return new Promise((resolve) => {
      setTimeout(() => {
        const code = `CPN-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;
        if (user) {
          setRedemptions(prev => [{
            id: `r_${Date.now()}`,
            couponId,
            userId: user.id,
            code,
            status: 'PENDING',
            redeemedAt: new Date().toISOString()
          }, ...prev]);
        }
        resolve(code);
      }, 1500);
    });
  };

  const handleValidateRedemption = (code: string): boolean => {
    const redemption = redemptions.find(r => r.code === code && r.status === 'PENDING');
    if (redemption) {
      setRedemptions(prev => prev.map(r => 
        r.id === redemption.id ? { ...r, status: 'USED', validatedAt: new Date().toISOString(), validatedBy: user?.name } : r
      ));
      return true;
    }
    return false;
  };

  if (!user) {
    return <LoginScreen onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-gray-900 text-gray-50 font-sans selection:bg-primary-500 selection:text-gray-900">
      {/* Global Navbar */}
      <nav className="bg-gray-800/80 backdrop-blur-md sticky top-0 z-30 border-b border-gray-700 shadow-md">
        <div className="max-w-6xl mx-auto px-4 h-16 flex justify-between items-center">
           <div className="flex items-center gap-2 cursor-pointer hover:opacity-80 transition-opacity" onClick={() => {/* Optional: Reset state logic if needed */}}>
              <div className="w-8 h-8 bg-gradient-to-br from-primary-400 to-primary-600 rounded-lg flex items-center justify-center text-gray-900 font-bold shadow-lg shadow-primary-500/20">SP</div>
              <span className="font-bold text-gray-100 tracking-tight hidden sm:block">ShopPerks</span>
           </div>
           <div className="flex items-center gap-4">
              <span className="text-xs font-semibold text-primary-400 hidden sm:block bg-primary-900/30 px-3 py-1 rounded-full border border-primary-500/20 uppercase tracking-wide">
                 {user.role === 'ADMIN' ? 'Administrador' : user.role === 'MANAGER' ? 'Gerente' : 'Funcionário'}
              </span>

              <div className="flex items-center gap-3 pl-3 border-l border-gray-700">
                <button onClick={() => setIsProfileOpen(true)} className="flex items-center gap-2 group">
                   <img src={user.avatarUrl || `https://ui-avatars.com/api/?name=${user.name}&background=D4AF37&color=0f172a`} className="w-9 h-9 rounded-full border-2 border-gray-700 shadow-sm transition-transform group-hover:scale-105 group-hover:border-primary-500" alt="avatar" />
                   <span className="text-sm font-medium text-gray-200 hidden md:block group-hover:text-primary-400 transition-colors">{user.name.split(' ')[0]}</span>
                </button>
                <button onClick={handleLogout} className="text-sm font-semibold text-gray-400 hover:text-red-400 transition-colors ml-2" title="Sair">
                   <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
                </button>
              </div>
           </div>
        </div>
      </nav>

      {user.role === UserRole.EMPLOYEE && (
        <EmployeeDashboard 
          user={user} 
          stores={stores} 
          coupons={coupons} 
          redemptions={redemptions.filter(r => r.userId === user.id)}
          onRedeem={handleRedeem} 
        />
      )}

      {user.role === UserRole.MANAGER && user.storeId && (
        <ManagerDashboard 
          user={user}
          store={stores.find(s => s.id === user.storeId)!}
          coupons={coupons}
          redemptions={redemptions}
          onCreateCoupon={handleCreateCoupon}
          onValidateRedemption={handleValidateRedemption}
        />
      )}

      {user.role === UserRole.ADMIN && (
        <AdminDashboard 
          stores={stores} 
          users={users} 
          onAddStore={handleAddStore}
          onUpdateStore={handleUpdateStore}
          onDeleteStore={handleDeleteStore}
          onAddUser={handleAddUser}
          onUpdateUser={handleUpdateUser}
          onDeleteUser={handleDeleteUser}
        />
      )}

      {/* Profile Modal */}
      {user && (
        <ProfileModal 
          user={user} 
          isOpen={isProfileOpen} 
          onClose={() => setIsProfileOpen(false)} 
          onUpdateUser={handleProfileUpdate}
        />
      )}
    </div>
  );
}

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost' | 'danger';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false, 
  className = '',
  ...props 
}) => {
  const baseStyles = "font-bold py-3 px-6 rounded-xl transition-all duration-200 flex items-center justify-center gap-2 active:scale-95 disabled:opacity-50 disabled:pointer-events-none tracking-wide text-sm";

  const variants = {
    // Primary Action (10% Rule): Gold Background, Dark Text for max contrast
    primary: "bg-primary-400 text-gray-900 shadow-lg shadow-primary-500/20 hover:bg-primary-300 hover:shadow-primary-500/30",
    // Secondary: Slate 700 (Lighter Surface), White Text
    secondary: "bg-gray-700 text-white border border-gray-600 hover:bg-gray-600 hover:border-gray-500",
    // Outline: Gold Border, Gold Text
    outline: "border-2 border-primary-500 text-primary-400 hover:bg-primary-500/10",
    // Ghost: Subtle gray text
    ghost: "text-gray-400 hover:text-white hover:bg-gray-800",
    // Danger: Red
    danger: "bg-red-500/10 text-red-400 border border-red-500/50 hover:bg-red-500 hover:text-white"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React from 'react';
import { Coupon, Store } from '../types';
import { Button } from './Button';

interface CouponCardProps {
  coupon: Coupon;
  store: Store;
  onClick: () => void;
}

export const CouponCard: React.FC<CouponCardProps> = ({ coupon, store, onClick }) => {
  // Determine gradient based on category, kept subtle for dark theme
  const getGradient = (cat: string) => {
    switch(cat) {
      case 'Alimentação': return 'from-orange-500/30 to-red-500/30';
      case 'Moda': return 'from-purple-500/30 to-pink-500/30';
      case 'Esportes': return 'from-blue-500/30 to-cyan-500/30';
      default: return 'from-gray-700 to-gray-600';
    }
  };

  return (
    <div 
      className="group bg-gray-800 rounded-2xl overflow-hidden border border-gray-700 shadow-lg hover:shadow-primary-500/20 hover:border-primary-500/50 transition-all duration-300 flex flex-col h-full cursor-pointer relative"
      onClick={onClick}
    >
      {/* Discount Badge */}
      <div className="absolute top-3 right-3 z-10">
        <div className="bg-gray-900/90 backdrop-blur-md px-3 py-1 rounded-full shadow-sm border border-gray-700">
          <span className="text-primary-400 font-bold text-sm">
            {coupon.discountType === 'PERCENTAGE' 
              ? `${coupon.discountValue}% OFF` 
              : `R$ ${coupon.discountValue} OFF`}
          </span>
        </div>
      </div>

      {/* Image Section */}
      <div className="relative h-40 overflow-hidden bg-gray-900">
        <div className={`absolute inset-0 bg-gradient-to-br ${getGradient(store.category)} opacity-40 z-0`} />
        <img 
          src={store.coverUrl} 
          alt={store.name} 
          className="w-full h-full object-cover transform group-hover:scale-105 transition-transform duration-500 opacity-80 group-hover:opacity-100"
        />
        {/* Logo overlay */}
        <div className="absolute -bottom-6 left-4 bg-gray-800 p-1 rounded-xl shadow-md border border-gray-700 w-16 h-16 flex items-center justify-center z-10">
           <div className="w-full h-full rounded-lg overflow-hidden bg-white flex items-center justify-center">
             {store.logoUrl.includes('http') ? (
                <img src={store.logoUrl} alt="logo" className="w-full h-full object-contain" />
             ) : (
                <span className="text-xs font-bold text-gray-900">{store.name.substring(0,2)}</span>
             )}
           </div>
        </div>
      </div>

      {/* Content Section */}
      <div className="p-4 pt-8 flex-1 flex flex-col">
        <div className="flex justify-between items-start mb-1">
          <span className="text-xs font-bold text-gray-500 uppercase tracking-wider">
            {store.category} • {store.floor}
          </span>
        </div>

        <h3 className="text-lg font-bold text-gray-100 leading-tight mb-2 line-clamp-2 group-hover:text-primary-400 transition-colors">
          {coupon.title}
        </h3>

        <p className="text-gray-400 text-sm mb-4 line-clamp-2 flex-1 font-medium">
          {coupon.description}
        </p>

        <div className="flex items-center justify-between mt-auto pt-4 border-t border-gray-700">
          <div className="text-xs text-gray-500">
            Válido até <br/>
            <span className="text-gray-300 font-semibold">
              {new Date(coupon.expiryDate).toLocaleDateString('pt-BR')}
            </span>
          </div>

          <Button 
            variant="outline" 
            className="!py-2 !px-4 !text-xs !rounded-lg"
            onClick={(e) => {
              e.stopPropagation();
              onClick();
            }}
          >
            Ver Cupom
          </Button>
        </div>
      </div>
    </div>
  );
};

