interface EmployeeDashboardProps {
  user: User;
  stores: Store[];
  coupons: Coupon[];
  redemptions: Redemption[];
  onRedeem: (couponId: string) => Promise<string>;
}

export const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({ 
  user, stores, coupons, redemptions, onRedeem 
}) => {
  const [currentView, setCurrentView] = useState<'home' | 'my-coupons'>('home');
  const [selectedCategory, setSelectedCategory] = useState('Todos');
  const [searchQuery, setSearchQuery] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [sortBy, setSortBy] = useState<'newest' | 'expiring' | 'discount'>('newest');

  // Loading State for Skeletons
  const [isLoadingFeed, setIsLoadingFeed] = useState(true);

  // Notification State
  const [showNotifications, setShowNotifications] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);

  // Modal State
  const [selectedCoupon, setSelectedCoupon] = useState<{coupon: Coupon, store: Store} | null>(null);
  const [selectedRedemption, setSelectedRedemption] = useState<Redemption | null>(null);
  const [isRedeeming, setIsRedeeming] = useState(false);
  const [redemptionCode, setRedemptionCode] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  // Simulate initial loading
  useEffect(() => {
    const timer = setTimeout(() => setIsLoadingFeed(false), 1500);
    return () => clearTimeout(timer);
  }, []);

  // Close notifications when clicking outside
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Notifications Logic
  const notifications = useMemo(() => {
    const today = new Date();
    const alerts: Array<{id: string, title: string, message: string, daysLeft: number}> = [];

    redemptions.forEach(r => {
      if (r.status !== 'PENDING') return;
      const coupon = coupons.find(c => c.id === r.couponId);
      if (!coupon) return;

      const expiry = new Date(coupon.expiryDate);
      const diffTime = expiry.getTime() - today.getTime();
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (diffDays <= 7 && diffDays >= 0) {
        alerts.push({
          id: r.id,
          title: 'Cupom Expirando',
          message: `"${coupon.title}" expira em ${diffDays === 0 ? 'menos de 24h' : diffDays + ' dias'}.`,
          daysLeft: diffDays
        });
      }
    });

    return alerts.sort((a, b) => a.daysLeft - b.daysLeft);
  }, [redemptions, coupons]);

  // Filter Logic
  const filteredCoupons = useMemo(() => {
    let result = coupons.filter(coupon => {
      const store = stores.find(s => s.id === coupon.storeId);
      if (!store) return false;

      const matchesCategory = selectedCategory === 'Todos' || coupon.category === selectedCategory;
      const matchesSearch = 
        coupon.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        store.name.toLowerCase().includes(searchQuery.toLowerCase());

      return matchesCategory && matchesSearch;
    });

    result = result.sort((a, b) => {
      if (sortBy === 'expiring') return new Date(a.expiryDate).getTime() - new Date(b.expiryDate).getTime();
      if (sortBy === 'discount') return b.discountValue - a.discountValue;
      return 0; 
    });

    return result;
  }, [coupons, stores, selectedCategory, searchQuery, sortBy]);

  const handleOpenCoupon = (coupon: Coupon) => {
    const store = stores.find(s => s.id === coupon.storeId);
    if (store) {
      setSelectedCoupon({ coupon, store });
      setIsRedeeming(false);
      setRedemptionCode(null);
    }
  };

  const executeRedeem = async () => {
    if (!selectedCoupon) return;
    setIsRedeeming(true);
    try {
      const code = await onRedeem(selectedCoupon.coupon.id);
      setRedemptionCode(code);

      // Trigger Confetti
      if ((window as any).confetti) {
        (window as any).confetti({
          particleCount: 150,
          spread: 70,
          origin: { y: 0.6 },
          colors: ['#D4AF37', '#10b981', '#ffffff'] // Gold, Green, White
        });
      }
    } catch (e) {
      alert("Erro ao resgatar");
    } finally {
      setIsRedeeming(false);
    }
  };

  const handleCopyCode = (code: string) => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 pt-8 pb-20">
      {/* Header with Navigation and Notifications */}
      <div className="flex justify-between items-start mb-8 animate-fade-in-up">
        <div className="flex items-center gap-3">
          {currentView !== 'home' && (
             <button 
               onClick={() => setCurrentView('home')} 
               className="p-2 rounded-full bg-gray-800 text-gray-400 hover:text-primary-400 shadow-sm border border-gray-700 hover:border-primary-500/50 transition-colors"
               title="Voltar ao início"
             >
                <BackIcon />
             </button>
          )}
          <div>
            <h1 className="text-3xl font-extrabold text-white leading-tight">
              {currentView === 'home' ? `Olá, ${user.name.split(' ')[0]}!` : 'Minha Carteira'}
            </h1>
            <p className="text-gray-400 mt-1">
              {currentView === 'home' ? 'Explore os descontos disponíveis no shopping hoje.' : 'Seus cupons ativos e histórico.'}
            </p>
          </div>
        </div>

        {/* Notification Bell */}
        <div className="relative" ref={notificationRef}>
          <button 
            onClick={() => setShowNotifications(!showNotifications)} 
            className={`p-3 rounded-xl border shadow-sm transition-all duration-200 relative group ${showNotifications ? 'bg-primary-500/10 border-primary-500/50 text-primary-400' : 'bg-gray-800 border-gray-700 hover:bg-gray-700 text-gray-400'}`}
          >
            <BellIcon />
            {notifications.length > 0 && (
               <span className="absolute top-2.5 right-3 flex h-2.5 w-2.5">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2.5 w-2.5 bg-red-500 border-2 border-gray-900"></span>
               </span>
            )}
          </button>

          {showNotifications && (
            <div className="absolute right-0 top-full mt-2 w-80 bg-gray-800 rounded-2xl shadow-xl border border-gray-700 p-0 z-50 animate-pop-in overflow-hidden ring-1 ring-black/5">
               <div className="p-4 border-b border-gray-700 bg-gray-900/50">
                 <h3 className="font-bold text-gray-100 text-sm">Notificações</h3>
               </div>
               {notifications.length === 0 ? (
                 <div className="p-8 text-center">
                    <p className="text-sm text-gray-500">Tudo limpo por aqui! ✨</p>
                 </div>
               ) : (
                 <div className="max-h-80 overflow-y-auto">
                    {notifications.map((notif) => (
                      <div 
                        key={notif.id} 
                        className="flex gap-3 items-start p-4 hover:bg-gray-700/50 transition-colors border-b border-gray-700 last:border-0 cursor-pointer"
                        onClick={() => {
                           const r = redemptions.find(x => x.id === notif.id);
                           if (r) setSelectedRedemption(r);
                           setShowNotifications(false);
                        }}
                      >
                        <div className={`w-2 h-2 mt-1.5 rounded-full shrink-0 ${notif.daysLeft <= 1 ? 'bg-red-500' : 'bg-orange-400'}`} />
                        <div>
                           <p className="text-sm font-bold text-gray-200">{notif.title}</p>
                           <p className="text-xs text-gray-400 mt-0.5 leading-relaxed">{notif.message}</p>
                        </div>
                      </div>
                    ))}
                 </div>
               )}
            </div>
          )}
        </div>
      </div>

      {currentView === 'home' && (
         <div className="flex justify-center mb-8">
            <button 
              onClick={() => setCurrentView('my-coupons')}
              className="bg-gradient-to-r from-primary-600 to-primary-800 text-white shadow-lg shadow-primary-900/50 px-8 py-3 rounded-xl font-bold text-sm flex items-center gap-2 hover:shadow-xl hover:scale-[1.02] hover:from-primary-500 hover:to-primary-700 transition-all border border-primary-500/20"
            >
              <TicketIcon />
              Ver Meus Resgates
            </button>
         </div>
      )}

      {currentView === 'home' ? (
        <>
          {/* Filters */}
          <div className="mb-8 sticky top-20 z-20 md:static animate-fade-in-up" style={{ animationDelay: '100ms' }}>
              <div className="flex flex-col md:flex-row gap-3">
                <div className="relative flex-1 group">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-500 group-focus-within:text-primary-400 transition-colors">
                    <SearchIcon />
                  </div>
                  <input
                    type="text"
                    placeholder="Busque por loja..."
                    className="block w-full pl-10 pr-3 py-3 border border-gray-700 rounded-xl leading-5 bg-gray-800 text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500 transition-all shadow-sm"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                </div>
                <button 
                  onClick={() => setShowFilters(!showFilters)}
                  className={`flex items-center gap-2 px-5 py-3 rounded-xl border transition-all ${showFilters ? 'bg-gray-700 border-primary-500 text-primary-400' : 'bg-gray-800 border-gray-700 text-gray-400 hover:bg-gray-700'}`}
                >
                  <FilterIcon />
                  <span className="font-medium text-sm">Filtros</span>
                </button>
              </div>

              {showFilters && (
                <div className="mt-4 bg-gray-800 p-5 rounded-2xl border border-gray-700 shadow-lg animate-pop-in space-y-4">
                   <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      <div>
                        <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Ordenar Por</label>
                        <div className="flex flex-wrap gap-2">
                           {[
                             { id: 'newest', label: 'Mais Recentes' },
                             { id: 'expiring', label: 'Vai Expirar' },
                             { id: 'discount', label: 'Maior Desconto' }
                           ].map((opt) => (
                             <button 
                               key={opt.id}
                               onClick={() => setSortBy(opt.id as any)} 
                               className={`px-3 py-2 text-xs font-semibold rounded-lg border transition-colors ${sortBy === opt.id ? 'bg-primary-600 text-gray-900 border-primary-600' : 'bg-gray-700 text-gray-300 border-gray-600 hover:border-gray-500'}`}
                             >
                               {opt.label}
                             </button>
                           ))}
                        </div>
                      </div>
                      <div>
                        <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Categoria</label>
                        <div className="relative">
                          <select 
                            value={selectedCategory}
                            onChange={(e) => setSelectedCategory(e.target.value)}
                            className="block w-full pl-3 pr-10 py-2 text-sm border border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500 bg-gray-700 text-white"
                          >
                            {CATEGORIES.map(cat => (
                              <option key={cat} value={cat}>{cat}</option>
                            ))}
                          </select>
                        </div>
                      </div>
                   </div>
                </div>
              )}
          </div>

          {/* Grid */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 animate-fade-in-up" style={{ animationDelay: '200ms' }}>
            {isLoadingFeed 
              ? Array.from({ length: 6 }).map((_, i) => <CouponSkeleton key={i} />)
              : filteredCoupons.map((coupon, idx) => {
                  const store = stores.find(s => s.id === coupon.storeId);
                  if (!store) return null;
                  return (
                    <div key={coupon.id} style={{ animationDelay: `${(idx * 50)}ms` }} className="animate-fade-in-up">
                      <CouponCard coupon={coupon} store={store} onClick={() => handleOpenCoupon(coupon)} />
                    </div>
                  );
                })
            }
          </div>
        </>
      ) : (
        /* My Redemptions */
        <div className="max-w-2xl mx-auto animate-fade-in-up">
           <div className="space-y-4">
             {redemptions.length === 0 ? (
               <div className="text-center py-12 text-gray-500 border-2 border-dashed border-gray-700 rounded-2xl bg-gray-800/50">
                 <p>Nenhum cupom resgatado ainda.</p>
                 <Button onClick={() => setCurrentView('home')} className="mt-4" variant="outline">Explorar Cupons</Button>
               </div>
             ) : (
               redemptions.map(r => {
                  const coupon = coupons.find(c => c.id === r.couponId);
                  const store = stores.find(s => s.id === coupon?.storeId);
                  if(!coupon || !store) return null;

                  // Calculate days left
                  const expiry = new Date(coupon.expiryDate);
                  const daysLeft = Math.ceil((expiry.getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24));
                  const isExpiring = r.status === 'PENDING' && daysLeft <= 7 && daysLeft >= 0;

                  return (
                    <div key={r.id} onClick={() => setSelectedRedemption(r)} className="bg-gray-800 p-4 rounded-2xl border border-gray-700 shadow-sm flex items-center gap-4 cursor-pointer hover:shadow-md hover:border-primary-500/50 transition-all group relative overflow-hidden">
                      {isExpiring && <div className="absolute top-0 left-0 w-1 h-full bg-orange-500"></div>}
                      <img src={store.logoUrl} className="w-12 h-12 object-contain rounded-lg border border-gray-600 bg-white p-1" alt={store.name} />
                      <div className="flex-1">
                        <h4 className="font-bold text-gray-100 group-hover:text-primary-400 transition-colors">{coupon.title}</h4>
                        <div className="flex items-center gap-2 mt-1">
                          <span className="text-xs text-gray-500 font-medium">{store.name}</span>
                          {isExpiring && <span className="text-[10px] bg-orange-900/30 text-orange-400 px-2 py-0.5 rounded-full font-bold border border-orange-500/20">Expira em {daysLeft} dias</span>}
                        </div>
                      </div>
                      <span className={`px-3 py-1 rounded-full text-xs font-bold border ${
                        r.status === 'PENDING' ? 'bg-green-900/20 text-green-400 border-green-500/30' : 
                        r.status === 'USED' ? 'bg-gray-700 text-gray-400 border-gray-600' :
                        'bg-red-900/20 text-red-400 border-red-500/30'
                      }`}>
                        {r.status === 'PENDING' ? 'Ativo' : r.status === 'USED' ? 'Usado' : 'Expirado'}
                      </span>
                    </div>
                  );
               })
             )}
           </div>
        </div>
      )}

      {/* Coupon Details Modal (Pre-Redemption) */}
      {selectedCoupon && (
        <Modal isOpen={!!selectedCoupon} onClose={() => setSelectedCoupon(null)}>
           <div className="h-48 relative">
              <img src={selectedCoupon.store.coverUrl} className="w-full h-full object-cover" alt="Cover" />
              <div className="absolute inset-0 bg-gradient-to-t from-gray-900 via-gray-900/60 to-transparent" />
              <div className="absolute bottom-4 left-6 flex items-center gap-3 text-white">
                 <div className="bg-white p-1 rounded-lg shadow-lg">
                   <img src={selectedCoupon.store.logoUrl} className="w-10 h-10 object-contain" alt="logo"/>
                 </div>
                 <div>
                   <p className="font-bold text-lg leading-none text-white">{selectedCoupon.store.name}</p>
                   <p className="text-xs opacity-80 mt-1 text-gray-300">{selectedCoupon.store.category}</p>
                 </div>
              </div>
           </div>
           <div className="p-6 bg-gray-900">
              {!redemptionCode ? (
                <>
                  <h2 className="text-2xl font-bold text-white mb-2">{selectedCoupon.coupon.title}</h2>
                  <p className="text-gray-400 mb-6 leading-relaxed">{selectedCoupon.coupon.description}</p>

                  <div className="bg-gray-800 rounded-xl p-4 mb-6 border border-gray-700">
                    <h4 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Regras</h4>
                    <ul className="text-sm text-gray-300 space-y-2">
                      <li className="flex items-start gap-2">
                           <span className="text-primary-500 mt-1.5 w-1.5 h-1.5 rounded-full bg-primary-500 shrink-0"></span>
                           <span>Limite de uso: <strong>{selectedCoupon.coupon.maxUsesPerUser} por pessoa</strong>.</span>
                      </li>
                      {selectedCoupon.coupon.rules.map((rule, i) => (
                        <li key={i} className="flex items-start gap-2">
                           <span className="text-primary-500 mt-1.5 w-1.5 h-1.5 rounded-full bg-primary-500 shrink-0"></span>
                           <span>{rule}</span>
                        </li>
                      ))}
                    </ul>
                  </div>

                  {(() => {
                    const userRedemptionsCount = redemptions.filter(r => r.couponId === selectedCoupon.coupon.id).length;
                    const isLimitReached = userRedemptionsCount >= selectedCoupon.coupon.maxUsesPerUser;

                    return (
                       <Button fullWidth onClick={executeRedeem} disabled={isRedeeming || isLimitReached}>
                        {isRedeeming ? <><Spinner /> Gerando Cupom...</> : isLimitReached ? 'Limite de Uso Atingido' : 'Resgatar Cupom'}
                      </Button>
                    );
                  })()}
                </>
              ) : (
                <div className="text-center py-6 animate-pop-in">
                   {/* Success State - Green as requested for dopamine hit */}
                   <div className="w-20 h-20 bg-green-500/10 text-green-500 rounded-full flex items-center justify-center mx-auto mb-6 ring-4 ring-green-500/20">
                      <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                   </div>
                   <h3 className="text-2xl font-bold text-white mb-2">Sucesso!</h3>
                   <p className="text-gray-400 mb-6">Apresente este código na loja para validar.</p>

                   <div className="bg-gray-800 text-primary-400 text-3xl font-mono p-5 rounded-xl mb-6 tracking-widest border-2 border-dashed border-gray-600 shadow-inner">
                     {redemptionCode}
                   </div>

                   <Button variant="secondary" fullWidth onClick={() => setSelectedCoupon(null)}>Fechar e Usar Depois</Button>
                </div>
              )}
           </div>
        </Modal>
      )}

      {/* Redemption Status Modal (Post-Redemption / Wallet) */}
      {selectedRedemption && (
         <Modal isOpen={!!selectedRedemption} onClose={() => setSelectedRedemption(null)}>
            {(() => {
               const coupon = coupons.find(c => c.id === selectedRedemption.couponId);
               const store = stores.find(s => s.id === coupon?.storeId);
               if (!coupon || !store) return null;

               const isUsed = selectedRedemption.status === 'USED';
               const isExpired = selectedRedemption.status === 'EXPIRED';
               const statusColor = isUsed ? 'text-gray-500 bg-gray-800' : isExpired ? 'text-red-400 bg-red-900/20' : 'text-green-400 bg-green-900/20';

               return (
                 <div className="p-0 bg-gray-900">
                    <div className="bg-gradient-to-br from-primary-600 to-primary-800 p-6 text-gray-900 text-center relative overflow-hidden">
                       <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>
                       <h2 className="text-xl font-bold relative z-10">{store.name}</h2>
                       <p className="text-primary-900/80 text-sm relative z-10 font-medium">{coupon.title}</p>
                    </div>

                    <div className="p-6">
                       {/* QR Code Section */}
                       <div className="flex justify-center mb-6">
                         <div className="p-3 bg-white border border-gray-700 rounded-xl shadow-lg">
                            {isUsed || isExpired ? (
                               <div className="w-40 h-40 flex items-center justify-center bg-gray-100 rounded-lg">
                                  <span className="text-gray-400 font-bold opacity-50 text-xl rotate-45 border-4 border-gray-300 p-2 rounded-lg">
                                    {isUsed ? 'UTILIZADO' : 'EXPIRADO'}
                                  </span>
                               </div>
                            ) : (
                               <img 
                                 src={`https://api.qrserver.com/v1/create-qr-code/?size=160x160&data=${selectedRedemption.code}`} 
                                 alt="QR Code" 
                                 className="w-40 h-40" 
                               />
                            )}
                         </div>
                       </div>

                       {/* Code & Copy */}
                       <div className="flex items-center gap-2 mb-6">
                          <div className="flex-1 bg-gray-800 border border-gray-700 rounded-lg py-3 px-4 text-center">
                             <span className="font-mono text-xl font-bold text-gray-100 tracking-widest">{selectedRedemption.code}</span>
                          </div>
                          <button 
                            onClick={() => handleCopyCode(selectedRedemption.code)}
                            className="bg-gray-800 text-primary-400 p-3.5 rounded-lg hover:bg-gray-700 transition-colors border border-gray-700 hover:border-primary-500/50"
                            title="Copiar código"
                          >
                            {copied ? <CheckIcon /> : <CopyIcon />}
                          </button>
                       </div>

                       {/* Details List */}
                       <div className="space-y-3 text-sm border-t border-gray-700 pt-4">
                          <div className="flex justify-between">
                             <span className="text-gray-400">Status</span>
                             <span className={`px-2 py-0.5 rounded text-xs font-bold uppercase ${statusColor}`}>
                               {selectedRedemption.status === 'PENDING' ? 'Disponível' : selectedRedemption.status === 'USED' ? 'Utilizado' : 'Expirado'}
                             </span>
                          </div>

                          {isUsed ? (
                             <>
                               <div className="flex justify-between">
                                  <span className="text-gray-400">Validado por</span>
                                  <span className="font-medium text-gray-200">{selectedRedemption.validatedBy || 'Loja'}</span>
                               </div>
                               <div className="flex justify-between">
                                  <span className="text-gray-400">Data de Uso</span>
                                  <span className="font-medium text-gray-200">
                                    {selectedRedemption.validatedAt ? new Date(selectedRedemption.validatedAt).toLocaleString('pt-BR') : '-'}
                                  </span>
                               </div>
                             </>
                          ) : (
                             <>
                               <div className="flex justify-between">
                                  <span className="text-gray-400">Resgatado em</span>
                                  <span className="font-medium text-gray-200">{new Date(selectedRedemption.redeemedAt).toLocaleDateString('pt-BR')}</span>
                               </div>
                               <div className="flex justify-between">
                                  <span className="text-gray-400">Válido até</span>
                                  <span className="font-medium text-red-400">{new Date(coupon.expiryDate).toLocaleDateString('pt-BR')}</span>
                               </div>
                             </>
                          )}
                       </div>

                       <div className="mt-8">
                         <Button fullWidth variant="secondary" onClick={() => setSelectedRedemption(null)}>Fechar</Button>
                       </div>
                    </div>
                 </div>
               );
            })()}
         </Modal>
      )}
    </div>
  );
};

import React from 'react';
import { Coupon, Store } from '../types';
import { Button } from './Button';

interface CouponCardProps {
  coupon: Coupon;
  store: Store;
  onClick: () => void;
  isRedeemed?: boolean;
}

export const CouponCard: React.FC<CouponCardProps> = ({ coupon, store, onClick, isRedeemed = false }) => {
  // Determine gradient based on category, kept subtle for dark theme
  const getGradient = (cat: string) => {
    switch(cat) {
      case 'Alimentação': return 'from-orange-500/30 to-red-500/30';
      case 'Moda': return 'from-purple-500/30 to-pink-500/30';
      case 'Esportes': return 'from-blue-500/30 to-cyan-500/30';
      default: return 'from-gray-700 to-gray-600';
    }
  };

  return (
    <div 
      className={`group bg-gray-800 rounded-2xl overflow-hidden border shadow-lg transition-all duration-300 flex flex-col h-full cursor-pointer relative ${
        isRedeemed 
          ? 'border-green-900/30 opacity-90' 
          : 'border-gray-700 hover:shadow-primary-500/20 hover:border-primary-500/50'
      }`}
      onClick={onClick}
    >
      {/* Discount Badge */}
      <div className="absolute top-3 right-3 z-10">
        <div className={`backdrop-blur-md px-3 py-1 rounded-full shadow-sm border ${isRedeemed ? 'bg-green-900/80 border-green-500/30' : 'bg-gray-900/90 border-gray-700'}`}>
          <span className={`font-bold text-sm ${isRedeemed ? 'text-green-400' : 'text-primary-400'}`}>
            {coupon.discountType === 'PERCENTAGE' 
              ? `${coupon.discountValue}% OFF` 
              : `R$ ${coupon.discountValue} OFF`}
          </span>
        </div>
      </div>

      {/* Redeemed Badge Overlay */}
      {isRedeemed && (
        <div className="absolute top-3 left-3 z-10">
          <div className="bg-green-500 text-gray-900 px-3 py-1 rounded-full shadow-lg border border-green-400 flex items-center gap-1">
             <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
             <span className="font-bold text-xs uppercase tracking-wider">Resgatado</span>
          </div>
        </div>
      )}

      {/* Image Section */}
      <div className="relative h-40 overflow-hidden bg-gray-900">
        <div className={`absolute inset-0 bg-gradient-to-br ${getGradient(store.category)} opacity-40 z-0`} />
        <img 
          src={store.coverUrl} 
          alt={store.name} 
          className={`w-full h-full object-cover transform transition-transform duration-500 opacity-80 ${isRedeemed ? 'grayscale-[0.5]' : 'group-hover:scale-105 group-hover:opacity-100'}`}
        />
        {/* Logo overlay */}
        <div className="absolute -bottom-6 left-4 bg-gray-800 p-1 rounded-xl shadow-md border border-gray-700 w-16 h-16 flex items-center justify-center z-10">
           <div className="w-full h-full rounded-lg overflow-hidden bg-white flex items-center justify-center">
             {store.logoUrl.includes('http') ? (
                <img src={store.logoUrl} alt="logo" className="w-full h-full object-contain" />
             ) : (
                <span className="text-xs font-bold text-gray-900">{store.name.substring(0,2)}</span>
             )}
           </div>
        </div>
      </div>

      {/* Content Section */}
      <div className="p-4 pt-8 flex-1 flex flex-col">
        <div className="flex justify-between items-start mb-1">
          <span className="text-xs font-bold text-gray-500 uppercase tracking-wider">
            {store.category} • {store.floor}
          </span>
        </div>

        <h3 className={`text-lg font-bold leading-tight mb-2 line-clamp-2 transition-colors ${isRedeemed ? 'text-gray-400' : 'text-gray-100 group-hover:text-primary-400'}`}>
          {coupon.title}
        </h3>

        <p className="text-gray-400 text-sm mb-4 line-clamp-2 flex-1 font-medium">
          {coupon.description}
        </p>

        <div className="flex items-center justify-between mt-auto pt-4 border-t border-gray-700">
          <div className="text-xs text-gray-500">
            Válido até <br/>
            <span className="text-gray-300 font-semibold">
              {new Date(coupon.expiryDate).toLocaleDateString('pt-BR')}
            </span>
          </div>

          {isRedeemed ? (
            <div className="py-2 px-4 rounded-lg bg-green-500/10 border border-green-500/20 text-green-500 text-xs font-bold flex items-center gap-1">
               <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
               Resgatado
            </div>
          ) : (
            <Button 
              variant="outline" 
              className="!py-2 !px-4 !text-xs !rounded-lg"
              onClick={(e) => {
                e.stopPropagation();
                onClick();
              }}
            >
              Ver Cupom
            </Button>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Coupon, Store, User, Redemption } from '../types';
import { CouponCard } from './CouponCard';
import { Button } from './Button';
import { Modal } from './Modal';
import { CATEGORIES } from '../constants';

const SearchIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>;
const FilterIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" /></svg>;
const TicketIcon = () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 5v2m0 4v2m0 4v2M5 5a2 2 0 00-2 2v3a2 2 0 110 4v3a2 2 0 002 2h14a2 2 0 002-2v-3a2 2 0 110-4V7a2 2 0 00-2-2H5z" /></svg>;
const CopyIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" /></svg>;
const CheckIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>;
const BellIcon = () => (
  <svg className="w-6 h-6 text-gray-400 group-hover:text-primary-400 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
  </svg>
);
const BackIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
  </svg>
);
const Spinner = () => (
  <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-gray-900" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
  </svg>
);

// Skeleton Component for Loading State
const CouponSkeleton = () => (
  <div className="bg-gray-800 rounded-2xl overflow-hidden border border-gray-700 shadow-sm h-full flex flex-col">
    <div className="h-40 bg-gray-700 animate-pulse relative overflow-hidden">
        <div className="absolute inset-0 -translate-x-full animate-[shimmer_1.5s_infinite] bg-gradient-to-r from-transparent via-gray-600/20 to-transparent"></div>
    </div>
    <div className="p-4 flex-1 flex flex-col">
      <div className="flex justify-between mb-3">
         <div className="h-3 w-24 bg-gray-700 rounded animate-pulse"></div>
      </div>
      <div className="h-6 w-3/4 bg-gray-700 rounded mb-2 animate-pulse"></div>
      <div className="h-4 w-full bg-gray-700 rounded mb-4 animate-pulse"></div>
      <div className="mt-auto pt-4 border-t border-gray-700 flex justify-between items-center">
         <div className="h-8 w-20 bg-gray-700 rounded animate-pulse"></div>
         <div className="h-8 w-24 bg-gray-700 rounded animate-pulse"></div>
      </div>
    </div>
  </div>
);

interface EmployeeDashboardProps {
  user: User;
  stores: Store[];
  coupons: Coupon[];
  redemptions: Redemption[];
  onRedeem: (couponId: string) => Promise<string>;
}

export const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({ 
  user, stores, coupons, redemptions, onRedeem 
}) => {
  const [currentView, setCurrentView] = useState<'home' | 'my-coupons'>('home');
  const [selectedCategory, setSelectedCategory] = useState('Todos');
  const [searchQuery, setSearchQuery] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [sortBy, setSortBy] = useState<'newest' | 'expiring' | 'discount'>('newest');

  // Loading State for Skeletons
  const [isLoadingFeed, setIsLoadingFeed] = useState(true);

  // Notification State
  const [showNotifications, setShowNotifications] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);

  // Modal State
  const [selectedCoupon, setSelectedCoupon] = useState<{coupon: Coupon, store: Store} | null>(null);
  const [selectedRedemption, setSelectedRedemption] = useState<Redemption | null>(null);
  const [isRedeeming, setIsRedeeming] = useState(false);
  const [redemptionCode, setRedemptionCode] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  // Simulate initial loading
  useEffect(() => {
    const timer = setTimeout(() => setIsLoadingFeed(false), 1500);
    return () => clearTimeout(timer);
  }, []);

  // Close notifications when clicking outside
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Notifications Logic
  const notifications = useMemo(() => {
    const today = new Date();
    const alerts: Array<{id: string, title: string, message: string, daysLeft: number}> = [];

    redemptions.forEach(r => {
      if (r.status !== 'PENDING') return;
      const coupon = coupons.find(c => c.id === r.couponId);
      if (!coupon) return;

      const expiry = new Date(coupon.expiryDate);
      const diffTime = expiry.getTime() - today.getTime();
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (diffDays <= 7 && diffDays >= 0) {
        alerts.push({
          id: r.id,
          title: 'Cupom Expirando',
          message: `"${coupon.title}" expira em ${diffDays === 0 ? 'menos de 24h' : diffDays + ' dias'}.`,
          daysLeft: diffDays
        });
      }
    });

    return alerts.sort((a, b) => a.daysLeft - b.daysLeft);
  }, [redemptions, coupons]);

  // Filter Logic
  const filteredCoupons = useMemo(() => {
    let result = coupons.filter(coupon => {
      const store = stores.find(s => s.id === coupon.storeId);
      if (!store) return false;

      const matchesCategory = selectedCategory === 'Todos' || coupon.category === selectedCategory;
      const matchesSearch = 
        coupon.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        store.name.toLowerCase().includes(searchQuery.toLowerCase());

      return matchesCategory && matchesSearch;
    });

    result = result.sort((a, b) => {
      if (sortBy === 'expiring') return new Date(a.expiryDate).getTime() - new Date(b.expiryDate).getTime();
      if (sortBy === 'discount') return b.discountValue - a.discountValue;
      return 0; 
    });

    return result;
  }, [coupons, stores, selectedCategory, searchQuery, sortBy]);

  const handleOpenCoupon = (coupon: Coupon) => {
    const store = stores.find(s => s.id === coupon.storeId);
    if (store) {
      setSelectedCoupon({ coupon, store });
      setIsRedeeming(false);
      setRedemptionCode(null);
    }
  };

  const executeRedeem = async () => {
    if (!selectedCoupon) return;
    setIsRedeeming(true);
    try {
      const code = await onRedeem(selectedCoupon.coupon.id);
      setRedemptionCode(code);

      // Trigger Confetti
      if ((window as any).confetti) {
        (window as any).confetti({
          particleCount: 150,
          spread: 70,
          origin: { y: 0.6 },
          colors: ['#D4AF37', '#10b981', '#ffffff'] // Gold, Green, White
        });
      }
    } catch (e) {
      alert("Erro ao resgatar");
    } finally {
      setIsRedeeming(false);
    }
  };

  const handleCopyCode = (code: string) => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 pt-8 pb-20">
      {/* Header with Navigation and Notifications */}
      <div className="flex justify-between items-start mb-8 animate-fade-in-up">
        <div className="flex items-center gap-3">
          {currentView !== 'home' && (
             <button 
               onClick={() => setCurrentView('home')} 
               className="p-2 rounded-full bg-gray-800 text-gray-400 hover:text-primary-400 shadow-sm border border-gray-700 hover:border-primary-500/50 transition-colors"
               title="Voltar ao início"
             >
                <BackIcon />
             </button>
          )}
          <div>
            <h1 className="text-3xl font-extrabold text-white leading-tight">
              {currentView === 'home' ? `Olá, ${user.name.split(' ')[0]}!` : 'Minha Carteira'}
            </h1>
            <p className="text-gray-400 mt-1">
              {currentView === 'home' ? 'Explore os descontos disponíveis no shopping hoje.' : 'Seus cupons ativos e histórico.'}
            </p>
          </div>
        </div>

        {/* Notification Bell */}
        <div className="relative" ref={notificationRef}>
          <button 
            onClick={() => setShowNotifications(!showNotifications)} 
            className={`p-3 rounded-xl border shadow-sm transition-all duration-200 relative group ${showNotifications ? 'bg-primary-500/10 border-primary-500/50 text-primary-400' : 'bg-gray-800 border-gray-700 hover:bg-gray-700 text-gray-400'}`}
          >
            <BellIcon />
            {notifications.length > 0 && (
               <span className="absolute top-2.5 right-3 flex h-2.5 w-2.5">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2.5 w-2.5 bg-red-500 border-2 border-gray-900"></span>
               </span>
            )}
          </button>

          {showNotifications && (
            <div className="absolute right-0 top-full mt-2 w-80 bg-gray-800 rounded-2xl shadow-xl border border-gray-700 p-0 z-50 animate-pop-in overflow-hidden ring-1 ring-black/5">
               <div className="p-4 border-b border-gray-700 bg-gray-900/50">
                 <h3 className="font-bold text-gray-100 text-sm">Notificações</h3>
               </div>
               {notifications.length === 0 ? (
                 <div className="p-8 text-center">
                    <p className="text-sm text-gray-500">Tudo limpo por aqui! ✨</p>
                 </div>
               ) : (
                 <div className="max-h-80 overflow-y-auto">
                    {notifications.map((notif) => (
                      <div 
                        key={notif.id} 
                        className="flex gap-3 items-start p-4 hover:bg-gray-700/50 transition-colors border-b border-gray-700 last:border-0 cursor-pointer"
                        onClick={() => {
                           const r = redemptions.find(x => x.id === notif.id);
                           if (r) setSelectedRedemption(r);
                           setShowNotifications(false);
                        }}
                      >
                        <div className={`w-2 h-2 mt-1.5 rounded-full shrink-0 ${notif.daysLeft <= 1 ? 'bg-red-500' : 'bg-orange-400'}`} />
                        <div>
                           <p className="text-sm font-bold text-gray-200">{notif.title}</p>
                           <p className="text-xs text-gray-400 mt-0.5 leading-relaxed">{notif.message}</p>
                        </div>
                      </div>
                    ))}
                 </div>
               )}
            </div>
          )}
        </div>
      </div>

      {currentView === 'home' && (
         <div className="flex justify-center mb-8">
            <button 
              onClick={() => setCurrentView('my-coupons')}
              className="bg-gradient-to-r from-primary-600 to-primary-800 text-white shadow-lg shadow-primary-900/50 px-8 py-3 rounded-xl font-bold text-sm flex items-center gap-2 hover:shadow-xl hover:scale-[1.02] hover:from-primary-500 hover:to-primary-700 transition-all border border-primary-500/20"
            >
              <TicketIcon />
              Ver Meus Resgates
            </button>
         </div>
      )}

      {currentView === 'home' ? (
        <>
          {/* Filters */}
          <div className="mb-8 sticky top-20 z-20 md:static animate-fade-in-up" style={{ animationDelay: '100ms' }}>
              <div className="flex flex-col md:flex-row gap-3">
                <div className="relative flex-1 group">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-500 group-focus-within:text-primary-400 transition-colors">
                    <SearchIcon />
                  </div>
                  <input
                    type="text"
                    placeholder="Busque por loja..."
                    className="block w-full pl-10 pr-3 py-3 border border-gray-700 rounded-xl leading-5 bg-gray-800 text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500 transition-all shadow-sm"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                </div>
                <button 
                  onClick={() => setShowFilters(!showFilters)}
                  className={`flex items-center gap-2 px-5 py-3 rounded-xl border transition-all ${showFilters ? 'bg-gray-700 border-primary-500 text-primary-400' : 'bg-gray-800 border-gray-700 text-gray-400 hover:bg-gray-700'}`}
                >
                  <FilterIcon />
                  <span className="font-medium text-sm">Filtros</span>
                </button>
              </div>

              {showFilters && (
                <div className="mt-4 bg-gray-800 p-5 rounded-2xl border border-gray-700 shadow-lg animate-pop-in space-y-4">
                   <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      <div>
                        <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Ordenar Por</label>
                        <div className="flex flex-wrap gap-2">
                           {[
                             { id: 'newest', label: 'Mais Recentes' },
                             { id: 'expiring', label: 'Vai Expirar' },
                             { id: 'discount', label: 'Maior Desconto' }
                           ].map((opt) => (
                             <button 
                               key={opt.id}
                               onClick={() => setSortBy(opt.id as any)} 
                               className={`px-3 py-2 text-xs font-semibold rounded-lg border transition-colors ${sortBy === opt.id ? 'bg-primary-600 text-gray-900 border-primary-600' : 'bg-gray-700 text-gray-300 border-gray-600 hover:border-gray-500'}`}
                             >
                               {opt.label}
                             </button>
                           ))}
                        </div>
                      </div>
                      <div>
                        <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Categoria</label>
                        <div className="relative">
                          <select 
                            value={selectedCategory}
                            onChange={(e) => setSelectedCategory(e.target.value)}
                            className="block w-full pl-3 pr-10 py-2 text-sm border border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500 bg-gray-700 text-white"
                          >
                            {CATEGORIES.map(cat => (
                              <option key={cat} value={cat}>{cat}</option>
                            ))}
                          </select>
                        </div>
                      </div>
                   </div>
                </div>
              )}
          </div>

          {/* Grid */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 animate-fade-in-up" style={{ animationDelay: '200ms' }}>
            {isLoadingFeed 
              ? Array.from({ length: 6 }).map((_, i) => <CouponSkeleton key={i} />)
              : filteredCoupons.map((coupon, idx) => {
                  const store = stores.find(s => s.id === coupon.storeId);
                  if (!store) return null;

                  // Calculate redemption status for card display
                  const userRedemptionsCount = redemptions.filter(r => r.couponId === coupon.id).length;
                  const isRedeemed = userRedemptionsCount >= coupon.maxUsesPerUser;

                  return (
                    <div key={coupon.id} style={{ animationDelay: `${(idx * 50)}ms` }} className="animate-fade-in-up">
                      <CouponCard 
                        coupon={coupon} 
                        store={store} 
                        onClick={() => handleOpenCoupon(coupon)} 
                        isRedeemed={isRedeemed}
                      />
                    </div>
                  );
                })
            }
          </div>
        </>
      ) : (
        /* My Redemptions */
        <div className="max-w-2xl mx-auto animate-fade-in-up">
           <div className="space-y-4">
             {redemptions.length === 0 ? (
               <div className="text-center py-12 text-gray-500 border-2 border-dashed border-gray-700 rounded-2xl bg-gray-800/50">
                 <p>Nenhum cupom resgatado ainda.</p>
                 <Button onClick={() => setCurrentView('home')} className="mt-4" variant="outline">Explorar Cupons</Button>
               </div>
             ) : (
               redemptions.map(r => {
                  const coupon = coupons.find(c => c.id === r.couponId);
                  const store = stores.find(s => s.id === coupon?.storeId);
                  if(!coupon || !store) return null;

                  // Calculate days left
                  const expiry = new Date(coupon.expiryDate);
                  const daysLeft = Math.ceil((expiry.getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24));
                  const isExpiring = r.status === 'PENDING' && daysLeft <= 7 && daysLeft >= 0;

                  return (
                    <div key={r.id} onClick={() => setSelectedRedemption(r)} className="bg-gray-800 p-4 rounded-2xl border border-gray-700 shadow-sm flex items-center gap-4 cursor-pointer hover:shadow-md hover:border-primary-500/50 transition-all group relative overflow-hidden">
                      {isExpiring && <div className="absolute top-0 left-0 w-1 h-full bg-orange-500"></div>}
                      <img src={store.logoUrl} className="w-12 h-12 object-contain rounded-lg border border-gray-600 bg-white p-1" alt={store.name} />
                      <div className="flex-1">
                        <h4 className="font-bold text-gray-100 group-hover:text-primary-400 transition-colors">{coupon.title}</h4>
                        <div className="flex items-center gap-2 mt-1">
                          <span className="text-xs text-gray-500 font-medium">{store.name}</span>
                          {isExpiring && <span className="text-[10px] bg-orange-900/30 text-orange-400 px-2 py-0.5 rounded-full font-bold border border-orange-500/20">Expira em {daysLeft} dias</span>}
                        </div>
                      </div>
                      <span className={`px-3 py-1 rounded-full text-xs font-bold border ${
                        r.status === 'PENDING' ? 'bg-green-900/20 text-green-400 border-green-500/30' : 
                        r.status === 'USED' ? 'bg-gray-700 text-gray-400 border-gray-600' :
                        'bg-red-900/20 text-red-400 border-red-500/30'
                      }`}>
                        {r.status === 'PENDING' ? 'Ativo' : r.status === 'USED' ? 'Usado' : 'Expirado'}
                      </span>
                    </div>
                  );
               })
             )}
           </div>
        </div>
      )}

      {/* Coupon Details Modal (Pre-Redemption) */}
      {selectedCoupon && (
        <Modal isOpen={!!selectedCoupon} onClose={() => setSelectedCoupon(null)}>
           <div className="h-48 relative">
              <img src={selectedCoupon.store.coverUrl} className="w-full h-full object-cover" alt="Cover" />
              <div className="absolute inset-0 bg-gradient-to-t from-gray-900 via-gray-900/60 to-transparent" />
              <div className="absolute bottom-4 left-6 flex items-center gap-3 text-white">
                 <div className="bg-white p-1 rounded-lg shadow-lg">
                   <img src={selectedCoupon.store.logoUrl} className="w-10 h-10 object-contain" alt="logo"/>
                 </div>
                 <div>
                   <p className="font-bold text-lg leading-none text-white">{selectedCoupon.store.name}</p>
                   <p className="text-xs opacity-80 mt-1 text-gray-300">{selectedCoupon.store.category}</p>
                 </div>
              </div>
           </div>
           <div className="p-6 bg-gray-900">
              {!redemptionCode ? (
                <>
                  <h2 className="text-2xl font-bold text-white mb-2">{selectedCoupon.coupon.title}</h2>
                  <p className="text-gray-400 mb-6 leading-relaxed">{selectedCoupon.coupon.description}</p>

                  <div className="bg-gray-800 rounded-xl p-4 mb-6 border border-gray-700">
                    <h4 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Regras</h4>
                    <ul className="text-sm text-gray-300 space-y-2">
                      <li className="flex items-start gap-2">
                           <span className="text-primary-500 mt-1.5 w-1.5 h-1.5 rounded-full bg-primary-500 shrink-0"></span>
                           <span>Limite de uso: <strong>{selectedCoupon.coupon.maxUsesPerUser} por pessoa</strong>.</span>
                      </li>
                      {selectedCoupon.coupon.rules.map((rule, i) => (
                        <li key={i} className="flex items-start gap-2">
                           <span className="text-primary-500 mt-1.5 w-1.5 h-1.5 rounded-full bg-primary-500 shrink-0"></span>
                           <span>{rule}</span>
                        </li>
                      ))}
                    </ul>
                  </div>

                  {(() => {
                    const userRedemptionsCount = redemptions.filter(r => r.couponId === selectedCoupon.coupon.id).length;
                    const isLimitReached = userRedemptionsCount >= selectedCoupon.coupon.maxUsesPerUser;

                    return (
                       <Button fullWidth onClick={executeRedeem} disabled={isRedeeming || isLimitReached}>
                        {isRedeeming ? <><Spinner /> Gerando Cupom...</> : isLimitReached ? 'Limite de Uso Atingido' : 'Resgatar Cupom'}
                      </Button>
                    );
                  })()}
                </>
              ) : (
                <div className="text-center py-6 animate-pop-in">
                   {/* Success State - Green as requested for dopamine hit */}
                   <div className="w-20 h-20 bg-green-500/10 text-green-500 rounded-full flex items-center justify-center mx-auto mb-6 ring-4 ring-green-500/20">
                      <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                   </div>
                   <h3 className="text-2xl font-bold text-white mb-2">Sucesso!</h3>
                   <p className="text-gray-400 mb-6">Apresente este código na loja para validar.</p>

                   <div className="bg-gray-800 text-primary-400 text-3xl font-mono p-5 rounded-xl mb-6 tracking-widest border-2 border-dashed border-gray-600 shadow-inner">
                     {redemptionCode}
                   </div>

                   <Button variant="secondary" fullWidth onClick={() => setSelectedCoupon(null)}>Fechar e Usar Depois</Button>
                </div>
              )}
           </div>
        </Modal>
      )}

      {/* Redemption Status Modal (Post-Redemption / Wallet) */}
      {selectedRedemption && (
         <Modal isOpen={!!selectedRedemption} onClose={() => setSelectedRedemption(null)}>
            {(() => {
               const coupon = coupons.find(c => c.id === selectedRedemption.couponId);
               const store = stores.find(s => s.id === coupon?.storeId);
               if (!coupon || !store) return null;

               const isUsed = selectedRedemption.status === 'USED';
               const isExpired = selectedRedemption.status === 'EXPIRED';
               const statusColor = isUsed ? 'text-gray-500 bg-gray-800' : isExpired ? 'text-red-400 bg-red-900/20' : 'text-green-400 bg-green-900/20';

               return (
                 <div className="p-0 bg-gray-900">
                    <div className="bg-gradient-to-br from-primary-600 to-primary-800 p-6 text-gray-900 text-center relative overflow-hidden">
                       <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>
                       <h2 className="text-xl font-bold relative z-10">{store.name}</h2>
                       <p className="text-primary-900/80 text-sm relative z-10 font-medium">{coupon.title}</p>
                    </div>

                    <div className="p-6">
                       {/* QR Code Section */}
                       <div className="flex justify-center mb-6">
                         <div className="p-3 bg-white border border-gray-700 rounded-xl shadow-lg">
                            {isUsed || isExpired ? (
                               <div className="w-40 h-40 flex items-center justify-center bg-gray-100 rounded-lg">
                                  <span className="text-gray-400 font-bold opacity-50 text-xl rotate-45 border-4 border-gray-300 p-2 rounded-lg">
                                    {isUsed ? 'UTILIZADO' : 'EXPIRADO'}
                                  </span>
                               </div>
                            ) : (
                               <img 
                                 src={`https://api.qrserver.com/v1/create-qr-code/?size=160x160&data=${selectedRedemption.code}`} 
                                 alt="QR Code" 
                                 className="w-40 h-40" 
                               />
                            )}
                         </div>
                       </div>

                       {/* Code & Copy */}
                       <div className="flex items-center gap-2 mb-6">
                          <div className="flex-1 bg-gray-800 border border-gray-700 rounded-lg py-3 px-4 text-center">
                             <span className="font-mono text-xl font-bold text-gray-100 tracking-widest">{selectedRedemption.code}</span>
                          </div>
                          <button 
                            onClick={() => handleCopyCode(selectedRedemption.code)}
                            className="bg-gray-800 text-primary-400 p-3.5 rounded-lg hover:bg-gray-700 transition-colors border border-gray-700 hover:border-primary-500/50"
                            title="Copiar código"
                          >
                            {copied ? <CheckIcon /> : <CopyIcon />}
                          </button>
                       </div>

                       {/* Details List */}
                       <div className="space-y-3 text-sm border-t border-gray-700 pt-4">
                          <div className="flex justify-between">
                             <span className="text-gray-400">Status</span>
                             <span className={`px-2 py-0.5 rounded text-xs font-bold uppercase ${statusColor}`}>
                               {selectedRedemption.status === 'PENDING' ? 'Disponível' : selectedRedemption.status === 'USED' ? 'Utilizado' : 'Expirado'}
                             </span>
                          </div>

                          {isUsed ? (
                             <>
                               <div className="flex justify-between">
                                  <span className="text-gray-400">Validado por</span>
                                  <span className="font-medium text-gray-200">{selectedRedemption.validatedBy || 'Loja'}</span>
                               </div>
                               <div className="flex justify-between">
                                  <span className="text-gray-400">Data de Uso</span>
                                  <span className="font-medium text-gray-200">
                                    {selectedRedemption.validatedAt ? new Date(selectedRedemption.validatedAt).toLocaleString('pt-BR') : '-'}
                                  </span>
                               </div>
                             </>
                          ) : (
                             <>
                               <div className="flex justify-between">
                                  <span className="text-gray-400">Resgatado em</span>
                                  <span className="font-medium text-gray-200">{new Date(selectedRedemption.redeemedAt).toLocaleDateString('pt-BR')}</span>
                               </div>
                               <div className="flex justify-between">
                                  <span className="text-gray-400">Válido até</span>
                                  <span className="font-medium text-red-400">{new Date(coupon.expiryDate).toLocaleDateString('pt-BR')}</span>
                               </div>
                             </>
                          )}
                       </div>

                       <div className="mt-8">
                         <Button fullWidth variant="secondary" onClick={() => setSelectedRedemption(null)}>Fechar</Button>
                       </div>
                    </div>
                 </div>
               );
            })()}
         </Modal>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, Store, Coupon, Redemption } from '../types';
import { Button } from './Button';
import { Modal } from './Modal';
import { Html5QrcodeScanner } from 'html5-qrcode';

interface ManagerDashboardProps {
  user: User;
  store: Store;
  coupons: Coupon[];
  redemptions: Redemption[]; // Global redemptions
  onCreateCoupon: (coupon: Omit<Coupon, 'id'>) => void;
  onValidateRedemption: (code: string) => boolean;
}

const BackIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
  </svg>
);

const ChartIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>;
const ListIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 10h16M4 14h16M4 18h16" /></svg>;
const QrCodeIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" /></svg>;
const UserGroupIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>;

const Spinner = () => (
  <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-gray-900" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
  </svg>
);

export const ManagerDashboard: React.FC<ManagerDashboardProps> = ({
  user, store, coupons, redemptions, onCreateCoupon, onValidateRedemption
}) => {
  const [view, setView] = useState<'overview' | 'manage' | 'validate'>('overview');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Validation State
  const [validationCode, setValidationCode] = useState('');
  const [validationResult, setValidationResult] = useState<'idle' | 'success' | 'error'>('idle');
  const [validationMessage, setValidationMessage] = useState('');
  const [isValidating, setIsValidating] = useState(false);

  // Scanner State
  const [isScannerOpen, setIsScannerOpen] = useState(false);

  // Form State
  const [newCoupon, setNewCoupon] = useState({
    title: '', description: '', discountValue: 0, quantity: 100, maxUsesPerUser: 1
  });

  // Derived Data
  const myCoupons = useMemo(() => coupons.filter(c => c.storeId === store.id), [coupons, store.id]);
  const myRedemptions = useMemo(() => redemptions.filter(r => myCoupons.find(c => c.id === r.couponId)), [redemptions, myCoupons]);

  // Stats
  const totalRedemptions = myRedemptions.length;
  const validatedRedemptions = myRedemptions.filter(r => r.status === 'USED').length;
  const activeCoupons = myCoupons.length;
  const uniqueUsersServed = new Set(myRedemptions.map(r => r.userId)).size;

  // Scanner Logic
  useEffect(() => {
    let scanner: any = null;
    let timer: any = null;

    if (isScannerOpen) {
      // Small delay to ensure the modal DOM is rendered
      timer = setTimeout(() => {
        try {
          scanner = new Html5QrcodeScanner(
            "reader",
            { 
              fps: 10, 
              qrbox: { width: 250, height: 250 },
              aspectRatio: 1.0,
              showTorchButtonIfSupported: true 
            },
            false
          );

          scanner.render(
            (decodedText: string) => {
              setValidationCode(decodedText);
              setIsScannerOpen(false); 
            },
            (error: any) => {
              // Ignore errors
            }
          );
        } catch (err) {
          console.error("Error initializing scanner:", err);
        }
      }, 100);
    }

    return () => {
      if (timer) clearTimeout(timer);
      if (scanner) {
        scanner.clear().catch((error: any) => {
          console.error("Failed to clear scanner", error);
        });
      }
    };
  }, [isScannerOpen]);

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onCreateCoupon({
      storeId: store.id,
      title: newCoupon.title,
      description: newCoupon.description,
      discountType: 'PERCENTAGE', 
      discountValue: newCoupon.discountValue,
      expiryDate: new Date(Date.now() + 86400000 * 30).toISOString(), 
      category: store.category,
      availableQuantity: newCoupon.quantity,
      maxUsesPerUser: newCoupon.maxUsesPerUser,
      rules: ['Regra padrão']
    });
    setIsModalOpen(false);
  };

  const handleValidate = (e: React.FormEvent) => {
    e.preventDefault();
    setIsValidating(true);
    // Simulate network delay
    setTimeout(() => {
      const success = onValidateRedemption(validationCode);
      if (success) {
        setValidationResult('success');
        setValidationMessage('Cupom validado com sucesso!');
      } else {
        setValidationResult('error');
        setValidationMessage('Código inválido ou já utilizado.');
      }
      setIsValidating(false);
    }, 800);
  };

  const inputClasses = "w-full border border-gray-600 bg-gray-700 text-white p-3 rounded-xl focus:ring-2 focus:ring-primary-500 focus:outline-none transition-all placeholder-gray-400";

  return (
    <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 pt-8 pb-20">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 bg-gray-800 p-6 rounded-3xl border border-gray-700 shadow-lg">
         <div className="flex items-center gap-4 mb-4 md:mb-0 w-full md:w-auto">
            <img src={store.logoUrl} className="w-16 h-16 rounded-xl border border-gray-600 p-1 object-contain bg-white" alt="logo" />
            <div>
              <h1 className="text-2xl font-bold text-white leading-none">{store.name}</h1>
              <p className="text-gray-400 text-sm mt-1">Painel do Gerente • {user.name}</p>
            </div>
         </div>
         {/* Navigation Tabs */}
         <div className="flex bg-gray-900 rounded-xl p-1 border border-gray-700">
             {[
               { id: 'overview', label: 'Visão Geral', icon: <ChartIcon /> },
               { id: 'manage', label: 'Gerenciar Cupons', icon: <ListIcon /> },
               { id: 'validate', label: 'Validar', icon: <QrCodeIcon /> }
             ].map(tab => (
               <button
                 key={tab.id}
                 onClick={() => setView(tab.id as any)}
                 className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold transition-all ${view === tab.id ? 'bg-primary-500 text-gray-900 shadow-lg' : 'text-gray-400 hover:text-white hover:bg-gray-800'}`}
               >
                 {tab.icon}
                 <span className="hidden sm:inline">{tab.label}</span>
               </button>
             ))}
         </div>
      </div>

      {view === 'overview' && (
        <div className="animate-fade-in-up space-y-8">
           {/* Top Stats */}
           <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <div className="bg-gray-800 p-5 rounded-2xl border border-gray-700 shadow-sm">
                 <p className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-1">Cupons Ativos</p>
                 <p className="text-3xl font-extrabold text-white">{activeCoupons}</p>
              </div>
              <div className="bg-gray-800 p-5 rounded-2xl border border-gray-700 shadow-sm">
                 <p className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-1">Total Gerados</p>
                 <p className="text-3xl font-extrabold text-primary-400">{totalRedemptions}</p>
              </div>
              <div className="bg-gray-800 p-5 rounded-2xl border border-gray-700 shadow-sm">
                 <p className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-1">Validados (Usados)</p>
                 <p className="text-3xl font-extrabold text-accent-500">{validatedRedemptions}</p>
              </div>
              <div className="bg-gray-800 p-5 rounded-2xl border border-gray-700 shadow-sm">
                 <p className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-1">Funcionários Únicos</p>
                 <div className="flex items-center gap-2">
                    <UserGroupIcon />
                    <p className="text-3xl font-extrabold text-white">{uniqueUsersServed}</p>
                 </div>
              </div>
           </div>

           <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              {/* Performance Card */}
              <div className="bg-gray-800 p-6 rounded-2xl border border-gray-700 shadow-lg">
                 <h3 className="text-lg font-bold text-white mb-4">Performance dos Cupons</h3>
                 <div className="space-y-4">
                    {myCoupons.slice(0, 5).map(coupon => {
                       const usage = redemptions.filter(r => r.couponId === coupon.id).length;
                       const percentage = Math.min(100, Math.round((usage / coupon.availableQuantity) * 100));
                       return (
                         <div key={coupon.id}>
                            <div className="flex justify-between text-sm mb-1">
                               <span className="font-medium text-gray-300">{coupon.title}</span>
                               <span className="text-gray-500">{usage} / {coupon.availableQuantity}</span>
                            </div>
                            <div className="w-full bg-gray-700 rounded-full h-2.5">
                               <div className="bg-primary-500 h-2.5 rounded-full" style={{ width: `${percentage}%` }}></div>
                            </div>
                         </div>
                       );
                    })}
                    {myCoupons.length === 0 && <p className="text-gray-500 text-sm">Nenhum cupom ativo para exibir dados.</p>}
                 </div>
              </div>

              {/* Recent Validations */}
              <div className="bg-gray-800 p-6 rounded-2xl border border-gray-700 shadow-lg">
                 <h3 className="text-lg font-bold text-white mb-4">Últimas Validações</h3>
                 <div className="space-y-3">
                    {myRedemptions.filter(r => r.status === 'USED').slice(0, 5).sort((a,b) => new Date(b.validatedAt!).getTime() - new Date(a.validatedAt!).getTime()).map(redemption => (
                       <div key={redemption.id} className="flex items-center justify-between p-3 bg-gray-900/50 rounded-xl border border-gray-700">
                          <div>
                             <p className="text-sm font-bold text-gray-200">{redemption.code}</p>
                             <p className="text-xs text-gray-500">
                                {new Date(redemption.validatedAt!).toLocaleDateString('pt-BR')} às {new Date(redemption.validatedAt!).toLocaleTimeString('pt-BR', {hour: '2-digit', minute:'2-digit'})}
                             </p>
                          </div>
                          <span className="text-xs font-medium text-green-400 bg-green-900/20 px-2 py-1 rounded">Validado</span>
                       </div>
                    ))}
                    {myRedemptions.filter(r => r.status === 'USED').length === 0 && (
                      <div className="text-center py-8 text-gray-500 text-sm border border-dashed border-gray-700 rounded-xl">
                        Nenhuma validação registrada ainda.
                      </div>
                    )}
                 </div>
              </div>
           </div>
        </div>
      )}

      {view === 'manage' && (
        <div className="animate-fade-in-up">
           <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-bold text-gray-200">Todos os Cupons</h2>
              <Button onClick={() => setIsModalOpen(true)}>+ Criar Cupom</Button>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {myCoupons.map(coupon => (
                 <div key={coupon.id} className="bg-gray-800 p-5 rounded-2xl border border-gray-700 shadow-sm hover:shadow-primary-500/10 hover:border-primary-500/30 transition-all group flex flex-col">
                    <h3 className="font-bold text-white mb-2 group-hover:text-primary-400 transition-colors line-clamp-1">{coupon.title}</h3>
                    <p className="text-sm text-gray-400 mb-4 line-clamp-2">{coupon.description}</p>

                    <div className="mt-auto pt-4 border-t border-gray-700 space-y-2">
                       <div className="flex justify-between text-sm">
                          <span className="text-gray-500">Desconto</span>
                          <span className="text-primary-400 font-bold">{coupon.discountValue}% OFF</span>
                       </div>
                       <div className="flex justify-between text-sm">
                          <span className="text-gray-500">Limite Usuário</span>
                          <span className="text-gray-300">{coupon.maxUsesPerUser}x</span>
                       </div>
                       <div className="flex justify-between text-sm">
                          <span className="text-gray-500">Total Estoque</span>
                          <span className="text-gray-300">{coupon.availableQuantity}</span>
                       </div>
                    </div>
                 </div>
              ))}
              <div 
                onClick={() => setIsModalOpen(true)}
                className="border-2 border-dashed border-gray-700 rounded-2xl flex flex-col items-center justify-center p-6 text-gray-500 cursor-pointer hover:border-primary-500 hover:bg-primary-500/10 hover:text-primary-400 transition-all min-h-[200px]"
              >
                 <span className="text-4xl mb-2 font-light">+</span>
                 <span className="font-medium text-sm">Novo Cupom</span>
              </div>
           </div>
        </div>
      )}

      {view === 'validate' && (
        <div className="max-w-md mx-auto bg-gray-800 p-8 rounded-3xl shadow-2xl border border-gray-700 animate-pop-in">
           <h2 className="text-xl font-bold text-white mb-6 text-center">Validar Cupom</h2>

           <div className="mb-6 flex justify-center">
              <button 
                type="button"
                onClick={() => setIsScannerOpen(true)}
                className="flex flex-col items-center justify-center w-full py-6 border-2 border-dashed border-primary-500/30 rounded-2xl bg-primary-500/5 hover:bg-primary-500/10 transition-colors group"
              >
                <div className="w-12 h-12 bg-gray-700 rounded-full flex items-center justify-center shadow-sm mb-2 group-hover:scale-110 transition-transform">
                   <svg className="w-6 h-6 text-primary-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" />
                   </svg>
                </div>
                <span className="text-primary-400 font-semibold">Escanear QR Code</span>
                <span className="text-xs text-gray-500 mt-1">Utilizar câmera do dispositivo</span>
              </button>
           </div>

           <div className="relative flex py-2 items-center mb-6">
              <div className="flex-grow border-t border-gray-700"></div>
              <span className="flex-shrink-0 mx-4 text-gray-500 text-xs uppercase">Ou digite o código</span>
              <div className="flex-grow border-t border-gray-700"></div>
           </div>

           <form onSubmit={handleValidate}>
             <label className="block text-sm font-medium text-gray-300 mb-2">Código do Cupom</label>
             <input 
               type="text" 
               className="block w-full px-4 py-3 text-center text-2xl tracking-widest font-mono border border-gray-600 bg-gray-900 text-white rounded-xl focus:ring-2 focus:ring-primary-500 focus:border-primary-500 uppercase mb-6"
               placeholder="CPN-XXXX"
               value={validationCode}
               onChange={(e) => {
                 setValidationCode(e.target.value.toUpperCase());
                 setValidationResult('idle');
               }}
             />
             <Button fullWidth type="submit" disabled={isValidating}>
                {isValidating ? <><Spinner /> Verificando...</> : 'Validar Agora'}
             </Button>
           </form>

           {validationResult !== 'idle' && (
             <div className={`mt-6 p-4 rounded-xl text-center ${validationResult === 'success' ? 'bg-green-900/30 text-green-400' : 'bg-red-900/30 text-red-400'} animate-fade-in`}>
               {validationResult === 'success' ? (
                 <div className="flex flex-col items-center">
                    <div className="w-8 h-8 bg-green-500/20 rounded-full flex items-center justify-center mb-2">
                       <svg className="w-5 h-5 text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                    </div>
                    <p className="font-bold">{validationMessage}</p>
                 </div>
               ) : (
                 <div className="flex flex-col items-center">
                    <div className="w-8 h-8 bg-red-500/20 rounded-full flex items-center justify-center mb-2">
                       <svg className="w-5 h-5 text-red-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                    </div>
                    <p className="font-bold">{validationMessage}</p>
                 </div>
               )}
             </div>
           )}
        </div>
      )}

      {/* Create Modal */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)}>
         <div className="p-6">
            <h2 className="text-xl font-bold mb-6 text-white">Novo Cupom</h2>
            <form onSubmit={handleCreateSubmit} className="space-y-4">
               <div>
                 <label className="block text-sm text-gray-400 mb-1">Título</label>
                 <input required className={inputClasses} value={newCoupon.title} onChange={e => setNewCoupon({...newCoupon, title: e.target.value})} />
               </div>
               <div>
                 <label className="block text-sm text-gray-400 mb-1">Descrição</label>
                 <textarea required className={inputClasses} value={newCoupon.description} onChange={e => setNewCoupon({...newCoupon, description: e.target.value})} />
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm text-gray-400 mb-1">Desconto (%)</label>
                    <input type="number" required className={inputClasses} value={newCoupon.discountValue} onChange={e => setNewCoupon({...newCoupon, discountValue: Number(e.target.value)})} />
                  </div>
                  <div>
                    <label className="block text-sm text-gray-400 mb-1">Qtd Total</label>
                    <input type="number" required className={inputClasses} value={newCoupon.quantity} onChange={e => setNewCoupon({...newCoupon, quantity: Number(e.target.value)})} />
                  </div>
               </div>
               <div>
                 <label className="block text-sm text-gray-400 mb-1">Limite por Usuário</label>
                 <input type="number" min="1" required className={inputClasses} value={newCoupon.maxUsesPerUser} onChange={e => setNewCoupon({...newCoupon, maxUsesPerUser: Number(e.target.value)})} />
                 <p className="text-xs text-gray-500 mt-1">Quantas vezes o mesmo funcionário pode resgatar este cupom.</p>
               </div>
               <Button fullWidth type="submit" className="mt-4">Publicar Cupom</Button>
            </form>
         </div>
      </Modal>

      {/* Scanner Modal */}
      <Modal isOpen={isScannerOpen} onClose={() => setIsScannerOpen(false)}>
         <div className="p-6">
            <h2 className="text-xl font-bold text-white mb-4 text-center">Escanear Cupom</h2>
            <div className="relative bg-black rounded-2xl overflow-hidden shadow-inner border border-gray-700">
               <div id="reader" className="w-full"></div>
            </div>
            <p className="text-center text-sm text-gray-400 mt-4">Aponte a câmera para o QR Code do funcionário.</p>
            <div className="mt-4 flex justify-center">
              <Button variant="secondary" onClick={() => setIsScannerOpen(false)}>Cancelar</Button>
            </div>
         </div>
      </Modal>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Store, User, UserRole } from '../types';
import { Button } from './Button';
import { Modal } from './Modal';
import { CATEGORIES, COUPONS, MY_REDEMPTIONS } from '../constants';

interface AdminDashboardProps {
  stores: Store[];
  users: User[];
  onAddStore: (store: Omit<Store, 'id'>) => void;
  onUpdateStore: (store: Store) => void;
  onDeleteStore: (storeId: string) => void;
  onAddUser: (user: Omit<User, 'id'>) => void;
  onUpdateUser: (user: User) => void;
  onDeleteUser: (userId: string) => void;
}

// Icons
const EditIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>;
const TrashIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>;
const SearchIcon = () => <svg className="w-5 h-5 text-gray-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>;
const StoreIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>;
const UserIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>;
const ChevronDownIcon = () => <svg className="w-4 h-4 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>;

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  stores, users, onAddStore, onUpdateStore, onDeleteStore, onAddUser, onUpdateUser, onDeleteUser 
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'stores' | 'users'>('overview');
  const [searchQuery, setSearchQuery] = useState('');

  // Store Modal State
  const [isStoreModalOpen, setIsStoreModalOpen] = useState(false);
  const [editingStore, setEditingStore] = useState<Store | null>(null);
  const [storeFormData, setStoreFormData] = useState<Partial<Store>>({ name: '', category: 'Moda', floor: '', logoUrl: '', coverUrl: '' });

  // User Modal State
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [userFormData, setUserFormData] = useState<Partial<User>>({ name: '', email: '', role: UserRole.EMPLOYEE, storeId: '' });

  // Filtering
  const filteredStores = useMemo(() => {
    return stores.filter(s => s.name.toLowerCase().includes(searchQuery.toLowerCase()) || s.category.toLowerCase().includes(searchQuery.toLowerCase()));
  }, [stores, searchQuery]);

  const filteredUsers = useMemo(() => {
    return users.filter(u => u.name.toLowerCase().includes(searchQuery.toLowerCase()) || u.email.toLowerCase().includes(searchQuery.toLowerCase()));
  }, [users, searchQuery]);

  // Global Stats Logic
  const globalStats = useMemo(() => {
     const totalRedemptions = MY_REDEMPTIONS.length;
     const activeUsersCount = new Set(MY_REDEMPTIONS.map(r => r.userId)).size;
     const topStoreId = stores.reduce((acc, store) => {
         const count = COUPONS.filter(c => c.storeId === store.id)
                              .reduce((sum, c) => sum + MY_REDEMPTIONS.filter(r => r.couponId === c.id).length, 0);
         return count > acc.count ? { id: store.id, count } : acc;
     }, { id: '', count: 0 }).id;

     const topStore = stores.find(s => s.id === topStoreId);

     // Category Distribution
     const catDist = CATEGORIES.filter(c => c !== 'Todos').map(cat => ({
       name: cat,
       count: stores.filter(s => s.category === cat).length
     }));

     return { totalRedemptions, activeUsersCount, topStore, catDist };
  }, [stores, users]);

  // Handlers - Stores
  const handleOpenAddStore = () => {
    setEditingStore(null);
    setStoreFormData({ name: '', category: 'Moda', floor: '', logoUrl: '', coverUrl: '' });
    setIsStoreModalOpen(true);
  };

  const handleOpenEditStore = (store: Store) => {
    setEditingStore(store);
    setStoreFormData(store);
    setIsStoreModalOpen(true);
  };

  const handleSubmitStore = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingStore) {
      onUpdateStore({ ...editingStore, ...storeFormData } as Store);
    } else {
      onAddStore(storeFormData as Omit<Store, 'id'>);
    }
    setIsStoreModalOpen(false);
  };

  // Handlers - Users
  const handleOpenAddUser = () => {
    setEditingUser(null);
    setUserFormData({ name: '', email: '', role: UserRole.EMPLOYEE, storeId: stores[0]?.id || '' });
    setIsUserModalOpen(true);
  };

  const handleOpenEditUser = (user: User) => {
    setEditingUser(user);
    setUserFormData(user);
    setIsUserModalOpen(true);
  };

  const handleSubmitUser = (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
       ...userFormData,
       // If role is admin, clear storeId
       storeId: userFormData.role === UserRole.ADMIN ? undefined : userFormData.storeId
    };

    if (editingUser) {
      onUpdateUser({ ...editingUser, ...payload } as User);
    } else {
      onAddUser(payload as Omit<User, 'id'>);
    }
    setIsUserModalOpen(false);
  };

  const inputClasses = "w-full border border-gray-600 bg-gray-700 text-white p-3 rounded-xl focus:ring-2 focus:ring-primary-500 focus:outline-none transition-all placeholder-gray-400";
  const selectClasses = "w-full border border-gray-600 bg-gray-700 text-white p-3 rounded-xl focus:ring-2 focus:ring-primary-500 focus:outline-none transition-all appearance-none";

  return (
    <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 pt-8 pb-20">
       <div className="flex flex-col md:flex-row justify-between items-end md:items-center mb-8 gap-4">
         <div>
            <h1 className="text-3xl font-bold text-white">Painel do Administrador</h1>
            <p className="text-gray-400 mt-1">Gerencie a estrutura e monitore o ecossistema.</p>
         </div>
         <div className="flex bg-gray-800 rounded-xl p-1.5 border border-gray-700 shadow-sm">
            <button 
              onClick={() => setActiveTab('overview')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all ${activeTab === 'overview' ? 'bg-primary-900/30 text-primary-400 shadow-sm' : 'text-gray-400 hover:text-white hover:bg-gray-700'}`}
            >
              Visão Geral
            </button>
            <button 
              onClick={() => setActiveTab('stores')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all flex items-center gap-2 ${activeTab === 'stores' ? 'bg-primary-900/30 text-primary-400 shadow-sm' : 'text-gray-400 hover:text-white hover:bg-gray-700'}`}
            >
              <StoreIcon /> Lojas
            </button>
            <button 
              onClick={() => setActiveTab('users')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all flex items-center gap-2 ${activeTab === 'users' ? 'bg-primary-900/30 text-primary-400 shadow-sm' : 'text-gray-400 hover:text-white hover:bg-gray-700'}`}
            >
              <UserIcon /> Usuários
            </button>
         </div>
       </div>

       {/* Search Bar (Shared for Stores and Users tabs) */}
       {activeTab !== 'overview' && (
         <div className="mb-6 flex gap-4 animate-fade-in">
           <div className="relative flex-1">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
               <SearchIcon />
             </div>
             <input
               type="text"
               placeholder={activeTab === 'stores' ? "Buscar loja..." : "Buscar usuário..."}
               className="block w-full pl-10 pr-3 py-3 border border-gray-700 rounded-xl leading-5 bg-gray-800 text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500 transition-all shadow-sm"
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
             />
           </div>
           <Button onClick={activeTab === 'stores' ? handleOpenAddStore : handleOpenAddUser} className="shrink-0">
             {activeTab === 'stores' ? '+ Nova Loja' : '+ Novo Usuário'}
           </Button>
         </div>
       )}

       {activeTab === 'overview' && (
         <div className="space-y-8 animate-fade-in-up">
            {/* Quick Stats */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
              <div className="bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-700 flex flex-col justify-between hover:shadow-md transition-shadow">
                 <div className="flex justify-between items-start">
                    <p className="text-gray-400 text-xs font-bold uppercase tracking-wider">Total de Lojas</p>
                    <div className="p-2 bg-gray-700 rounded-lg text-gray-300"><StoreIcon /></div>
                 </div>
                 <p className="text-4xl font-extrabold text-white mt-4">{stores.length}</p>
              </div>
              <div className="bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-700 flex flex-col justify-between hover:shadow-md transition-shadow">
                 <div className="flex justify-between items-start">
                    <p className="text-gray-400 text-xs font-bold uppercase tracking-wider">Usuários</p>
                    <div className="p-2 bg-gray-700 rounded-lg text-gray-300"><UserIcon /></div>
                 </div>
                 <p className="text-4xl font-extrabold text-white mt-4">{users.length}</p>
              </div>
              <div className="bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-700 flex flex-col justify-between hover:shadow-md transition-shadow">
                 <div className="flex justify-between items-start">
                    <p className="text-gray-400 text-xs font-bold uppercase tracking-wider">Total Resgates</p>
                    <div className="p-2 bg-primary-900/20 text-primary-400 rounded-lg">
                       <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                    </div>
                 </div>
                 <p className="text-4xl font-extrabold text-white mt-4">{globalStats.totalRedemptions}</p>
              </div>
              <div className="bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-700 flex flex-col justify-between hover:shadow-md transition-shadow relative overflow-hidden">
                 <div className="absolute top-0 right-0 p-8 opacity-5">
                    <StoreIcon />
                 </div>
                 <div className="flex justify-between items-start relative z-10">
                    <p className="text-gray-400 text-xs font-bold uppercase tracking-wider">Loja Top Performance</p>
                    <div className="p-2 bg-accent-900/20 text-accent-400 rounded-lg">
                       <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z" /></svg>
                    </div>
                 </div>
                 <p className="text-2xl font-bold text-white mt-4 truncate">{globalStats.topStore?.name || 'N/A'}</p>
                 <p className="text-xs text-gray-400">Maior volume de resgates</p>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
               {/* Category Distribution Chart */}
               <div className="bg-gray-800 p-6 rounded-2xl border border-gray-700 shadow-lg">
                  <h3 className="text-lg font-bold text-white mb-6">Distribuição de Lojas</h3>
                  <div className="space-y-4">
                     {globalStats.catDist.map((cat) => {
                       const max = Math.max(...globalStats.catDist.map(c => c.count));
                       const percent = (cat.count / (max || 1)) * 100;
                       return (
                         <div key={cat.name}>
                            <div className="flex justify-between text-sm mb-1 text-gray-300">
                               <span>{cat.name}</span>
                               <span className="font-bold">{cat.count}</span>
                            </div>
                            <div className="w-full bg-gray-700 rounded-full h-3">
                               <div 
                                 className="bg-gradient-to-r from-primary-500 to-primary-600 h-3 rounded-full transition-all duration-500" 
                                 style={{ width: `${percent}%` }}
                               ></div>
                            </div>
                         </div>
                       )
                     })}
                  </div>
               </div>

               {/* Recent Activity Feed */}
               <div className="bg-gray-800 p-6 rounded-2xl border border-gray-700 shadow-lg">
                  <h3 className="text-lg font-bold text-white mb-6">Atividade Recente do Sistema</h3>
                  <div className="space-y-4">
                     {MY_REDEMPTIONS.slice(0, 5).sort((a,b) => new Date(b.redeemedAt).getTime() - new Date(a.redeemedAt).getTime()).map(r => {
                        const coupon = COUPONS.find(c => c.id === r.couponId);
                        const user = users.find(u => u.id === r.userId);
                        const store = stores.find(s => s.id === coupon?.storeId);
                        if (!coupon || !user || !store) return null;

                        return (
                          <div key={r.id} className="flex gap-4 items-start p-3 bg-gray-900/50 rounded-xl border border-gray-700">
                             <div className={`mt-1 w-2 h-2 rounded-full shrink-0 ${r.status === 'USED' ? 'bg-green-500' : 'bg-primary-500'}`} />
                             <div>
                                <p className="text-sm text-gray-200">
                                   <span className="font-bold text-white">{user.name}</span> resgatou <span className="text-primary-400">{coupon.title}</span> em <span className="font-medium text-gray-300">{store.name}</span>.
                                </p>
                                <p className="text-xs text-gray-500 mt-1">{new Date(r.redeemedAt).toLocaleString('pt-BR')}</p>
                             </div>
                          </div>
                        );
                     })}
                     {MY_REDEMPTIONS.length === 0 && <p className="text-gray-500">Sem atividade recente.</p>}
                  </div>
               </div>
            </div>
         </div>
       )}

       {activeTab === 'stores' && (
         <div className="animate-fade-in-up space-y-6">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
               {filteredStores.map(store => (
                  <div key={store.id} className="bg-gray-800 rounded-2xl p-5 border border-gray-700 shadow-sm hover:shadow-primary-500/10 hover:border-primary-500/50 transition-all group flex flex-col">
                     <div className="flex items-center gap-4 mb-4">
                        <img src={store.logoUrl} className="w-14 h-14 rounded-xl object-contain bg-white border border-gray-600 p-1" alt={store.name} />
                        <div>
                           <h3 className="font-bold text-white text-lg leading-tight group-hover:text-primary-400 transition-colors">{store.name}</h3>
                           <span className="inline-block mt-1 px-2 py-0.5 rounded text-xs font-medium bg-gray-700 text-gray-300">
                             {store.category}
                           </span>
                        </div>
                     </div>
                     <div className="mt-auto flex items-center justify-between pt-4 border-t border-gray-700">
                        <span className="text-sm text-gray-400 font-medium">Piso {store.floor}</span>
                        <div className="flex gap-2 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity">
                           <button onClick={() => handleOpenEditStore(store)} className="p-2 text-primary-400 hover:bg-gray-700 rounded-lg transition-colors" title="Editar">
                              <EditIcon />
                           </button>
                           <button onClick={() => onDeleteStore(store.id)} className="p-2 text-red-400 hover:bg-gray-700 rounded-lg transition-colors" title="Remover">
                              <TrashIcon />
                           </button>
                        </div>
                     </div>
                  </div>
               ))}
            </div>
            {filteredStores.length === 0 && <div className="text-center py-12 text-gray-500">Nenhuma loja encontrada.</div>}
         </div>
       )}

       {activeTab === 'users' && (
         <div className="animate-fade-in-up">
            <div className="bg-gray-800 rounded-2xl shadow-sm border border-gray-700 overflow-hidden">
               <div className="overflow-x-auto">
                 <table className="w-full text-left border-collapse">
                    <thead className="bg-gray-900/50 text-gray-400 text-xs uppercase font-semibold">
                       <tr>
                          <th className="px-6 py-4">Usuário</th>
                          <th className="px-6 py-4">Função</th>
                          <th className="px-6 py-4">Loja Associada</th>
                          <th className="px-6 py-4 text-right">Ações</th>
                       </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-700 text-sm">
                       {filteredUsers.map(u => {
                          const userStore = stores.find(s => s.id === u.storeId);
                          return (
                            <tr key={u.id} className="hover:bg-gray-700/50 transition-colors">
                               <td className="px-6 py-4">
                                  <div className="flex items-center gap-3">
                                     <div className="w-9 h-9 rounded-full bg-primary-900/30 text-primary-400 flex items-center justify-center font-bold text-xs border border-primary-500/20">
                                       {u.avatarUrl ? <img src={u.avatarUrl} className="w-full h-full rounded-full object-cover" /> : u.name.substring(0,2).toUpperCase()}
                                     </div>
                                     <div>
                                       <p className="font-bold text-white">{u.name}</p>
                                       <p className="text-gray-500 text-xs">{u.email}</p>
                                     </div>
                                  </div>
                               </td>
                               <td className="px-6 py-4">
                                  <span className={`px-2 py-1 rounded-md text-xs font-bold ${
                                    u.role === UserRole.ADMIN ? 'bg-purple-900/30 text-purple-400' :
                                    u.role === UserRole.MANAGER ? 'bg-blue-900/30 text-blue-400' :
                                    'bg-green-900/30 text-green-400'
                                  }`}>
                                    {u.role === UserRole.ADMIN ? 'Administrador' : u.role === UserRole.MANAGER ? 'Gerente' : 'Funcionário'}
                                  </span>
                               </td>
                               <td className="px-6 py-4 text-gray-400">
                                  {userStore ? (
                                    <div className="flex items-center gap-2">
                                       <img src={userStore.logoUrl} className="w-5 h-5 rounded object-contain bg-white" />
                                       <span>{userStore.name}</span>
                                    </div>
                                  ) : '-'}
                               </td>
                               <td className="px-6 py-4 text-right">
                                  <div className="flex justify-end gap-2">
                                     <button onClick={() => handleOpenEditUser(u)} className="p-2 text-primary-400 hover:bg-gray-700 rounded-lg transition-colors">
                                        <EditIcon />
                                     </button>
                                     <button onClick={() => onDeleteUser(u.id)} className="p-2 text-red-400 hover:bg-gray-700 rounded-lg transition-colors">
                                        <TrashIcon />
                                     </button>
                                  </div>
                               </td>
                            </tr>
                          );
                       })}
                    </tbody>
                 </table>
               </div>
            </div>
         </div>
       )}

       {/* Store Modal */}
       <Modal isOpen={isStoreModalOpen} onClose={() => setIsStoreModalOpen(false)}>
          <div className="p-6">
             <h2 className="text-xl font-bold mb-6 text-white">{editingStore ? 'Editar Loja' : 'Nova Loja'}</h2>
             <form onSubmit={handleSubmitStore} className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-400 mb-1">Nome da Loja</label>
                  <input required className={inputClasses} value={storeFormData.name} onChange={e => setStoreFormData({...storeFormData, name: e.target.value})} />
                </div>
                <div className="grid grid-cols-2 gap-4">
                   <div>
                     <label className="block text-sm font-medium text-gray-400 mb-1">Categoria</label>
                     <div className="relative">
                       <select className={selectClasses} value={storeFormData.category} onChange={e => setStoreFormData({...storeFormData, category: e.target.value})}>
                          {CATEGORIES.filter(c => c !== 'Todos').map(c => <option key={c} value={c}>{c}</option>)}
                       </select>
                       <div className="absolute inset-y-0 right-0 flex items-center px-4 pointer-events-none">
                          <ChevronDownIcon />
                       </div>
                     </div>
                   </div>
                   <div>
                     <label className="block text-sm font-medium text-gray-400 mb-1">Piso</label>
                     <input required className={inputClasses} value={storeFormData.floor} onChange={e => setStoreFormData({...storeFormData, floor: e.target.value})} />
                   </div>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-400 mb-1">URL do Logo</label>
                  <input required className={inputClasses} value={storeFormData.logoUrl} onChange={e => setStoreFormData({...storeFormData, logoUrl: e.target.value})} placeholder="https://..." />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-400 mb-1">URL da Capa</label>
                  <input required className={inputClasses} value={storeFormData.coverUrl} onChange={e => setStoreFormData({...storeFormData, coverUrl: e.target.value})} placeholder="https://..." />
                </div>
                <div className="pt-4">
                   <Button fullWidth type="submit">{editingStore ? 'Salvar Alterações' : 'Criar Loja'}</Button>
                </div>
             </form>
          </div>
       </Modal>

       {/* User Modal */}
       <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)}>
          <div className="p-6">
             <h2 className="text-xl font-bold mb-6 text-white">{editingUser ? 'Editar Usuário' : 'Novo Usuário'}</h2>
             <form onSubmit={handleSubmitUser} className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-400 mb-1">Nome Completo</label>
                  <input required className={inputClasses} value={userFormData.name} onChange={e => setUserFormData({...userFormData, name: e.target.value})} />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-400 mb-1">E-mail</label>
                  <input type="email" required className={inputClasses} value={userFormData.email} onChange={e => setUserFormData({...userFormData, email: e.target.value})} />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-400 mb-1">Função</label>
                  <div className="relative">
                    <select className={selectClasses} value={userFormData.role} onChange={e => setUserFormData({...userFormData, role: e.target.value as UserRole})}>
                       <option value={UserRole.EMPLOYEE}>Funcionário</option>
                       <option value={UserRole.MANAGER}>Gerente</option>
                       <option value={UserRole.ADMIN}>Administrador</option>
                    </select>
                    <div className="absolute inset-y-0 right-0 flex items-center px-4 pointer-events-none">
                       <ChevronDownIcon />
                    </div>
                  </div>
                </div>
                {userFormData.role !== UserRole.ADMIN && (
                  <div>
                    <label className="block text-sm font-medium text-gray-400 mb-1">Loja Associada</label>
                    <div className="relative">
                      <select className={selectClasses} value={userFormData.storeId} onChange={e => setUserFormData({...userFormData, storeId: e.target.value})}>
                         {stores.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                      </select>
                      <div className="absolute inset-y-0 right-0 flex items-center px-4 pointer-events-none">
                         <ChevronDownIcon />
                      </div>
                    </div>
                  </div>
                )}
                <div className="pt-4">
                   <Button fullWidth type="submit">{editingUser ? 'Salvar Alterações' : 'Criar Usuário'}</Button>
                </div>
             </form>
          </div>
       </Modal>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Store, User, UserRole, Redemption, Coupon } from '../types';
import { Button } from './Button';
import { Modal } from './Modal';
import { CATEGORIES } from '../constants';

interface AdminDashboardProps {
  stores: Store[];
  users: User[];
  coupons: Coupon[];
  redemptions: Redemption[];
  onAddStore: (store: Omit<Store, 'id'>) => void;
  onUpdateStore: (store: Store) => void;
  onDeleteStore: (storeId: string) => void;
  onAddUser: (user: Omit<User, 'id'>) => void;
  onUpdateUser: (user: User) => void;
  onDeleteUser: (userId: string) => void;
}

// Icons
const EditIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>;
const TrashIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>;
const SearchIcon = () => <svg className="w-5 h-5 text-gray-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>;
const StoreIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>;
const UserIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>;
const ChevronDownIcon = () => <svg className="w-4 h-4 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>;

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  stores, users, coupons, redemptions, onAddStore, onUpdateStore, onDeleteStore, onAddUser, onUpdateUser, onDeleteUser 
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'stores' | 'users'>('overview');
  const [searchQuery, setSearchQuery] = useState('');

  // Store Modal State
  const [isStoreModalOpen, setIsStoreModalOpen] = useState(false);
  const [editingStore, setEditingStore] = useState<Store | null>(null);
  const [storeFormData, setStoreFormData] = useState<Partial<Store>>({ name: '', category: 'Moda', floor: '', logoUrl: '', coverUrl: '' });

  // User Modal State
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [userFormData, setUserFormData] = useState<Partial<User>>({ name: '', email: '', role: UserRole.EMPLOYEE, storeId: '' });

  // Filtering
  const filteredStores = useMemo(() => {
    return stores.filter(s => s.name.toLowerCase().includes(searchQuery.toLowerCase()) || s.category.toLowerCase().includes(searchQuery.toLowerCase()));
  }, [stores, searchQuery]);

  const filteredUsers = useMemo(() => {
    return users.filter(u => u.name.toLowerCase().includes(searchQuery.toLowerCase()) || u.email.toLowerCase().includes(searchQuery.toLowerCase()));
  }, [users, searchQuery]);

  // Global Stats Logic
  const globalStats = useMemo(() => {
     const totalRedemptions = redemptions.length;
     const activeUsersCount = new Set(redemptions.map(r => r.userId)).size;

     // Calculate top store based on redemption count
     const topStoreId = stores.reduce((acc, store) => {
         const storeCoupons = coupons.filter(c => c.storeId === store.id);
         const count = storeCoupons.reduce((sum, c) => sum + redemptions.filter(r => r.couponId === c.id).length, 0);
         return count > acc.count ? { id: store.id, count } : acc;
     }, { id: '', count: 0 }).id;

     const topStore = stores.find(s => s.id === topStoreId);

     // Category Distribution
     const catDist = CATEGORIES.filter(c => c !== 'Todos').map(cat => ({
       name: cat,
       count: stores.filter(s => s.category === cat).length
     }));

     return { totalRedemptions, activeUsersCount, topStore, catDist };
  }, [stores, users, coupons, redemptions]);

  // Handlers - Stores
  const handleOpenAddStore = () => {
    setEditingStore(null);
    setStoreFormData({ name: '', category: 'Moda', floor: '', logoUrl: '', coverUrl: '' });
    setIsStoreModalOpen(true);
  };

  const handleOpenEditStore = (store: Store) => {
    setEditingStore(store);
    setStoreFormData(store);
    setIsStoreModalOpen(true);
  };

  const handleSubmitStore = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingStore) {
      onUpdateStore({ ...editingStore, ...storeFormData } as Store);
    } else {
      onAddStore(storeFormData as Omit<Store, 'id'>);
    }
    setIsStoreModalOpen(false);
  };

  // Handlers - Users
  const handleOpenAddUser = () => {
    setEditingUser(null);
    setUserFormData({ name: '', email: '', role: UserRole.EMPLOYEE, storeId: stores[0]?.id || '' });
    setIsUserModalOpen(true);
  };

  const handleOpenEditUser = (user: User) => {
    setEditingUser(user);
    setUserFormData(user);
    setIsUserModalOpen(true);
  };

  const handleSubmitUser = (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
       ...userFormData,
       // If role is admin, clear storeId
       storeId: userFormData.role === UserRole.ADMIN ? undefined : userFormData.storeId
    };

    if (editingUser) {
      onUpdateUser({ ...editingUser, ...payload } as User);
    } else {
      onAddUser(payload as Omit<User, 'id'>);
    }
    setIsUserModalOpen(false);
  };

  const inputClasses = "w-full border border-gray-600 bg-gray-700 text-white p-3 rounded-xl focus:ring-2 focus:ring-primary-500 focus:outline-none transition-all placeholder-gray-400";
  const selectClasses = "w-full border border-gray-600 bg-gray-700 text-white p-3 rounded-xl focus:ring-2 focus:ring-primary-500 focus:outline-none transition-all appearance-none";

  return (
    <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 pt-8 pb-20">
       <div className="flex flex-col md:flex-row justify-between items-end md:items-center mb-8 gap-4">
         <div>
            <h1 className="text-3xl font-bold text-white">Painel do Administrador</h1>
            <p className="text-gray-400 mt-1">Gerencie a estrutura e monitore o ecossistema.</p>
         </div>
         <div className="flex bg-gray-800 rounded-xl p-1.5 border border-gray-700 shadow-sm">
            <button 
              onClick={() => setActiveTab('overview')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all ${activeTab === 'overview' ? 'bg-primary-900/30 text-primary-400 shadow-sm' : 'text-gray-400 hover:text-white hover:bg-gray-700'}`}
            >
              Visão Geral
            </button>
            <button 
              onClick={() => setActiveTab('stores')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all flex items-center gap-2 ${activeTab === 'stores' ? 'bg-primary-900/30 text-primary-400 shadow-sm' : 'text-gray-400 hover:text-white hover:bg-gray-700'}`}
            >
              <StoreIcon /> Lojas
            </button>
            <button 
              onClick={() => setActiveTab('users')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all flex items-center gap-2 ${activeTab === 'users' ? 'bg-primary-900/30 text-primary-400 shadow-sm' : 'text-gray-400 hover:text-white hover:bg-gray-700'}`}
            >
              <UserIcon /> Usuários
            </button>
         </div>
       </div>

       {/* Search Bar (Shared for Stores and Users tabs) */}
       {activeTab !== 'overview' && (
         <div className="mb-6 flex gap-4 animate-fade-in">
           <div className="relative flex-1">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
               <SearchIcon />
             </div>
             <input
               type="text"
               placeholder={activeTab === 'stores' ? "Buscar loja..." : "Buscar usuário..."}
               className="block w-full pl-10 pr-3 py-3 border border-gray-700 rounded-xl leading-5 bg-gray-800 text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500 transition-all shadow-sm"
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
             />
           </div>
           <Button onClick={activeTab === 'stores' ? handleOpenAddStore : handleOpenAddUser} className="shrink-0">
             {activeTab === 'stores' ? '+ Nova Loja' : '+ Novo Usuário'}
           </Button>
         </div>
       )}

       {activeTab === 'overview' && (
         <div className="space-y-8 animate-fade-in-up">
            {/* Quick Stats */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
              <div className="bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-700 flex flex-col justify-between hover:shadow-md transition-shadow">
                 <div className="flex justify-between items-start">
                    <p className="text-gray-400 text-xs font-bold uppercase tracking-wider">Total de Lojas</p>
                    <div className="p-2 bg-gray-700 rounded-lg text-gray-300"><StoreIcon /></div>
                 </div>
                 <p className="text-4xl font-extrabold text-white mt-4">{stores.length}</p>
              </div>
              <div className="bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-700 flex flex-col justify-between hover:shadow-md transition-shadow">
                 <div className="flex justify-between items-start">
                    <p className="text-gray-400 text-xs font-bold uppercase tracking-wider">Usuários</p>
                    <div className="p-2 bg-gray-700 rounded-lg text-gray-300"><UserIcon /></div>
                 </div>
                 <p className="text-4xl font-extrabold text-white mt-4">{users.length}</p>
              </div>
              <div className="bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-700 flex flex-col justify-between hover:shadow-md transition-shadow">
                 <div className="flex justify-between items-start">
                    <p className="text-gray-400 text-xs font-bold uppercase tracking-wider">Total Resgates</p>
                    <div className="p-2 bg-primary-900/20 text-primary-400 rounded-lg">
                       <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                    </div>
                 </div>
                 <p className="text-4xl font-extrabold text-white mt-4">{globalStats.totalRedemptions}</p>
              </div>
              <div className="bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-700 flex flex-col justify-between hover:shadow-md transition-shadow relative overflow-hidden">
                 <div className="absolute top-0 right-0 p-8 opacity-5">
                    <StoreIcon />
                 </div>
                 <div className="flex justify-between items-start relative z-10">
                    <p className="text-gray-400 text-xs font-bold uppercase tracking-wider">Loja Top Performance</p>
                    <div className="p-2 bg-accent-900/20 text-accent-400 rounded-lg">
                       <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z" /></svg>
                    </div>
                 </div>
                 <p className="text-2xl font-bold text-white mt-4 truncate">{globalStats.topStore?.name || 'N/A'}</p>
                 <p className="text-xs text-gray-400">Maior volume de resgates</p>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
               {/* Category Distribution Chart */}
               <div className="bg-gray-800 p-6 rounded-2xl border border-gray-700 shadow-lg">
                  <h3 className="text-lg font-bold text-white mb-6">Distribuição de Lojas</h3>
                  <div className="space-y-4">
                     {globalStats.catDist.map((cat) => {
                       const max = Math.max(...globalStats.catDist.map(c => c.count));
                       const percent = (cat.count / (max || 1)) * 100;
                       return (
                         <div key={cat.name}>
                            <div className="flex justify-between text-sm mb-1 text-gray-300">
                               <span>{cat.name}</span>
                               <span className="font-bold">{cat.count}</span>
                            </div>
                            <div className="w-full bg-gray-700 rounded-full h-3">
                               <div 
                                 className="bg-gradient-to-r from-primary-500 to-primary-600 h-3 rounded-full transition-all duration-500" 
                                 style={{ width: `${percent}%` }}
                               ></div>
                            </div>
                         </div>
                       )
                     })}
                  </div>
               </div>

               {/* Recent Activity Feed */}
               <div className="bg-gray-800 p-6 rounded-2xl border border-gray-700 shadow-lg">
                  <h3 className="text-lg font-bold text-white mb-6">Atividade Recente do Sistema</h3>
                  <div className="space-y-4">
                     {redemptions.slice().sort((a,b) => new Date(b.redeemedAt).getTime() - new Date(a.redeemedAt).getTime()).slice(0, 5).map(r => {
                        const coupon = coupons.find(c => c.id === r.couponId);
                        const user = users.find(u => u.id === r.userId);
                        const store = stores.find(s => s.id === coupon?.storeId);

                        if (!coupon || !user || !store) return null;

                        return (
                          <div key={r.id} className="flex gap-4 items-start p-3 bg-gray-900/50 rounded-xl border border-gray-700 animate-fade-in">
                             <div className={`mt-1 w-2 h-2 rounded-full shrink-0 ${r.status === 'USED' ? 'bg-green-500' : 'bg-primary-500'}`} />
                             <div>
                                <p className="text-sm text-gray-200">
                                   <span className="font-bold text-white">{user.name}</span> resgatou <span className="text-primary-400">{coupon.title}</span> em <span className="font-medium text-gray-300">{store.name}</span>.
                                </p>
                                <p className="text-xs text-gray-500 mt-1">{new Date(r.redeemedAt).toLocaleString('pt-BR')}</p>
                             </div>
                          </div>
                        );
                     })}
                     {redemptions.length === 0 && <p className="text-gray-500">Sem atividade recente.</p>}
                  </div>
               </div>
            </div>
         </div>
       )}

       {activeTab === 'stores' && (
         <div className="animate-fade-in-up space-y-6">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
               {filteredStores.map(store => (
                  <div key={store.id} className="bg-gray-800 rounded-2xl p-5 border border-gray-700 shadow-sm hover:shadow-primary-500/10 hover:border-primary-500/50 transition-all group flex flex-col">
                     <div className="flex items-center gap-4 mb-4">
                        <img src={store.logoUrl} className="w-14 h-14 rounded-xl object-contain bg-white border border-gray-600 p-1" alt={store.name} />
                        <div>
                           <h3 className="font-bold text-white text-lg leading-tight group-hover:text-primary-400 transition-colors">{store.name}</h3>
                           <span className="inline-block mt-1 px-2 py-0.5 rounded text-xs font-medium bg-gray-700 text-gray-300">
                             {store.category}
                           </span>
                        </div>
                     </div>
                     <div className="mt-auto flex items-center justify-between pt-4 border-t border-gray-700">
                        <span className="text-sm text-gray-400 font-medium">Piso {store.floor}</span>
                        <div className="flex gap-2 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity">
                           <button onClick={() => handleOpenEditStore(store)} className="p-2 text-primary-400 hover:bg-gray-700 rounded-lg transition-colors" title="Editar">
                              <EditIcon />
                           </button>
                           <button onClick={() => onDeleteStore(store.id)} className="p-2 text-red-400 hover:bg-gray-700 rounded-lg transition-colors" title="Remover">
                              <TrashIcon />
                           </button>
                        </div>
                     </div>
                  </div>
               ))}
            </div>
            {filteredStores.length === 0 && <div className="text-center py-12 text-gray-500">Nenhuma loja encontrada.</div>}
         </div>
       )}

       {activeTab === 'users' && (
         <div className="animate-fade-in-up">
            <div className="bg-gray-800 rounded-2xl shadow-sm border border-gray-700 overflow-hidden">
               <div className="overflow-x-auto">
                 <table className="w-full text-left border-collapse">
                    <thead className="bg-gray-900/50 text-gray-400 text-xs uppercase font-semibold">
                       <tr>
                          <th className="px-6 py-4">Usuário</th>
                          <th className="px-6 py-4">Função</th>
                          <th className="px-6 py-4">Loja Associada</th>
                          <th className="px-6 py-4 text-right">Ações</th>
                       </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-700 text-sm">
                       {filteredUsers.map(u => {
                          const userStore = stores.find(s => s.id === u.storeId);
                          return (
                            <tr key={u.id} className="hover:bg-gray-700/50 transition-colors">
                               <td className="px-6 py-4">
                                  <div className="flex items-center gap-3">
                                     <div className="w-9 h-9 rounded-full bg-primary-900/30 text-primary-400 flex items-center justify-center font-bold text-xs border border-primary-500/20">
                                       {u.avatarUrl ? <img src={u.avatarUrl} className="w-full h-full rounded-full object-cover" /> : u.name.substring(0,2).toUpperCase()}
                                     </div>
                                     <div>
                                       <p className="font-bold text-white">{u.name}</p>
                                       <p className="text-gray-500 text-xs">{u.email}</p>
                                     </div>
                                  </div>
                               </td>
                               <td className="px-6 py-4">
                                  <span className={`px-2 py-1 rounded-md text-xs font-bold ${
                                    u.role === UserRole.ADMIN ? 'bg-purple-900/30 text-purple-400' :
                                    u.role === UserRole.MANAGER ? 'bg-blue-900/30 text-blue-400' :
                                    'bg-green-900/30 text-green-400'
                                  }`}>
                                    {u.role === UserRole.ADMIN ? 'Administrador' : u.role === UserRole.MANAGER ? 'Gerente' : 'Funcionário'}
                                  </span>
                               </td>
                               <td className="px-6 py-4 text-gray-400">
                                  {userStore ? (
                                    <div className="flex items-center gap-2">
                                       <img src={userStore.logoUrl} className="w-5 h-5 rounded object-contain bg-white" />
                                       <span>{userStore.name}</span>
                                    </div>
                                  ) : '-'}
                               </td>
                               <td className="px-6 py-4 text-right">
                                  <div className="flex justify-end gap-2">
                                     <button onClick={() => handleOpenEditUser(u)} className="p-2 text-primary-400 hover:bg-gray-700 rounded-lg transition-colors">
                                        <EditIcon />
                                     </button>
                                     <button onClick={() => onDeleteUser(u.id)} className="p-2 text-red-400 hover:bg-gray-700 rounded-lg transition-colors">
                                        <TrashIcon />
                                     </button>
                                  </div>
                               </td>
                            </tr>
                          );
                       })}
                    </tbody>
                 </table>
               </div>
            </div>
         </div>
       )}

       {/* Store Modal */}
       <Modal isOpen={isStoreModalOpen} onClose={() => setIsStoreModalOpen(false)}>
          <div className="p-6">
             <h2 className="text-xl font-bold mb-6 text-white">{editingStore ? 'Editar Loja' : 'Nova Loja'}</h2>
             <form onSubmit={handleSubmitStore} className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-400 mb-1">Nome da Loja</label>
