import React from 'react';
import { Coupon, Store } from '../types';
import { Button } from './Button';

interface CouponCardProps {
  coupon: Coupon;
  store: Store;
  onClick: () => void;
  isRedeemed?: boolean;
}

export const CouponCard: React.FC<CouponCardProps> = ({ coupon, store, onClick, isRedeemed = false }) => {
  // Determine gradient based on category, kept subtle
  const getGradient = (cat: string) => {
    switch(cat) {
      case 'Alimentação': return 'from-orange-500/20 to-red-500/20';
      case 'Moda': return 'from-purple-500/20 to-pink-500/20';
      case 'Esportes': return 'from-blue-500/20 to-cyan-500/20';
      default: return 'from-gray-500/20 to-slate-500/20';
    }
  };

  return (
    <div 
      className={`group glass-panel rounded-2xl overflow-hidden transition-all duration-300 flex flex-col h-full cursor-pointer relative shadow-lg ${
        isRedeemed 
          ? 'opacity-80 grayscale-[0.3]' 
          : 'hover:shadow-primary-500/20 hover:scale-[1.02] hover:border-primary-500/40'
      }`}
      onClick={onClick}
    >
      {/* Discount Badge */}
      <div className="absolute top-3 right-3 z-10">
        <div className={`backdrop-blur-md px-3 py-1 rounded-full shadow-sm border ${isRedeemed ? 'bg-green-500/20 border-green-500/30' : 'bg-surface/80 border-white/10'}`}>
          <span className={`font-bold text-sm ${isRedeemed ? 'text-green-500' : 'text-primary-500'}`}>
            {coupon.discountType === 'PERCENTAGE' 
              ? `${coupon.discountValue}% OFF` 
              : `R$ ${coupon.discountValue} OFF`}
          </span>
        </div>
      </div>

      {/* Redeemed Badge Overlay */}
      {isRedeemed && (
        <div className="absolute top-3 left-3 z-10">
          <div className="bg-green-500 text-white px-3 py-1 rounded-full shadow-lg flex items-center gap-1">
             <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
             <span className="font-bold text-xs uppercase tracking-wider">Resgatado</span>
          </div>
        </div>
      )}

      {/* Image Section */}
      <div className="relative h-40 overflow-hidden bg-surface">
        <div className={`absolute inset-0 bg-gradient-to-br ${getGradient(store.category)} opacity-60 z-0`} />
        <img 
          src={store.coverUrl} 
          alt={store.name} 
          className={`w-full h-full object-cover transform transition-transform duration-500 opacity-90 ${isRedeemed ? 'grayscale-[0.5]' : 'group-hover:scale-105 group-hover:opacity-100'}`}
        />
        {/* Logo overlay */}
        <div className="absolute -bottom-6 left-4 glass-panel p-1 rounded-xl shadow-md w-16 h-16 flex items-center justify-center z-10">
           <div className="w-full h-full rounded-lg overflow-hidden bg-white flex items-center justify-center">
             {store.logoUrl.includes('http') ? (
                <img src={store.logoUrl} alt="logo" className="w-full h-full object-contain" />
             ) : (
                <span className="text-xs font-bold text-gray-900">{store.name.substring(0,2)}</span>
             )}
           </div>
        </div>
      </div>

      {/* Content Section */}
      <div className="p-4 pt-8 flex-1 flex flex-col">
        <div className="flex justify-between items-start mb-1">
          <span className="text-xs font-bold text-text-muted uppercase tracking-wider">
            {store.category} • {store.floor}
          </span>
        </div>

        <h3 className={`text-lg font-bold leading-tight mb-2 line-clamp-2 transition-colors ${isRedeemed ? 'text-text-muted' : 'text-text-main group-hover:text-primary-500'}`}>
          {coupon.title}
        </h3>

        <p className="text-text-muted text-sm mb-4 line-clamp-2 flex-1 font-medium">
          {coupon.description}
        </p>

        <div className="flex items-center justify-between mt-auto pt-4 border-t border-border">
          <div className="text-xs text-text-muted">
            Válido até <br/>
            <span className="text-text-main font-semibold">
              {new Date(coupon.expiryDate).toLocaleDateString('pt-BR')}
            </span>
          </div>

          {isRedeemed ? (
            <div className="py-2 px-4 rounded-lg bg-green-500/10 border border-green-500/20 text-green-500 text-xs font-bold flex items-center gap-1">
               <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
               Resgatado
            </div>
          ) : (
            <Button 
              variant="outline" 
              className="!py-2 !px-4 !text-xs !rounded-lg"
              onClick={(e) => {
                e.stopPropagation();
                onClick();
              }}
            >
              Ver Cupom
            </Button>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Coupon, Store, User, Redemption } from '../types';
import { CouponCard } from './CouponCard';
import { Button } from './Button';
import { Modal } from './Modal';
import { CATEGORIES } from '../constants';

const SearchIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>;
const FilterIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" /></svg>;
const TicketIcon = () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 5v2m0 4v2m0 4v2M5 5a2 2 0 00-2 2v3a2 2 0 110 4v3a2 2 0 002 2h14a2 2 0 002-2v-3a2 2 0 110-4V7a2 2 0 00-2-2H5z" /></svg>;
const CopyIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" /></svg>;
const CheckIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>;
const BellIcon = () => (
  <svg className="w-6 h-6 text-text-muted group-hover:text-primary-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
  </svg>
);
const BackIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
  </svg>
);
const Spinner = () => (
  <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
  </svg>
);

// Skeleton Component for Loading State
const CouponSkeleton = () => (
  <div className="glass-panel rounded-2xl overflow-hidden shadow-sm h-full flex flex-col">
    <div className="h-40 bg-surface/50 animate-pulse relative overflow-hidden">
        <div className="absolute inset-0 -translate-x-full animate-[shimmer_1.5s_infinite] bg-gradient-to-r from-transparent via-white/10 to-transparent"></div>
    </div>
    <div className="p-4 flex-1 flex flex-col">
      <div className="flex justify-between mb-3">
         <div className="h-3 w-24 bg-surface/50 rounded animate-pulse"></div>
      </div>
      <div className="h-6 w-3/4 bg-surface/50 rounded mb-2 animate-pulse"></div>
      <div className="h-4 w-full bg-surface/50 rounded mb-4 animate-pulse"></div>
      <div className="mt-auto pt-4 border-t border-border flex justify-between items-center">
         <div className="h-8 w-20 bg-surface/50 rounded animate-pulse"></div>
         <div className="h-8 w-24 bg-surface/50 rounded animate-pulse"></div>
      </div>
    </div>
  </div>
);

interface EmployeeDashboardProps {
  user: User;
  stores: Store[];
  coupons: Coupon[];
  redemptions: Redemption[];
  onRedeem: (couponId: string) => Promise<string>;
}

export const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({ 
  user, stores, coupons, redemptions, onRedeem 
}) => {
  const [currentView, setCurrentView] = useState<'home' | 'my-coupons'>('home');
  const [selectedCategory, setSelectedCategory] = useState('Todos');
  const [searchQuery, setSearchQuery] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [sortBy, setSortBy] = useState<'newest' | 'expiring' | 'discount'>('newest');

  // Loading State
  const [isLoadingFeed, setIsLoadingFeed] = useState(true);

  // Notification State
  const [showNotifications, setShowNotifications] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);

  // Modal State
  const [selectedCoupon, setSelectedCoupon] = useState<{coupon: Coupon, store: Store} | null>(null);
  const [selectedRedemption, setSelectedRedemption] = useState<Redemption | null>(null);
  const [isRedeeming, setIsRedeeming] = useState(false);
  const [redemptionCode, setRedemptionCode] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => setIsLoadingFeed(false), 1500);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const notifications = useMemo(() => {
    const today = new Date();
    const alerts: Array<{id: string, title: string, message: string, daysLeft: number}> = [];

    redemptions.forEach(r => {
      if (r.status !== 'PENDING') return;
      const coupon = coupons.find(c => c.id === r.couponId);
      if (!coupon) return;

      const expiry = new Date(coupon.expiryDate);
      const diffTime = expiry.getTime() - today.getTime();
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (diffDays <= 7 && diffDays >= 0) {
        alerts.push({
          id: r.id,
          title: 'Cupom Expirando',
          message: `"${coupon.title}" expira em ${diffDays === 0 ? 'menos de 24h' : diffDays + ' dias'}.`,
          daysLeft: diffDays
        });
      }
    });

    return alerts.sort((a, b) => a.daysLeft - b.daysLeft);
  }, [redemptions, coupons]);

  const filteredCoupons = useMemo(() => {
    let result = coupons.filter(coupon => {
      const store = stores.find(s => s.id === coupon.storeId);
      if (!store) return false;

      const matchesCategory = selectedCategory === 'Todos' || coupon.category === selectedCategory;
      const matchesSearch = 
        coupon.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        store.name.toLowerCase().includes(searchQuery.toLowerCase());

      return matchesCategory && matchesSearch;
    });

    result = result.sort((a, b) => {
      if (sortBy === 'expiring') return new Date(a.expiryDate).getTime() - new Date(b.expiryDate).getTime();
      if (sortBy === 'discount') return b.discountValue - a.discountValue;
      return 0; 
    });

    return result;
  }, [coupons, stores, selectedCategory, searchQuery, sortBy]);

  const handleOpenCoupon = (coupon: Coupon) => {
    const store = stores.find(s => s.id === coupon.storeId);
    if (store) {
      setSelectedCoupon({ coupon, store });
      setIsRedeeming(false);
      setRedemptionCode(null);
    }
  };

  const executeRedeem = async () => {
    if (!selectedCoupon) return;
    setIsRedeeming(true);
    try {
      const code = await onRedeem(selectedCoupon.coupon.id);
      setRedemptionCode(code);
      if ((window as any).confetti) {
        (window as any).confetti({
          particleCount: 150,
          spread: 70,
          origin: { y: 0.6 },
          colors: ['#D4AF37', '#10b981', '#ffffff']
        });
      }
    } catch (e) {
      alert("Erro ao resgatar");
    } finally {
      setIsRedeeming(false);
    }
  };

  const handleCopyCode = (code: string) => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 pt-8 pb-20">
      {/* Header */}
      <div className="flex justify-between items-start mb-8 animate-fade-in-up">
        <div className="flex items-center gap-3">
          {currentView !== 'home' && (
             <button 
               onClick={() => setCurrentView('home')} 
               className="p-2 rounded-full glass-panel text-text-muted hover:text-primary-500 hover:border-primary-500/50 transition-colors"
               title="Voltar ao início"
             >
                <BackIcon />
             </button>
          )}
          <div>
            <h1 className="text-3xl font-extrabold text-text-main leading-tight">
              {currentView === 'home' ? `Olá, ${user.name.split(' ')[0]}!` : 'Minha Carteira'}
            </h1>
            <p className="text-text-muted mt-1">
              {currentView === 'home' ? 'Explore os descontos disponíveis no shopping hoje.' : 'Seus cupons ativos e histórico.'}
            </p>
          </div>
        </div>

        {/* Notification Bell */}
        <div className="relative" ref={notificationRef}>
          <button 
            onClick={() => setShowNotifications(!showNotifications)} 
            className={`p-3 rounded-xl glass-panel transition-all duration-200 relative group ${showNotifications ? 'bg-primary-500/10 border-primary-500/50 text-primary-500' : 'hover:bg-surface/50 text-text-muted'}`}
          >
            <BellIcon />
            {notifications.length > 0 && (
               <span className="absolute top-2.5 right-3 flex h-2.5 w-2.5">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2.5 w-2.5 bg-red-500 border-2 border-main"></span>
               </span>
            )}
          </button>

          {showNotifications && (
            <div className="absolute right-0 top-full mt-2 w-80 glass-panel rounded-2xl shadow-xl p-0 z-50 animate-pop-in overflow-hidden ring-1 ring-black/5">
               <div className="p-4 border-b border-border bg-surface/50">
                 <h3 className="font-bold text-text-main text-sm">Notificações</h3>
               </div>
               {notifications.length === 0 ? (
                 <div className="p-8 text-center">
                    <p className="text-sm text-text-muted">Tudo limpo por aqui! ✨</p>
                 </div>
               ) : (
                 <div className="max-h-80 overflow-y-auto">
                    {notifications.map((notif) => (
                      <div 
                        key={notif.id} 
                        className="flex gap-3 items-start p-4 hover:bg-surface/50 transition-colors border-b border-border last:border-0 cursor-pointer"
                        onClick={() => {
                           const r = redemptions.find(x => x.id === notif.id);
                           if (r) setSelectedRedemption(r);
                           setShowNotifications(false);
                        }}
                      >
                        <div className={`w-2 h-2 mt-1.5 rounded-full shrink-0 ${notif.daysLeft <= 1 ? 'bg-red-500' : 'bg-orange-400'}`} />
                        <div>
                           <p className="text-sm font-bold text-text-main">{notif.title}</p>
                           <p className="text-xs text-text-muted mt-0.5 leading-relaxed">{notif.message}</p>
                        </div>
                      </div>
                    ))}
                 </div>
               )}
            </div>
          )}
        </div>
      </div>

      {currentView === 'home' && (
         <div className="flex justify-center mb-8">
            <button 
              onClick={() => setCurrentView('my-coupons')}
              className="bg-gradient-to-r from-primary-400 to-primary-600 text-white shadow-lg shadow-primary-500/30 px-8 py-3 rounded-xl font-bold text-sm flex items-center gap-2 hover:shadow-xl hover:scale-[1.02] transition-all border border-white/20"
            >
              <TicketIcon />
              Ver Meus Resgates
            </button>
         </div>
      )}

      {currentView === 'home' ? (
        <>
          {/* Filters */}
          <div className="mb-8 sticky top-20 z-20 md:static animate-fade-in-up" style={{ animationDelay: '100ms' }}>
              <div className="flex flex-col md:flex-row gap-3">
                <div className="relative flex-1 group">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-text-muted group-focus-within:text-primary-500 transition-colors">
                    <SearchIcon />
                  </div>
                  <input
                    type="text"
                    placeholder="Busque por loja..."
                    className="block w-full pl-10 pr-3 py-3 glass-panel rounded-xl leading-5 text-text-main placeholder-text-muted focus:outline-none focus:ring-2 focus:ring-primary-500 transition-all shadow-sm"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                </div>
                <button 
                  onClick={() => setShowFilters(!showFilters)}
                  className={`flex items-center gap-2 px-5 py-3 rounded-xl border transition-all glass-panel ${showFilters ? 'bg-surface/80 border-primary-500 text-primary-500' : 'text-text-muted hover:bg-surface/50'}`}
                >
                  <FilterIcon />
                  <span className="font-medium text-sm">Filtros</span>
                </button>
              </div>

              {showFilters && (
                <div className="mt-4 glass-panel p-5 rounded-2xl shadow-lg animate-pop-in space-y-4">
                   <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      <div>
                        <label className="block text-xs font-bold text-text-muted uppercase mb-2">Ordenar Por</label>
                        <div className="flex flex-wrap gap-2">
                           {[
                             { id: 'newest', label: 'Mais Recentes' },
                             { id: 'expiring', label: 'Vai Expirar' },
                             { id: 'discount', label: 'Maior Desconto' }
                           ].map((opt) => (
                             <button 
                               key={opt.id}
                               onClick={() => setSortBy(opt.id as any)} 
                               className={`px-3 py-2 text-xs font-semibold rounded-lg border transition-colors ${sortBy === opt.id ? 'bg-primary-500 text-white border-primary-500' : 'bg-surface/50 text-text-muted border-border hover:border-primary-500/50'}`}
                             >
                               {opt.label}
                             </button>
                           ))}
                        </div>
                      </div>
                      <div>
                        <label className="block text-xs font-bold text-text-muted uppercase mb-2">Categoria</label>
                        <div className="relative">
                          <select 
                            value={selectedCategory}
                            onChange={(e) => setSelectedCategory(e.target.value)}
                            className="block w-full pl-3 pr-10 py-2 text-sm border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500 bg-surface/50 text-text-main"
                          >
                            {CATEGORIES.map(cat => (
                              <option key={cat} value={cat}>{cat}</option>
                            ))}
                          </select>
                        </div>
                      </div>
                   </div>
                </div>
              )}
          </div>

          {/* Grid */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 animate-fade-in-up" style={{ animationDelay: '200ms' }}>
            {isLoadingFeed 
              ? Array.from({ length: 6 }).map((_, i) => <CouponSkeleton key={i} />)
              : filteredCoupons.map((coupon, idx) => {
                  const store = stores.find(s => s.id === coupon.storeId);
                  if (!store) return null;
                  const userRedemptionsCount = redemptions.filter(r => r.couponId === coupon.id).length;
                  const isRedeemed = userRedemptionsCount >= coupon.maxUsesPerUser;

                  return (
                    <div key={coupon.id} style={{ animationDelay: `${(idx * 50)}ms` }} className="animate-fade-in-up">
                      <CouponCard 
                        coupon={coupon} 
                        store={store} 
                        onClick={() => handleOpenCoupon(coupon)} 
                        isRedeemed={isRedeemed}
                      />
                    </div>
                  );
                })
            }
          </div>
        </>
      ) : (
        /* My Redemptions */
        <div className="max-w-2xl mx-auto animate-fade-in-up">
           <div className="space-y-4">
             {redemptions.length === 0 ? (
               <div className="text-center py-12 text-text-muted border-2 border-dashed border-border rounded-2xl glass-panel">
                 <p>Nenhum cupom resgatado ainda.</p>
                 <Button onClick={() => setCurrentView('home')} className="mt-4" variant="outline">Explorar Cupons</Button>
               </div>
             ) : (
               redemptions.map(r => {
                  const coupon = coupons.find(c => c.id === r.couponId);
                  const store = stores.find(s => s.id === coupon?.storeId);
                  if(!coupon || !store) return null;

                  const expiry = new Date(coupon.expiryDate);
                  const daysLeft = Math.ceil((expiry.getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24));
                  const isExpiring = r.status === 'PENDING' && daysLeft <= 7 && daysLeft >= 0;

                  return (
                    <div key={r.id} onClick={() => setSelectedRedemption(r)} className="glass-panel p-4 rounded-2xl shadow-sm flex items-center gap-4 cursor-pointer hover:shadow-md hover:border-primary-500/50 transition-all group relative overflow-hidden">
                      {isExpiring && <div className="absolute top-0 left-0 w-1 h-full bg-orange-500"></div>}
                      <img src={store.logoUrl} className="w-12 h-12 object-contain rounded-lg border border-border bg-white p-1" alt={store.name} />
                      <div className="flex-1">
                        <h4 className="font-bold text-text-main group-hover:text-primary-500 transition-colors">{coupon.title}</h4>
                        <div className="flex items-center gap-2 mt-1">
                          <span className="text-xs text-text-muted font-medium">{store.name}</span>
                          {isExpiring && <span className="text-[10px] bg-orange-500/20 text-orange-500 px-2 py-0.5 rounded-full font-bold border border-orange-500/20">Expira em {daysLeft} dias</span>}
                        </div>
                      </div>
                      <span className={`px-3 py-1 rounded-full text-xs font-bold border ${
                        r.status === 'PENDING' ? 'bg-green-500/10 text-green-500 border-green-500/30' : 
                        r.status === 'USED' ? 'bg-surface/50 text-text-muted border-border' :
                        'bg-red-500/10 text-red-500 border-red-500/30'
                      }`}>
                        {r.status === 'PENDING' ? 'Ativo' : r.status === 'USED' ? 'Usado' : 'Expirado'}
                      </span>
                    </div>
                  );
               })
             )}
           </div>
        </div>
      )}

      {/* Coupon Details Modal */}
      {selectedCoupon && (
        <Modal isOpen={!!selectedCoupon} onClose={() => setSelectedCoupon(null)}>
           <div className="h-48 relative">
              <img src={selectedCoupon.store.coverUrl} className="w-full h-full object-cover" alt="Cover" />
              <div className="absolute inset-0 bg-gradient-to-t from-main via-main/60 to-transparent" />
              <div className="absolute bottom-4 left-6 flex items-center gap-3 text-white">
                 <div className="bg-white p-1 rounded-lg shadow-lg">
                   <img src={selectedCoupon.store.logoUrl} className="w-10 h-10 object-contain" alt="logo"/>
                 </div>
                 <div>
                   <p className="font-bold text-lg leading-none text-white">{selectedCoupon.store.name}</p>
                   <p className="text-xs opacity-80 mt-1 text-gray-200">{selectedCoupon.store.category}</p>
                 </div>
              </div>
           </div>
           <div className="p-6 bg-main">
              {!redemptionCode ? (
                <>
                  <h2 className="text-2xl font-bold text-text-main mb-2">{selectedCoupon.coupon.title}</h2>
                  <p className="text-text-muted mb-6 leading-relaxed">{selectedCoupon.coupon.description}</p>

                  <div className="bg-surface/30 rounded-xl p-4 mb-6 border border-border">
                    <h4 className="text-xs font-bold text-text-muted uppercase tracking-wider mb-2">Regras</h4>
                    <ul className="text-sm text-text-main space-y-2">
                      <li className="flex items-start gap-2">
                           <span className="text-primary-500 mt-1.5 w-1.5 h-1.5 rounded-full bg-primary-500 shrink-0"></span>
                           <span>Limite de uso: <strong>{selectedCoupon.coupon.maxUsesPerUser} por pessoa</strong>.</span>
                      </li>
                      {selectedCoupon.coupon.rules.map((rule, i) => (
                        <li key={i} className="flex items-start gap-2">
                           <span className="text-primary-500 mt-1.5 w-1.5 h-1.5 rounded-full bg-primary-500 shrink-0"></span>
                           <span>{rule}</span>
                        </li>
                      ))}
                    </ul>
                  </div>

                  {(() => {
                    const userRedemptionsCount = redemptions.filter(r => r.couponId === selectedCoupon.coupon.id).length;
                    const isLimitReached = userRedemptionsCount >= selectedCoupon.coupon.maxUsesPerUser;

                    return (
                       <Button fullWidth onClick={executeRedeem} disabled={isRedeeming || isLimitReached}>
                        {isRedeeming ? <><Spinner /> Gerando Cupom...</> : isLimitReached ? 'Limite de Uso Atingido' : 'Resgatar Cupom'}
                      </Button>
                    );
                  })()}
                </>
              ) : (
                <div className="text-center py-6 animate-pop-in">
                   <div className="w-20 h-20 bg-green-500/10 text-green-500 rounded-full flex items-center justify-center mx-auto mb-6 ring-4 ring-green-500/20">
                      <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                   </div>
                   <h3 className="text-2xl font-bold text-text-main mb-2">Sucesso!</h3>
                   <p className="text-text-muted mb-6">Apresente este código na loja para validar.</p>

                   <div className="bg-surface/50 text-primary-500 text-3xl font-mono p-5 rounded-xl mb-6 tracking-widest border-2 border-dashed border-border shadow-inner">
                     {redemptionCode}
                   </div>

                   <Button variant="secondary" fullWidth onClick={() => setSelectedCoupon(null)}>Fechar e Usar Depois</Button>
                </div>
              )}
           </div>
        </Modal>
      )}

      {/* Redemption Status Modal */}
      {selectedRedemption && (
         <Modal isOpen={!!selectedRedemption} onClose={() => setSelectedRedemption(null)}>
            {(() => {
               const coupon = coupons.find(c => c.id === selectedRedemption.couponId);
               const store = stores.find(s => s.id === coupon?.storeId);
               if (!coupon || !store) return null;

               const isUsed = selectedRedemption.status === 'USED';
               const isExpired = selectedRedemption.status === 'EXPIRED';
               const statusColor = isUsed ? 'text-text-muted bg-surface/50' : isExpired ? 'text-red-400 bg-red-500/10' : 'text-green-500 bg-green-500/10';

               return (
                 <div className="p-0 bg-main">
                    <div className="bg-gradient-to-br from-primary-400 to-primary-600 p-6 text-white text-center relative overflow-hidden">
                       <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>
                       <h2 className="text-xl font-bold relative z-10">{store.name}</h2>
                       <p className="text-white/80 text-sm relative z-10 font-medium">{coupon.title}</p>
                    </div>

                    <div className="p-6">
                       <div className="flex justify-center mb-6">
                         <div className="p-3 bg-white border border-border rounded-xl shadow-lg">
                            {isUsed || isExpired ? (
                               <div className="w-40 h-40 flex items-center justify-center bg-gray-100 rounded-lg">
                                  <span className="text-gray-400 font-bold opacity-50 text-xl rotate-45 border-4 border-gray-300 p-2 rounded-lg">
                                    {isUsed ? 'UTILIZADO' : 'EXPIRADO'}
                                  </span>
                               </div>
                            ) : (
                               <img 
                                 src={`https://api.qrserver.com/v1/create-qr-code/?size=160x160&data=${selectedRedemption.code}`} 
                                 alt="QR Code" 
                                 className="w-40 h-40" 
                               />
                            )}
                         </div>
                       </div>

                       <div className="flex items-center gap-2 mb-6">
                          <div className="flex-1 bg-surface/50 border border-border rounded-lg py-3 px-4 text-center">
                             <span className="font-mono text-xl font-bold text-text-main tracking-widest">{selectedRedemption.code}</span>
                          </div>
                          <button 
                            onClick={() => handleCopyCode(selectedRedemption.code)}
                            className="bg-surface/50 text-primary-500 p-3.5 rounded-lg hover:bg-surface/80 transition-colors border border-border hover:border-primary-500/50"
                            title="Copiar código"
                          >
                            {copied ? <CheckIcon /> : <CopyIcon />}
                          </button>
                       </div>

                       <div className="space-y-3 text-sm border-t border-border pt-4">
                          <div className="flex justify-between">
                             <span className="text-text-muted">Status</span>
                             <span className={`px-2 py-0.5 rounded text-xs font-bold uppercase ${statusColor}`}>
                               {selectedRedemption.status === 'PENDING' ? 'Disponível' : selectedRedemption.status === 'USED' ? 'Utilizado' : 'Expirado'}
                             </span>
                          </div>

                          {isUsed ? (
                             <>
                               <div className="flex justify-between">
                                  <span className="text-text-muted">Validado por</span>
                                  <span className="font-medium text-text-main">{selectedRedemption.validatedBy || 'Loja'}</span>
                               </div>
                               <div className="flex justify-between">
                                  <span className="text-text-muted">Data de Uso</span>
                                  <span className="font-medium text-text-main">
                                    {selectedRedemption.validatedAt ? new Date(selectedRedemption.validatedAt).toLocaleString('pt-BR') : '-'}
                                  </span>
                               </div>
                             </>
                          ) : (
                             <>
                               <div className="flex justify-between">
                                  <span className="text-text-muted">Resgatado em</span>
                                  <span className="font-medium text-text-main">{new Date(selectedRedemption.redeemedAt).toLocaleDateString('pt-BR')}</span>
                               </div>
                               <div className="flex justify-between">
                                  <span className="text-text-muted">Válido até</span>
                                  <span className="font-medium text-red-400">{new Date(coupon.expiryDate).toLocaleDateString('pt-BR')}</span>
                               </div>
                             </>
                          )}
                       </div>

                       <div className="mt-8">
                         <Button fullWidth variant="secondary" onClick={() => setSelectedRedemption(null)}>Fechar</Button>
                       </div>
                    </div>
                 </div>
               );
            })()}
         </Modal>
      )}
    </div>
  );
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost' | 'danger';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false, 
  className = '',
  ...props 
}) => {
  const baseStyles = "font-bold py-3 px-6 rounded-xl transition-all duration-200 flex items-center justify-center gap-2 active:scale-95 disabled:opacity-50 disabled:pointer-events-none tracking-wide text-sm";

  const variants = {
    // Primary: Uses the theme's primary color variable
    primary: "bg-primary-500 text-white shadow-lg shadow-primary-500/30 hover:bg-primary-600 hover:shadow-primary-500/40",

    // Secondary: Surface based with border
    secondary: "bg-surface text-text-main border border-border hover:bg-surface/80 hover:border-gray-500",

    // Outline: Primary border and text
    outline: "border-2 border-primary-500 text-primary-500 hover:bg-primary-500/10",

    // Ghost: Subtle
    ghost: "text-text-muted hover:text-text-main hover:bg-surface/50",

    // Danger: Red
    danger: "bg-red-500/10 text-red-500 border border-red-500/50 hover:bg-red-500 hover:text-white"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React, { useEffect, useState } from 'react';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  children: React.ReactNode;
}

export const Modal: React.FC<ModalProps> = ({ isOpen, onClose, children }) => {
  const [isClosing, setIsClosing] = useState(false);

  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => {
      document.body.style.overflow = 'unset';
    };
  }, [isOpen]);

  // Handle the closing animation sequence
  const handleClose = () => {
    setIsClosing(true);
    // Wait for animation (0.2s = 200ms) to finish before actually closing
    setTimeout(() => {
      onClose();
      setIsClosing(false); 
    }, 200);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      {/* Backdrop */}
      <div 
        className={`absolute inset-0 bg-black/60 backdrop-blur-sm ${isClosing ? 'animate-fade-out' : 'animate-fade-in'}`} 
        onClick={handleClose}
      />

      {/* Content */}
      <div 
        className={`relative glass-panel rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden max-h-[90vh] overflow-y-auto ${isClosing ? 'animate-scale-out' : 'animate-pop-in'}`}
      >
        <button 
          onClick={handleClose}
          className="absolute top-4 right-4 z-10 bg-black/20 backdrop-blur rounded-full p-2 hover:bg-black/40 text-white/70 hover:text-white transition-colors"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
        {children}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
