export const ManagerDashboard: React.FC<ManagerDashboardProps> = ({
  user, store, coupons, redemptions, onCreateCoupon, onValidateRedemption
}) => {
  const [view, setView] = useState<'overview' | 'manage' | 'validate'>('overview');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Validation State
  const [validationCode, setValidationCode] = useState('');
  const [validationResult, setValidationResult] = useState<'idle' | 'success' | 'error'>('idle');
  const [validationMessage, setValidationMessage] = useState('');
  const [isValidating, setIsValidating] = useState(false);

  // Scanner State
  const [isScannerOpen, setIsScannerOpen] = useState(false);

  // Form State
  const [newCoupon, setNewCoupon] = useState({
    title: '', description: '', discountValue: 0, quantity: 100, maxUsesPerUser: 1
  });

  // Derived Data
  const myCoupons = useMemo(() => coupons.filter(c => c.storeId === store.id), [coupons, store.id]);
  const myRedemptions = useMemo(() => redemptions.filter(r => myCoupons.find(c => c.id === r.couponId)), [redemptions, myCoupons]);

  // Stats
  const totalRedemptions = myRedemptions.length;
  const validatedRedemptions = myRedemptions.filter(r => r.status === 'USED').length;
  const activeCoupons = myCoupons.length;
  const uniqueUsersServed = new Set(myRedemptions.map(r => r.userId)).size;

  // Scanner Logic
  useEffect(() => {
    let scanner: any = null;
    let timer: any = null;

    if (isScannerOpen) {
      timer = setTimeout(() => {
        try {
          scanner = new Html5QrcodeScanner(
            "reader",
            { 
              fps: 10, 
              qrbox: { width: 250, height: 250 },
              aspectRatio: 1.0,
              showTorchButtonIfSupported: true 
            },
            false
          );

          scanner.render(
            (decodedText: string) => {
              setValidationCode(decodedText);
              setIsScannerOpen(false); 
            },
            (error: any) => {
              // Ignore errors
            }
          );
        } catch (err) {
          console.error("Error initializing scanner:", err);
        }
      }, 100);
    }

    return () => {
      if (timer) clearTimeout(timer);
      if (scanner) {
        scanner.clear().catch((error: any) => {
          console.error("Failed to clear scanner", error);
        });
      }
    };
  }, [isScannerOpen]);

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onCreateCoupon({
      storeId: store.id,
      title: newCoupon.title,
      description: newCoupon.description,
      discountType: 'PERCENTAGE', 
      discountValue: newCoupon.discountValue,
      expiryDate: new Date(Date.now() + 86400000 * 30).toISOString(), 
      category: store.category,
      availableQuantity: newCoupon.quantity,
      maxUsesPerUser: newCoupon.maxUsesPerUser,
      rules: ['Regra padrão']
    });
    setIsModalOpen(false);
  };

  const handleValidate = (e: React.FormEvent) => {
    e.preventDefault();
    setIsValidating(true);
    setTimeout(() => {
      const success = onValidateRedemption(validationCode);
      if (success) {
        setValidationResult('success');
        setValidationMessage('Cupom validado com sucesso!');
      } else {
        setValidationResult('error');
        setValidationMessage('Código inválido ou já utilizado.');
      }
      setIsValidating(false);
    }, 800);
  };

  const inputClasses = "input-base w-full px-3 py-3 rounded-xl transition-all focus:outline-none";

  return (
    <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 pt-8 pb-20">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 glass-panel p-6 rounded-3xl shadow-lg">
         <div className="flex items-center gap-4 mb-4 md:mb-0 w-full md:w-auto">
            <img src={store.logoUrl} className="w-16 h-16 rounded-xl border border-border p-1 object-contain bg-white" alt="logo" />
            <div>
              <h1 className="text-2xl font-bold text-text-main leading-none">{store.name}</h1>
              <p className="text-text-muted text-sm mt-1">Painel do Gerente • {user.name}</p>
            </div>
         </div>
         {/* Navigation Tabs */}
         <div className="flex bg-surface/50 rounded-xl p-1 border border-border">
             {[
               { id: 'overview', label: 'Visão Geral', icon: <ChartIcon /> },
               { id: 'manage', label: 'Gerenciar Cupons', icon: <ListIcon /> },
               { id: 'validate', label: 'Validar', icon: <QrCodeIcon /> }
             ].map(tab => (
               <button
                 key={tab.id}
                 onClick={() => setView(tab.id as any)}
                 className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold transition-all ${view === tab.id ? 'bg-primary-500 text-white shadow-lg' : 'text-text-muted hover:text-text-main hover:bg-surface'}`}
               >
                 {tab.icon}
                 <span className="hidden sm:inline">{tab.label}</span>
               </button>
             ))}
         </div>
      </div>

      {view === 'overview' && (
        <div className="animate-fade-in-up space-y-8">
           {/* Top Stats */}
           <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <div className="glass-panel p-5 rounded-2xl shadow-sm">
                 <p className="text-text-muted text-xs font-bold uppercase tracking-wider mb-1">Cupons Ativos</p>
                 <p className="text-3xl font-extrabold text-text-main">{activeCoupons}</p>
              </div>
              <div className="glass-panel p-5 rounded-2xl shadow-sm">
                 <p className="text-text-muted text-xs font-bold uppercase tracking-wider mb-1">Total Gerados</p>
                 <p className="text-3xl font-extrabold text-primary-500">{totalRedemptions}</p>
              </div>
              <div className="glass-panel p-5 rounded-2xl shadow-sm">
                 <p className="text-text-muted text-xs font-bold uppercase tracking-wider mb-1">Validados (Usados)</p>
                 <p className="text-3xl font-extrabold text-green-500">{validatedRedemptions}</p>
              </div>
              <div className="glass-panel p-5 rounded-2xl shadow-sm">
                 <p className="text-text-muted text-xs font-bold uppercase tracking-wider mb-1">Funcionários Únicos</p>
                 <div className="flex items-center gap-2">
                    <UserGroupIcon />
                    <p className="text-3xl font-extrabold text-text-main">{uniqueUsersServed}</p>
                 </div>
              </div>
           </div>

           <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              {/* Performance Card */}
              <div className="glass-panel p-6 rounded-2xl shadow-lg">
                 <h3 className="text-lg font-bold text-text-main mb-4">Performance dos Cupons</h3>
                 <div className="space-y-4">
                    {myCoupons.slice(0, 5).map(coupon => {
                       const usage = redemptions.filter(r => r.couponId === coupon.id).length;
                       const percentage = Math.min(100, Math.round((usage / coupon.availableQuantity) * 100));
                       return (
                         <div key={coupon.id}>
                            <div className="flex justify-between text-sm mb-1">
                               <span className="font-medium text-text-main">{coupon.title}</span>
                               <span className="text-text-muted">{usage} / {coupon.availableQuantity}</span>
                            </div>
                            <div className="w-full bg-surface rounded-full h-2.5">
                               <div className="bg-primary-500 h-2.5 rounded-full" style={{ width: `${percentage}%` }}></div>
                            </div>
                         </div>
                       );
                    })}
                    {myCoupons.length === 0 && <p className="text-text-muted text-sm">Nenhum cupom ativo para exibir dados.</p>}
                 </div>
              </div>

              {/* Recent Validations */}
              <div className="glass-panel p-6 rounded-2xl shadow-lg">
                 <h3 className="text-lg font-bold text-text-main mb-4">Últimas Validações</h3>
                 <div className="space-y-3">
                    {myRedemptions.filter(r => r.status === 'USED').slice(0, 5).sort((a,b) => new Date(b.validatedAt!).getTime() - new Date(a.validatedAt!).getTime()).map(redemption => (
                       <div key={redemption.id} className="flex items-center justify-between p-3 bg-surface/30 rounded-xl border border-border">
                          <div>
                             <p className="text-sm font-bold text-text-main">{redemption.code}</p>
                             <p className="text-xs text-text-muted">
                                {new Date(redemption.validatedAt!).toLocaleDateString('pt-BR')} às {new Date(redemption.validatedAt!).toLocaleTimeString('pt-BR', {hour: '2-digit', minute:'2-digit'})}
                             </p>
                          </div>
                          <span className="text-xs font-medium text-green-500 bg-green-500/10 px-2 py-1 rounded border border-green-500/20">Validado</span>
                       </div>
                    ))}
                    {myRedemptions.filter(r => r.status === 'USED').length === 0 && (
                      <div className="text-center py-8 text-text-muted text-sm border border-dashed border-border rounded-xl">
                        Nenhuma validação registrada ainda.
                      </div>
                    )}
                 </div>
              </div>
           </div>
        </div>
      )}

      {view === 'manage' && (
        <div className="animate-fade-in-up">
           <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-bold text-text-main">Todos os Cupons</h2>
              <Button onClick={() => setIsModalOpen(true)}>+ Criar Cupom</Button>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {myCoupons.map(coupon => (
                 <div key={coupon.id} className="glass-panel p-5 rounded-2xl shadow-sm hover:shadow-primary-500/10 hover:border-primary-500/30 transition-all group flex flex-col">
                    <h3 className="font-bold text-text-main mb-2 group-hover:text-primary-500 transition-colors line-clamp-1">{coupon.title}</h3>
                    <p className="text-sm text-text-muted mb-4 line-clamp-2">{coupon.description}</p>

                    <div className="mt-auto pt-4 border-t border-border space-y-2">
                       <div className="flex justify-between text-sm">
                          <span className="text-text-muted">Desconto</span>
                          <span className="text-primary-500 font-bold">{coupon.discountValue}% OFF</span>
                       </div>
                       <div className="flex justify-between text-sm">
                          <span className="text-text-muted">Limite Usuário</span>
                          <span className="text-text-main">{coupon.maxUsesPerUser}x</span>
                       </div>
                       <div className="flex justify-between text-sm">
                          <span className="text-text-muted">Total Estoque</span>
                          <span className="text-text-main">{coupon.availableQuantity}</span>
                       </div>
                    </div>
                 </div>
              ))}
              <div 
                onClick={() => setIsModalOpen(true)}
                className="border-2 border-dashed border-border rounded-2xl flex flex-col items-center justify-center p-6 text-text-muted cursor-pointer hover:border-primary-500 hover:bg-primary-500/10 hover:text-primary-500 transition-all min-h-[200px]"
              >
                 <span className="text-4xl mb-2 font-light">+</span>
                 <span className="font-medium text-sm">Novo Cupom</span>
              </div>
           </div>
        </div>
      )}

      {view === 'validate' && (
        <div className="max-w-md mx-auto glass-panel p-8 rounded-3xl shadow-2xl animate-pop-in">
           <h2 className="text-xl font-bold text-text-main mb-6 text-center">Validar Cupom</h2>

           <div className="mb-6 flex justify-center">
              <button 
                type="button"
                onClick={() => setIsScannerOpen(true)}
                className="flex flex-col items-center justify-center w-full py-6 border-2 border-dashed border-primary-500/30 rounded-2xl bg-primary-500/5 hover:bg-primary-500/10 transition-colors group"
              >
                <div className="w-12 h-12 bg-surface rounded-full flex items-center justify-center shadow-sm mb-2 group-hover:scale-110 transition-transform">
                   <svg className="w-6 h-6 text-primary-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" />
                   </svg>
                </div>
                <span className="text-primary-500 font-semibold">Escanear QR Code</span>
                <span className="text-xs text-text-muted mt-1">Utilizar câmera do dispositivo</span>
              </button>
           </div>

           <div className="relative flex py-2 items-center mb-6">
              <div className="flex-grow border-t border-border"></div>
              <span className="flex-shrink-0 mx-4 text-text-muted text-xs uppercase">Ou digite o código</span>
              <div className="flex-grow border-t border-border"></div>
           </div>

           <form onSubmit={handleValidate}>
             <label className="block text-sm font-medium text-text-muted mb-2">Código do Cupom</label>
             <input 
               type="text" 
               className="input-base block w-full px-4 py-3 text-center text-2xl tracking-widest font-mono rounded-xl focus:ring-2 focus:ring-primary-500 focus:border-primary-500 uppercase mb-6"
               placeholder="CPN-XXXX"
               value={validationCode}
               onChange={(e) => {
                 setValidationCode(e.target.value.toUpperCase());
                 setValidationResult('idle');
               }}
             />
             <Button fullWidth type="submit" disabled={isValidating}>
                {isValidating ? <><Spinner /> Verificando...</> : 'Validar Agora'}
             </Button>
           </form>

           {validationResult !== 'idle' && (
             <div className={`mt-6 p-4 rounded-xl text-center ${validationResult === 'success' ? 'bg-green-500/20 text-green-500' : 'bg-red-500/20 text-red-500'} animate-fade-in`}>
               {validationResult === 'success' ? (
                 <div className="flex flex-col items-center">
                    <div className="w-8 h-8 bg-green-500/20 rounded-full flex items-center justify-center mb-2">
                       <svg className="w-5 h-5 text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                    </div>
                    <p className="font-bold">{validationMessage}</p>
                 </div>
               ) : (
                 <div className="flex flex-col items-center">
                    <div className="w-8 h-8 bg-red-500/20 rounded-full flex items-center justify-center mb-2">
                       <svg className="w-5 h-5 text-red-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                    </div>
                    <p className="font-bold">{validationMessage}</p>
                 </div>
               )}
             </div>
           )}
        </div>
      )}

      {/* Create Modal */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)}>
         <div className="p-6 bg-main">
            <h2 className="text-xl font-bold mb-6 text-text-main">Novo Cupom</h2>
            <form onSubmit={handleCreateSubmit} className="space-y-4">
               <div>
                 <label className="block text-sm text-text-muted mb-1">Título</label>
                 <input required className={inputClasses} value={newCoupon.title} onChange={e => setNewCoupon({...newCoupon, title: e.target.value})} />
               </div>
               <div>
                 <label className="block text-sm text-text-muted mb-1">Descrição</label>
                 <textarea required className={inputClasses} value={newCoupon.description} onChange={e => setNewCoupon({...newCoupon, description: e.target.value})} />
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm text-text-muted mb-1">Desconto (%)</label>
                    <input type="number" required className={inputClasses} value={newCoupon.discountValue} onChange={e => setNewCoupon({...newCoupon, discountValue: Number(e.target.value)})} />
                  </div>
                  <div>
                    <label className="block text-sm text-text-muted mb-1">Qtd Total</label>
                    <input type="number" required className={inputClasses} value={newCoupon.quantity} onChange={e => setNewCoupon({...newCoupon, quantity: Number(e.target.value)})} />
                  </div>
               </div>
               <div>
                 <label className="block text-sm text-text-muted mb-1">Limite por Usuário</label>
                 <input type="number" min="1" required className={inputClasses} value={newCoupon.maxUsesPerUser} onChange={e => setNewCoupon({...newCoupon, maxUsesPerUser: Number(e.target.value)})} />
                 <p className="text-xs text-text-muted mt-1">Quantas vezes o mesmo funcionário pode resgatar este cupom.</p>
               </div>
               <Button fullWidth type="submit" className="mt-4">Publicar Cupom</Button>
            </form>
         </div>
      </Modal>

      {/* Scanner Modal */}
      <Modal isOpen={isScannerOpen} onClose={() => setIsScannerOpen(false)}>
         <div className="p-6 bg-main">
            <h2 className="text-xl font-bold text-text-main mb-4 text-center">Escanear Cupom</h2>
            <div className="relative bg-black rounded-2xl overflow-hidden shadow-inner border border-border">
               <div id="reader" className="w-full"></div>
            </div>
            <p className="text-center text-sm text-text-muted mt-4">Aponte a câmera para o QR Code do funcionário.</p>
            <div className="mt-4 flex justify-center">
              <Button variant="secondary" onClick={() => setIsScannerOpen(false)}>Cancelar</Button>
            </div>
         </div>
      </Modal>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Store, User, UserRole, Redemption, Coupon } from '../types';
import { Button } from './Button';
import { Modal } from './Modal';
import { CATEGORIES } from '../constants';

interface AdminDashboardProps {
  stores: Store[];
  users: User[];
  coupons: Coupon[];
  redemptions: Redemption[];
  onAddStore: (store: Omit<Store, 'id'>) => void;
  onUpdateStore: (store: Store) => void;
  onDeleteStore: (storeId: string) => void;
  onAddUser: (user: Omit<User, 'id'>) => void;
  onUpdateUser: (user: User) => void;
  onDeleteUser: (userId: string) => void;
}

// Icons
const EditIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>;
const TrashIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>;
const SearchIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>;
const StoreIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>;
const UserIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>;
const ChevronDownIcon = () => <svg className="w-4 h-4 text-text-muted" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>;

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  stores, users, coupons, redemptions, onAddStore, onUpdateStore, onDeleteStore, onAddUser, onUpdateUser, onDeleteUser 
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'stores' | 'users'>('overview');
  const [searchQuery, setSearchQuery] = useState('');

  // Store Modal State
  const [isStoreModalOpen, setIsStoreModalOpen] = useState(false);
  const [editingStore, setEditingStore] = useState<Store | null>(null);
  const [storeFormData, setStoreFormData] = useState<Partial<Store>>({ name: '', category: 'Moda', floor: '', logoUrl: '', coverUrl: '' });

  // User Modal State
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [userFormData, setUserFormData] = useState<Partial<User>>({ name: '', email: '', role: UserRole.EMPLOYEE, storeId: '' });

  // Filtering
  const filteredStores = useMemo(() => {
    return stores.filter(s => s.name.toLowerCase().includes(searchQuery.toLowerCase()) || s.category.toLowerCase().includes(searchQuery.toLowerCase()));
  }, [stores, searchQuery]);

  const filteredUsers = useMemo(() => {
    return users.filter(u => u.name.toLowerCase().includes(searchQuery.toLowerCase()) || u.email.toLowerCase().includes(searchQuery.toLowerCase()));
  }, [users, searchQuery]);

  // Global Stats Logic
  const globalStats = useMemo(() => {
     const totalRedemptions = redemptions.length;
     const activeUsersCount = new Set(redemptions.map(r => r.userId)).size;

     // Calculate top store based on redemption count
     const topStoreId = stores.reduce((acc, store) => {
         const storeCoupons = coupons.filter(c => c.storeId === store.id);
         const count = storeCoupons.reduce((sum, c) => sum + redemptions.filter(r => r.couponId === c.id).length, 0);
         return count > acc.count ? { id: store.id, count } : acc;
     }, { id: '', count: 0 }).id;

     const topStore = stores.find(s => s.id === topStoreId);

     // Category Distribution
     const catDist = CATEGORIES.filter(c => c !== 'Todos').map(cat => ({
       name: cat,
       count: stores.filter(s => s.category === cat).length
     }));

     return { totalRedemptions, activeUsersCount, topStore, catDist };
  }, [stores, users, coupons, redemptions]);

  // Handlers - Stores
  const handleOpenAddStore = () => {
    setEditingStore(null);
    setStoreFormData({ name: '', category: 'Moda', floor: '', logoUrl: '', coverUrl: '' });
    setIsStoreModalOpen(true);
  };

  const handleOpenEditStore = (store: Store) => {
    setEditingStore(store);
    setStoreFormData(store);
    setIsStoreModalOpen(true);
  };

  const handleSubmitStore = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingStore) {
      onUpdateStore({ ...editingStore, ...storeFormData } as Store);
    } else {
      onAddStore(storeFormData as Omit<Store, 'id'>);
    }
    setIsStoreModalOpen(false);
  };

  // Handlers - Users
  const handleOpenAddUser = () => {
    setEditingUser(null);
    setUserFormData({ name: '', email: '', role: UserRole.EMPLOYEE, storeId: stores[0]?.id || '' });
    setIsUserModalOpen(true);
  };

  const handleOpenEditUser = (user: User) => {
    setEditingUser(user);
    setUserFormData(user);
    setIsUserModalOpen(true);
  };

  const handleSubmitUser = (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
       ...userFormData,
       // If role is admin, clear storeId
       storeId: userFormData.role === UserRole.ADMIN ? undefined : userFormData.storeId
    };

    if (editingUser) {
      onUpdateUser({ ...editingUser, ...payload } as User);
    } else {
      onAddUser(payload as Omit<User, 'id'>);
    }
    setIsUserModalOpen(false);
  };

  const inputClasses = "input-base w-full p-3 rounded-xl transition-all focus:outline-none";
  const selectClasses = "input-base w-full p-3 rounded-xl transition-all appearance-none focus:outline-none";

  return (
    <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 pt-8 pb-20">
       <div className="flex flex-col md:flex-row justify-between items-end md:items-center mb-8 gap-4">
         <div>
            <h1 className="text-3xl font-bold text-text-main">Painel do Administrador</h1>
            <p className="text-text-muted mt-1">Gerencie a estrutura e monitore o ecossistema.</p>
         </div>
         <div className="flex bg-surface/50 rounded-xl p-1.5 border border-border shadow-sm">
            <button 
              onClick={() => setActiveTab('overview')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all ${activeTab === 'overview' ? 'bg-primary-900/30 text-primary-500 shadow-sm' : 'text-text-muted hover:text-text-main hover:bg-surface'}`}
            >
              Visão Geral
            </button>
            <button 
              onClick={() => setActiveTab('stores')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all flex items-center gap-2 ${activeTab === 'stores' ? 'bg-primary-900/30 text-primary-500 shadow-sm' : 'text-text-muted hover:text-text-main hover:bg-surface'}`}
            >
              <StoreIcon /> Lojas
            </button>
            <button 
              onClick={() => setActiveTab('users')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all flex items-center gap-2 ${activeTab === 'users' ? 'bg-primary-900/30 text-primary-500 shadow-sm' : 'text-text-muted hover:text-text-main hover:bg-surface'}`}
            >
              <UserIcon /> Usuários
            </button>
         </div>
       </div>

       {/* Search Bar (Shared for Stores and Users tabs) */}
       {activeTab !== 'overview' && (
         <div className="mb-6 flex gap-4 animate-fade-in">
           <div className="relative flex-1 group">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-text-muted">
               <SearchIcon />
             </div>
             <input
               type="text"
               placeholder={activeTab === 'stores' ? "Buscar loja..." : "Buscar usuário..."}
               className="input-base block w-full pl-10 pr-3 py-3 rounded-xl leading-5 transition-all shadow-sm focus:outline-none"
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
             />
           </div>
           <Button onClick={activeTab === 'stores' ? handleOpenAddStore : handleOpenAddUser} className="shrink-0">
             {activeTab === 'stores' ? '+ Nova Loja' : '+ Novo Usuário'}
           </Button>
         </div>
       )}

       {activeTab === 'overview' && (
         <div className="space-y-8 animate-fade-in-up">
            {/* Quick Stats */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
              <div className="glass-panel p-6 rounded-2xl shadow-sm flex flex-col justify-between hover:shadow-md transition-shadow">
                 <div className="flex justify-between items-start">
                    <p className="text-text-muted text-xs font-bold uppercase tracking-wider">Total de Lojas</p>
                    <div className="p-2 bg-surface rounded-lg text-text-muted"><StoreIcon /></div>
                 </div>
                 <p className="text-4xl font-extrabold text-text-main mt-4">{stores.length}</p>
              </div>
              <div className="glass-panel p-6 rounded-2xl shadow-sm flex flex-col justify-between hover:shadow-md transition-shadow">
                 <div className="flex justify-between items-start">
                    <p className="text-text-muted text-xs font-bold uppercase tracking-wider">Usuários</p>
                    <div className="p-2 bg-surface rounded-lg text-text-muted"><UserIcon /></div>
                 </div>
                 <p className="text-4xl font-extrabold text-text-main mt-4">{users.length}</p>
              </div>
              <div className="glass-panel p-6 rounded-2xl shadow-sm flex flex-col justify-between hover:shadow-md transition-shadow">
                 <div className="flex justify-between items-start">
                    <p className="text-text-muted text-xs font-bold uppercase tracking-wider">Total Resgates</p>
                    <div className="p-2 bg-primary-900/20 text-primary-500 rounded-lg">
                       <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                    </div>
                 </div>
                 <p className="text-4xl font-extrabold text-text-main mt-4">{globalStats.totalRedemptions}</p>
              </div>
              <div className="glass-panel p-6 rounded-2xl shadow-sm flex flex-col justify-between hover:shadow-md transition-shadow relative overflow-hidden">
                 <div className="absolute top-0 right-0 p-8 opacity-5">
                    <StoreIcon />
                 </div>
                 <div className="flex justify-between items-start relative z-10">
                    <p className="text-text-muted text-xs font-bold uppercase tracking-wider">Loja Top Performance</p>
                    <div className="p-2 bg-yellow-500/20 text-yellow-500 rounded-lg">
                       <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z" /></svg>
                    </div>
                 </div>
                 <p className="text-2xl font-bold text-text-main mt-4 truncate">{globalStats.topStore?.name || 'N/A'}</p>
                 <p className="text-xs text-text-muted">Maior volume de resgates</p>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
               {/* Category Distribution Chart */}
               <div className="glass-panel p-6 rounded-2xl shadow-lg">
                  <h3 className="text-lg font-bold text-text-main mb-6">Distribuição de Lojas</h3>
                  <div className="space-y-4">
                     {globalStats.catDist.map((cat) => {
                       const max = Math.max(...globalStats.catDist.map(c => c.count));
                       const percent = (cat.count / (max || 1)) * 100;
                       return (
                         <div key={cat.name}>
                            <div className="flex justify-between text-sm mb-1 text-text-muted">
                               <span>{cat.name}</span>
                               <span className="font-bold">{cat.count}</span>
                            </div>
                            <div className="w-full bg-surface rounded-full h-3">
                               <div 
                                 className="bg-gradient-to-r from-primary-500 to-primary-600 h-3 rounded-full transition-all duration-500" 
                                 style={{ width: `${percent}%` }}
                               ></div>
                            </div>
                         </div>
                       )
                     })}
                  </div>
               </div>

               {/* Recent Activity Feed */}
               <div className="glass-panel p-6 rounded-2xl shadow-lg">
                  <h3 className="text-lg font-bold text-text-main mb-6">Atividade Recente do Sistema</h3>
                  <div className="space-y-4">
                     {redemptions.slice().sort((a,b) => new Date(b.redeemedAt).getTime() - new Date(a.redeemedAt).getTime()).slice(0, 5).map(r => {
                        const coupon = coupons.find(c => c.id === r.couponId);
                        const user = users.find(u => u.id === r.userId);
                        const store = stores.find(s => s.id === coupon?.storeId);

                        if (!coupon || !user || !store) return null;

                        return (
                          <div key={r.id} className="flex gap-4 items-start p-3 bg-surface/30 rounded-xl border border-border animate-fade-in">
                             <div className={`mt-1 w-2 h-2 rounded-full shrink-0 ${r.status === 'USED' ? 'bg-green-500' : 'bg-primary-500'}`} />
                             <div>
                                <p className="text-sm text-text-muted">
                                   <span className="font-bold text-text-main">{user.name}</span> resgatou <span className="text-primary-500">{coupon.title}</span> em <span className="font-medium text-text-main">{store.name}</span>.
                                </p>
                                <p className="text-xs text-text-muted mt-1">{new Date(r.redeemedAt).toLocaleString('pt-BR')}</p>
                             </div>
                          </div>
                        );
                     })}
                     {redemptions.length === 0 && <p className="text-text-muted">Sem atividade recente.</p>}
                  </div>
               </div>
            </div>
         </div>
       )}

       {activeTab === 'stores' && (
         <div className="animate-fade-in-up space-y-6">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
               {filteredStores.map(store => (
                  <div key={store.id} className="glass-panel rounded-2xl p-5 shadow-sm hover:shadow-primary-500/10 hover:border-primary-500/50 transition-all group flex flex-col">
                     <div className="flex items-center gap-4 mb-4">
                        <img src={store.logoUrl} className="w-14 h-14 rounded-xl object-contain bg-white border border-border p-1" alt={store.name} />
                        <div>
                           <h3 className="font-bold text-text-main text-lg leading-tight group-hover:text-primary-500 transition-colors">{store.name}</h3>
                           <span className="inline-block mt-1 px-2 py-0.5 rounded text-xs font-medium bg-surface text-text-muted">
                             {store.category}
