import React, { useState, useMemo } from 'react';
import { Store, User, UserRole, Redemption, Coupon } from '../types';
import { Button } from './Button';
import { Modal } from './Modal';
import { ConfirmationModal } from './ConfirmationModal';
import { CATEGORIES } from '../constants';

interface AdminDashboardProps {
  stores: Store[];
  users: User[];
  coupons: Coupon[];
  redemptions: Redemption[];
  onAddStore: (store: Omit<Store, 'id'>) => void;
  onUpdateStore: (store: Store) => void;
  onDeleteStore: (storeId: string) => void;
  onAddUser: (user: Omit<User, 'id'>) => void;
  onUpdateUser: (user: User) => void;
  onDeleteUser: (userId: string) => void;
}

// Icons
const EditIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>;
const TrashIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>;
const SearchIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>;
const StoreIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>;
const UserIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>;
const ChevronDownIcon = () => <svg className="w-4 h-4 text-text-muted" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>;

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  stores, users, coupons, redemptions, onAddStore, onUpdateStore, onDeleteStore, onAddUser, onUpdateUser, onDeleteUser 
}) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'stores' | 'users'>('overview');
  const [searchQuery, setSearchQuery] = useState('');

  // Store Modal State
  const [isStoreModalOpen, setIsStoreModalOpen] = useState(false);
  const [editingStore, setEditingStore] = useState<Store | null>(null);
  const [storeFormData, setStoreFormData] = useState<Partial<Store>>({ name: '', category: 'Moda', floor: '', logoUrl: '', coverUrl: '' });

  // Confirmation State
  const [itemToDelete, setItemToDelete] = useState<{ type: 'store' | 'user', id: string, name: string } | null>(null);

  // User Modal State
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [userFormData, setUserFormData] = useState<Partial<User>>({ name: '', email: '', role: UserRole.EMPLOYEE, storeId: '' });

  // Filtering
  const filteredStores = useMemo(() => {
    return stores.filter(s => s.name.toLowerCase().includes(searchQuery.toLowerCase()) || s.category.toLowerCase().includes(searchQuery.toLowerCase()));
  }, [stores, searchQuery]);

  const filteredUsers = useMemo(() => {
    return users.filter(u => u.name.toLowerCase().includes(searchQuery.toLowerCase()) || u.email.toLowerCase().includes(searchQuery.toLowerCase()));
  }, [users, searchQuery]);

  // Global Stats Logic
  const globalStats = useMemo(() => {
     const totalRedemptions = redemptions.length;
     const activeUsersCount = new Set(redemptions.map(r => r.userId)).size;

     // Calculate top store based on redemption count
     const topStoreId = stores.reduce((acc, store) => {
         const storeCoupons = coupons.filter(c => c.storeId === store.id);
         const count = storeCoupons.reduce((sum, c) => sum + redemptions.filter(r => r.couponId === c.id).length, 0);
         return count > acc.count ? { id: store.id, count } : acc;
     }, { id: '', count: 0 }).id;

     const topStore = stores.find(s => s.id === topStoreId);

     // Category Distribution
     const catDist = CATEGORIES.filter(c => c !== 'Todos').map(cat => ({
       name: cat,
       count: stores.filter(s => s.category === cat).length
     }));

     return { totalRedemptions, activeUsersCount, topStore, catDist };
  }, [stores, users, coupons, redemptions]);

  // Handlers - Stores
  const handleOpenAddStore = () => {
    setEditingStore(null);
    setStoreFormData({ name: '', category: 'Moda', floor: '', logoUrl: '', coverUrl: '' });
    setIsStoreModalOpen(true);
  };

  const handleOpenEditStore = (store: Store) => {
    setEditingStore(store);
    setStoreFormData(store);
    setIsStoreModalOpen(true);
  };

  const handleSubmitStore = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingStore) {
      onUpdateStore({ ...editingStore, ...storeFormData } as Store);
    } else {
      onAddStore(storeFormData as Omit<Store, 'id'>);
    }
    setIsStoreModalOpen(false);
  };

  // Handlers - Users
  const handleOpenAddUser = () => {
    setEditingUser(null);
    setUserFormData({ name: '', email: '', role: UserRole.EMPLOYEE, storeId: stores[0]?.id || '' });
    setIsUserModalOpen(true);
  };

  const handleOpenEditUser = (user: User) => {
    setEditingUser(user);
    setUserFormData(user);
    setIsUserModalOpen(true);
  };

  const handleSubmitUser = (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
       ...userFormData,
       // If role is admin, clear storeId
       storeId: userFormData.role === UserRole.ADMIN ? undefined : userFormData.storeId
    };

    if (editingUser) {
      onUpdateUser({ ...editingUser, ...payload } as User);
    } else {
      onAddUser(payload as Omit<User, 'id'>);
    }
    setIsUserModalOpen(false);
  };

  const handleConfirmDelete = () => {
    if (!itemToDelete) return;

    if (itemToDelete.type === 'store') {
      onDeleteStore(itemToDelete.id);
    } else {
      onDeleteUser(itemToDelete.id);
    }
    setItemToDelete(null);
  };

  const inputClasses = "input-base w-full p-3 rounded-xl transition-all focus:outline-none";
  const selectClasses = "input-base w-full p-3 rounded-xl transition-all appearance-none focus:outline-none";

  return (
    <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 pt-8 pb-20">
       <div className="flex flex-col md:flex-row justify-between items-end md:items-center mb-8 gap-4">
         <div>
            <h1 className="text-3xl font-bold text-text-main">Painel do Administrador</h1>
            <p className="text-text-muted mt-1">Gerencie a estrutura e monitore o ecossistema.</p>
         </div>
         <div className="flex bg-surface/50 rounded-xl p-1.5 border border-border shadow-sm">
            <button 
              onClick={() => setActiveTab('overview')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all ${activeTab === 'overview' ? 'bg-primary-900/30 text-primary-500 shadow-sm' : 'text-text-muted hover:text-text-main hover:bg-surface'}`}
            >
              Visão Geral
            </button>
            <button 
              onClick={() => setActiveTab('stores')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all flex items-center gap-2 ${activeTab === 'stores' ? 'bg-primary-900/30 text-primary-500 shadow-sm' : 'text-text-muted hover:text-text-main hover:bg-surface'}`}
            >
              <StoreIcon /> Lojas
            </button>
            <button 
              onClick={() => setActiveTab('users')}
              className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all flex items-center gap-2 ${activeTab === 'users' ? 'bg-primary-900/30 text-primary-500 shadow-sm' : 'text-text-muted hover:text-text-main hover:bg-surface'}`}
            >
              <UserIcon /> Usuários
            </button>
         </div>
       </div>

       {/* Search Bar (Shared for Stores and Users tabs) */}
       {activeTab !== 'overview' && (
         <div className="mb-6 flex gap-4 animate-fade-in">
           <div className="relative flex-1 group">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-text-muted">
               <SearchIcon />
             </div>
             <input
               type="text"
               placeholder={activeTab === 'stores' ? "Buscar loja..." : "Buscar usuário..."}
               className="input-base block w-full pl-10 pr-3 py-3 rounded-xl leading-5 transition-all shadow-sm focus:outline-none"
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
             />
           </div>
           <Button onClick={activeTab === 'stores' ? handleOpenAddStore : handleOpenAddUser} className="shrink-0">
             {activeTab === 'stores' ? '+ Nova Loja' : '+ Novo Usuário'}
           </Button>
         </div>
       )}

       {activeTab === 'overview' && (
         <div className="space-y-8 animate-fade-in-up">
            {/* Quick Stats */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
              <div className="glass-panel p-6 rounded-2xl shadow-sm flex flex-col justify-between hover:shadow-md transition-shadow">
                 <div className="flex justify-between items-start">
                    <p className="text-text-muted text-xs font-bold uppercase tracking-wider">Total de Lojas</p>
                    <div className="p-2 bg-surface rounded-lg text-text-muted"><StoreIcon /></div>
                 </div>
                 <p className="text-4xl font-extrabold text-text-main mt-4">{stores.length}</p>
              </div>
              <div className="glass-panel p-6 rounded-2xl shadow-sm flex flex-col justify-between hover:shadow-md transition-shadow">
                 <div className="flex justify-between items-start">
                    <p className="text-text-muted text-xs font-bold uppercase tracking-wider">Usuários</p>
                    <div className="p-2 bg-surface rounded-lg text-text-muted"><UserIcon /></div>
                 </div>
                 <p className="text-4xl font-extrabold text-text-main mt-4">{users.length}</p>
              </div>
              <div className="glass-panel p-6 rounded-2xl shadow-sm flex flex-col justify-between hover:shadow-md transition-shadow">
                 <div className="flex justify-between items-start">
                    <p className="text-text-muted text-xs font-bold uppercase tracking-wider">Total Resgates</p>
                    <div className="p-2 bg-primary-900/20 text-primary-500 rounded-lg">
                       <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                    </div>
                 </div>
                 <p className="text-4xl font-extrabold text-text-main mt-4">{globalStats.totalRedemptions}</p>
              </div>
              <div className="glass-panel p-6 rounded-2xl shadow-sm flex flex-col justify-between hover:shadow-md transition-shadow relative overflow-hidden">
                 <div className="absolute top-0 right-0 p-8 opacity-5">
                    <StoreIcon />
                 </div>
                 <div className="flex justify-between items-start relative z-10">
                    <p className="text-text-muted text-xs font-bold uppercase tracking-wider">Loja Top Performance</p>
                    <div className="p-2 bg-yellow-500/20 text-yellow-500 rounded-lg">
                       <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z" /></svg>
                    </div>
                 </div>
                 <p className="text-2xl font-bold text-text-main mt-4 truncate">{globalStats.topStore?.name || 'N/A'}</p>
                 <p className="text-xs text-text-muted">Maior volume de resgates</p>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
               {/* Category Distribution Chart */}
               <div className="glass-panel p-6 rounded-2xl shadow-lg">
                  <h3 className="text-lg font-bold text-text-main mb-6">Distribuição de Lojas</h3>
                  <div className="space-y-4">
                     {globalStats.catDist.map((cat) => {
                       const max = Math.max(...globalStats.catDist.map(c => c.count));
                       const percent = (cat.count / (max || 1)) * 100;
                       return (
                         <div key={cat.name}>
                            <div className="flex justify-between text-sm mb-1 text-text-muted">
                               <span>{cat.name}</span>
                               <span className="font-bold">{cat.count}</span>
                            </div>
                            <div className="w-full bg-surface rounded-full h-3">
                               <div 
                                 className="bg-gradient-to-r from-primary-500 to-primary-600 h-3 rounded-full transition-all duration-500" 
                                 style={{ width: `${percent}%` }}
                               ></div>
                            </div>
                         </div>
                       )
                     })}
                  </div>
               </div>

               {/* Recent Activity Feed */}
               <div className="glass-panel p-6 rounded-2xl shadow-lg">
                  <h3 className="text-lg font-bold text-text-main mb-6">Atividade Recente do Sistema</h3>
                  <div className="space-y-4">
                     {redemptions.slice().sort((a,b) => new Date(b.redeemedAt).getTime() - new Date(a.redeemedAt).getTime()).slice(0, 5).map(r => {
                        const coupon = coupons.find(c => c.id === r.couponId);
                        const user = users.find(u => u.id === r.userId);
                        const store = stores.find(s => s.id === coupon?.storeId);

                        if (!coupon || !user || !store) return null;

                        return (
                          <div key={r.id} className="flex gap-4 items-start p-3 bg-surface/30 rounded-xl border border-border animate-fade-in">
                             <div className={`mt-1 w-2 h-2 rounded-full shrink-0 ${r.status === 'USED' ? 'bg-green-500' : 'bg-primary-500'}`} />
                             <div>
                                <p className="text-sm text-text-muted">
                                   <span className="font-bold text-text-main">{user.name}</span> resgatou <span className="text-primary-500">{coupon.title}</span> em <span className="font-medium text-text-main">{store.name}</span>.
                                </p>
                                <p className="text-xs text-text-muted mt-1">{new Date(r.redeemedAt).toLocaleString('pt-BR')}</p>
                             </div>
                          </div>
                        );
                     })}
                     {redemptions.length === 0 && <p className="text-text-muted">Sem atividade recente.</p>}
                  </div>
               </div>
            </div>
         </div>
       )}

       {activeTab === 'stores' && (
         <div className="animate-fade-in-up space-y-6">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
               {filteredStores.map(store => (
                  <div key={store.id} className="glass-panel rounded-2xl p-5 shadow-sm hover:shadow-primary-500/10 hover:border-primary-500/50 transition-all group flex flex-col">
                     <div className="flex items-center gap-4 mb-4">
                        <img src={store.logoUrl} className="w-14 h-14 rounded-xl object-contain bg-white border border-border p-1" alt={store.name} />
                        <div>
                           <h3 className="font-bold text-text-main text-lg leading-tight group-hover:text-primary-500 transition-colors">{store.name}</h3>
                           <span className="inline-block mt-1 px-2 py-0.5 rounded text-xs font-medium bg-surface text-text-muted">
                             {store.category}
                           </span>
                        </div>
                     </div>
                     <div className="mt-auto flex items-center justify-between pt-4 border-t border-border">
                        <span className="text-sm text-text-muted font-medium">Piso {store.floor}</span>
                        <div className="flex gap-2 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity">
                           <button onClick={() => handleOpenEditStore(store)} className="p-2 text-primary-500 hover:bg-surface rounded-lg transition-colors" title="Editar">
                              <EditIcon />
                           </button>
                           <button onClick={() => setItemToDelete({ type: 'store', id: store.id, name: store.name })} className="p-2 text-red-400 hover:bg-surface rounded-lg transition-colors" title="Remover">
                              <TrashIcon />
                           </button>
                        </div>
                     </div>
                  </div>
               ))}
            </div>
            {filteredStores.length === 0 && <div className="text-center py-12 text-text-muted">Nenhuma loja encontrada.</div>}
         </div>
       )}

       {activeTab === 'users' && (
         <div className="animate-fade-in-up">
            <div className="glass-panel rounded-2xl shadow-sm overflow-hidden">
               <div className="overflow-x-auto">
                 <table className="w-full text-left border-collapse">
                    <thead className="bg-surface/50 text-text-muted text-xs uppercase font-semibold">
                       <tr>
                          <th className="px-6 py-4">Usuário</th>
                          <th className="px-6 py-4">Função</th>
                          <th className="px-6 py-4">Loja Associada</th>
                          <th className="px-6 py-4 text-right">Ações</th>
                       </tr>
                    </thead>
                    <tbody className="divide-y divide-border text-sm">
                       {filteredUsers.map(u => {
                          const userStore = stores.find(s => s.id === u.storeId);
                          return (
                            <tr key={u.id} className="hover:bg-surface/30 transition-colors">
                               <td className="px-6 py-4">
                                  <div className="flex items-center gap-3">
                                     <div className="w-9 h-9 rounded-full bg-primary-500/10 text-primary-500 flex items-center justify-center font-bold text-xs border border-primary-500/20">
                                       {u.avatarUrl ? <img src={u.avatarUrl} className="w-full h-full rounded-full object-cover" /> : u.name.substring(0,2).toUpperCase()}
                                     </div>
                                     <div>
                                       <p className="font-bold text-text-main">{u.name}</p>
                                       <p className="text-text-muted text-xs">{u.email}</p>
                                     </div>
                                  </div>
                               </td>
                               <td className="px-6 py-4">
                                  <span className={`px-2 py-1 rounded-md text-xs font-bold ${
                                    u.role === UserRole.ADMIN ? 'bg-purple-500/10 text-purple-500' :
                                    u.role === UserRole.MANAGER ? 'bg-blue-500/10 text-blue-500' :
                                    'bg-green-500/10 text-green-500'
                                  }`}>
                                    {u.role === UserRole.ADMIN ? 'Administrador' : u.role === UserRole.MANAGER ? 'Gerente' : 'Funcionário'}
                                  </span>
                               </td>
                               <td className="px-6 py-4 text-text-muted">
                                  {userStore ? (
                                    <div className="flex items-center gap-2">
                                       <img src={userStore.logoUrl} className="w-5 h-5 rounded object-contain bg-white" />
                                       <span>{userStore.name}</span>
                                    </div>
                                  ) : '-'}
                               </td>
                               <td className="px-6 py-4 text-right">
                                  <div className="flex justify-end gap-2">
                                     <button onClick={() => handleOpenEditUser(u)} className="p-2 text-primary-500 hover:bg-surface rounded-lg transition-colors">
                                        <EditIcon />
                                     </button>
                                     <button onClick={() => setItemToDelete({ type: 'user', id: u.id, name: u.name })} className="p-2 text-red-400 hover:bg-surface rounded-lg transition-colors">
                                        <TrashIcon />
                                     </button>
                                  </div>
                               </td>
                            </tr>
                          );
                       })}
                    </tbody>
                 </table>
               </div>
            </div>
         </div>
       )}

       {/* Store Modal */}
       <Modal isOpen={isStoreModalOpen} onClose={() => setIsStoreModalOpen(false)}>
          <div className="p-6 bg-main">
             <h2 className="text-xl font-bold mb-6 text-text-main">{editingStore ? 'Editar Loja' : 'Nova Loja'}</h2>
             <form onSubmit={handleSubmitStore} className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-text-muted mb-1">Nome da Loja</label>
                  <input required className={inputClasses} value={storeFormData.name} onChange={e => setStoreFormData({...storeFormData, name: e.target.value})} />
                </div>
                <div className="grid grid-cols-2 gap-4">
                   <div>
                     <label className="block text-sm font-medium text-text-muted mb-1">Categoria</label>
                     <div className="relative">
                       <select className={selectClasses} value={storeFormData.category} onChange={e => setStoreFormData({...storeFormData, category: e.target.value})}>
                          {CATEGORIES.filter(c => c !== 'Todos').map(c => <option key={c} value={c}>{c}</option>)}
                       </select>
                       <div className="absolute inset-y-0 right-0 flex items-center px-4 pointer-events-none">
                          <ChevronDownIcon />
                       </div>
                     </div>
                   </div>
                   <div>
                     <label className="block text-sm font-medium text-text-muted mb-1">Piso</label>
                     <input required className={inputClasses} value={storeFormData.floor} onChange={e => setStoreFormData({...storeFormData, floor: e.target.value})} />
                   </div>
                </div>
                <div>
                  <label className="block text-sm font-medium text-text-muted mb-1">URL do Logo</label>
                  <input required className={inputClasses} value={storeFormData.logoUrl} onChange={e => setStoreFormData({...storeFormData, logoUrl: e.target.value})} placeholder="https://..." />
                </div>
                <div>
                  <label className="block text-sm font-medium text-text-muted mb-1">URL da Capa</label>
                  <input required className={inputClasses} value={storeFormData.coverUrl} onChange={e => setStoreFormData({...storeFormData, coverUrl: e.target.value})} placeholder="https://..." />
                </div>
                <div className="pt-4">
                   <Button fullWidth type="submit">{editingStore ? 'Salvar Alterações' : 'Criar Loja'}</Button>
                </div>
             </form>
          </div>
       </Modal>

       {/* User Modal */}
       <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)}>
          <div className="p-6 bg-main">
             <h2 className="text-xl font-bold mb-6 text-text-main">{editingUser ? 'Editar Usuário' : 'Novo Usuário'}</h2>
             <form onSubmit={handleSubmitUser} className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-text-muted mb-1">Nome Completo</label>
                  <input required className={inputClasses} value={userFormData.name} onChange={e => setUserFormData({...userFormData, name: e.target.value})} />
                </div>
                <div>
                  <label className="block text-sm font-medium text-text-muted mb-1">E-mail</label>
                  <input type="email" required className={inputClasses} value={userFormData.email} onChange={e => setUserFormData({...userFormData, email: e.target.value})} />
                </div>
                <div>
                  <label className="block text-sm font-medium text-text-muted mb-1">Função</label>
                  <div className="relative">
                    <select className={selectClasses} value={userFormData.role} onChange={e => setUserFormData({...userFormData, role: e.target.value as UserRole})}>
                       <option value={UserRole.EMPLOYEE}>Funcionário</option>
                       <option value={UserRole.MANAGER}>Gerente</option>
                       <option value={UserRole.ADMIN}>Administrador</option>
                    </select>
                    <div className="absolute inset-y-0 right-0 flex items-center px-4 pointer-events-none">
                       <ChevronDownIcon />
                    </div>
                  </div>
                </div>
                {userFormData.role !== UserRole.ADMIN && (
                  <div>
                    <label className="block text-sm font-medium text-text-muted mb-1">Loja Associada</label>
                    <div className="relative">
                      <select className={selectClasses} value={userFormData.storeId} onChange={e => setUserFormData({...userFormData, storeId: e.target.value})}>
                         {stores.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                      </select>
                      <div className="absolute inset-y-0 right-0 flex items-center px-4 pointer-events-none">
                         <ChevronDownIcon />
                      </div>
                    </div>
                  </div>
                )}
                <div className="pt-4">
                   <Button fullWidth type="submit">{editingUser ? 'Salvar Alterações' : 'Criar Usuário'}</Button>
                </div>
             </form>
          </div>
       </Modal>

       {/* Delete Confirmation Modal */}
       <ConfirmationModal
         isOpen={!!itemToDelete}
         onClose={() => setItemToDelete(null)}
         onConfirm={handleConfirmDelete}
         title={`Excluir ${itemToDelete?.type === 'store' ? 'Loja' : 'Usuário'}`}
         message={`Tem certeza que deseja excluir "${itemToDelete?.name}"? Esta ação não pode ser desfeita.`}
         confirmText="Sim, excluir"
       />
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, Store, Coupon, Redemption } from '../types';
import { Button } from './Button';
import { Modal } from './Modal';
import { ConfirmationModal } from './ConfirmationModal';
import { Html5QrcodeScanner } from 'html5-qrcode';
import { SecurityService } from '../services/security';

interface ManagerDashboardProps {
  user: User;
  store: Store;
  coupons: Coupon[];
  redemptions: Redemption[];
  onCreateCoupon: (coupon: Omit<Coupon, 'id'>) => void;
  onDeleteCoupon: (couponId: string) => void;
  onValidateRedemption: (code: string) => boolean;
}

const BackIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
  </svg>
);

const ChartIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>;
const ListIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 10h16M4 14h16M4 18h16" /></svg>;
const QrCodeIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" /></svg>;
const UserGroupIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>;
const TrashIcon = () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>;

const Spinner = () => (
  <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
  </svg>
);

export const ManagerDashboard: React.FC<ManagerDashboardProps> = ({
  user, store, coupons, redemptions, onCreateCoupon, onDeleteCoupon, onValidateRedemption
}) => {
  const [view, setView] = useState<'overview' | 'manage' | 'validate'>('overview');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [couponToDelete, setCouponToDelete] = useState<Coupon | null>(null);

  // Validation State
  const [validationCode, setValidationCode] = useState('');
  const [validationResult, setValidationResult] = useState<'idle' | 'success' | 'error' | 'expired'>('idle');
  const [validationMessage, setValidationMessage] = useState('');
  const [isValidating, setIsValidating] = useState(false);

  // Scanner State
  const [isScannerOpen, setIsScannerOpen] = useState(false);

  // Form State
  const [newCoupon, setNewCoupon] = useState({
    title: '', description: '', discountValue: 0, quantity: 100, maxUsesPerUser: 1
  });

  // Derived Data
  const myCoupons = useMemo(() => coupons.filter(c => c.storeId === store.id), [coupons, store.id]);
  const myRedemptions = useMemo(() => redemptions.filter(r => myCoupons.find(c => c.id === r.couponId)), [redemptions, myCoupons]);

  // Stats
  const totalRedemptions = myRedemptions.length;
  const validatedRedemptions = myRedemptions.filter(r => r.status === 'USED').length;
  const activeCoupons = myCoupons.length;
  const uniqueUsersServed = new Set(myRedemptions.map(r => r.userId)).size;

  // Scanner Logic
  useEffect(() => {
    let scanner: any = null;
    let timer: any = null;

    if (isScannerOpen) {
      timer = setTimeout(() => {
        try {
          scanner = new Html5QrcodeScanner(
            "reader",
            { 
              fps: 10, 
              qrbox: { width: 250, height: 250 },
              aspectRatio: 1.0,
              showTorchButtonIfSupported: true 
            },
            false
          );

          scanner.render(
            (decodedText: string) => {
              setValidationCode(decodedText);
              setIsScannerOpen(false); 
              // Auto trigger validation
              handleValidate(undefined, decodedText);
            },
            (error: any) => {
              // Ignore errors
            }
          );
        } catch (err) {
          console.error("Error initializing scanner:", err);
        }
      }, 100);
    }

    return () => {
      if (timer) clearTimeout(timer);
      if (scanner) {
        scanner.clear().catch((error: any) => {
          console.error("Failed to clear scanner", error);
        });
      }
    };
  }, [isScannerOpen]);

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onCreateCoupon({
      storeId: store.id,
      title: newCoupon.title,
      description: newCoupon.description,
      discountType: 'PERCENTAGE', 
      discountValue: newCoupon.discountValue,
      expiryDate: new Date(Date.now() + 86400000 * 30).toISOString(), 
      category: store.category,
      availableQuantity: newCoupon.quantity,
      maxUsesPerUser: newCoupon.maxUsesPerUser,
      rules: ['Regra padrão']
    });
    setIsModalOpen(false);
  };

  const handleValidate = async (e?: React.FormEvent, codeOverride?: string) => {
    if (e) e.preventDefault();
    const codeToTest = codeOverride || validationCode;

    setIsValidating(true);
    setValidationResult('idle');

    // 1. Verify Crypto Signature
    const verification = await SecurityService.verifyToken(codeToTest);

    if (!verification.valid) {
      setIsValidating(false);
      setValidationResult(verification.reason === 'EXPIRED' ? 'expired' : 'error');
      setValidationMessage(verification.reason === 'EXPIRED' ? 'QR Code Expirado. Peça para o funcionário gerar um novo.' : 'QR Code Inválido ou Adulterado.');
      return;
    }

    // 2. If valid, check Redemption ID in "Database"
    // In our mock, we are looking for the redemption ID that matches the token's rid
    setTimeout(() => {
      // Logic adapter: we pass the rid (Redemption ID) to the app handler
      const success = onValidateRedemption(verification.data!.rid);

      if (success) {
        setValidationResult('success');
        setValidationMessage('Cupom validado com sucesso!');
      } else {
        setValidationResult('error');
        setValidationMessage('Cupom já utilizado ou não encontrado.');
      }
      setIsValidating(false);
    }, 600);
  };

  const handleDeleteConfirm = () => {
    if (couponToDelete) {
      onDeleteCoupon(couponToDelete.id);
      setCouponToDelete(null);
    }
  };

  const inputClasses = "input-base w-full px-3 py-3 rounded-xl transition-all focus:outline-none";

  return (
    <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 pt-8 pb-20">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 glass-panel p-6 rounded-3xl shadow-lg">
         <div className="flex items-center gap-4 mb-4 md:mb-0 w-full md:w-auto">
            <img src={store.logoUrl} className="w-16 h-16 rounded-xl border border-border p-1 object-contain bg-white" alt="logo" />
            <div>
              <h1 className="text-2xl font-bold text-text-main leading-none">{store.name}</h1>
              <p className="text-text-muted text-sm mt-1">Painel do Gerente • {user.name}</p>
            </div>
         </div>
         {/* Navigation Tabs */}
         <div className="flex bg-surface/50 rounded-xl p-1 border border-border">
             {[
               { id: 'overview', label: 'Visão Geral', icon: <ChartIcon /> },
               { id: 'manage', label: 'Gerenciar Cupons', icon: <ListIcon /> },
               { id: 'validate', label: 'Validar', icon: <QrCodeIcon /> }
             ].map(tab => (
               <button
                 key={tab.id}
                 onClick={() => setView(tab.id as any)}
                 className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold transition-all ${view === tab.id ? 'bg-primary-500 text-white shadow-lg' : 'text-text-muted hover:text-text-main hover:bg-surface'}`}
               >
                 {tab.icon}
                 <span className="hidden sm:inline">{tab.label}</span>
               </button>
             ))}
         </div>
      </div>

      {view === 'overview' && (
        <div className="animate-fade-in-up space-y-8">
           {/* Top Stats */}
           <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <div className="glass-panel p-5 rounded-2xl shadow-sm">
                 <p className="text-text-muted text-xs font-bold uppercase tracking-wider mb-1">Cupons Ativos</p>
                 <p className="text-3xl font-extrabold text-text-main">{activeCoupons}</p>
              </div>
              <div className="glass-panel p-5 rounded-2xl shadow-sm">
                 <p className="text-text-muted text-xs font-bold uppercase tracking-wider mb-1">Total Gerados</p>
                 <p className="text-3xl font-extrabold text-primary-500">{totalRedemptions}</p>
              </div>
              <div className="glass-panel p-5 rounded-2xl shadow-sm">
                 <p className="text-text-muted text-xs font-bold uppercase tracking-wider mb-1">Validados (Usados)</p>
                 <p className="text-3xl font-extrabold text-green-500">{validatedRedemptions}</p>
              </div>
              <div className="glass-panel p-5 rounded-2xl shadow-sm">
                 <p className="text-text-muted text-xs font-bold uppercase tracking-wider mb-1">Funcionários Únicos</p>
                 <div className="flex items-center gap-2">
                    <UserGroupIcon />
                    <p className="text-3xl font-extrabold text-text-main">{uniqueUsersServed}</p>
                 </div>
              </div>
           </div>

           <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              {/* Performance Card */}
              <div className="glass-panel p-6 rounded-2xl shadow-lg">
                 <h3 className="text-lg font-bold text-text-main mb-4">Performance dos Cupons</h3>
                 <div className="space-y-4">
                    {myCoupons.slice(0, 5).map(coupon => {
                       const usage = redemptions.filter(r => r.couponId === coupon.id).length;
                       const percentage = Math.min(100, Math.round((usage / coupon.availableQuantity) * 100));
                       return (
                         <div key={coupon.id}>
                            <div className="flex justify-between text-sm mb-1">
                               <span className="font-medium text-text-main">{coupon.title}</span>
                               <span className="text-text-muted">{usage} / {coupon.availableQuantity}</span>
                            </div>
                            <div className="w-full bg-surface rounded-full h-2.5">
                               <div className="bg-primary-500 h-2.5 rounded-full" style={{ width: `${percentage}%` }}></div>
                            </div>
                         </div>
                       );
                    })}
                    {myCoupons.length === 0 && <p className="text-text-muted text-sm">Nenhum cupom ativo para exibir dados.</p>}
                 </div>
              </div>

              {/* Recent Validations */}
              <div className="glass-panel p-6 rounded-2xl shadow-lg">
                 <h3 className="text-lg font-bold text-text-main mb-4">Últimas Validações</h3>
                 <div className="space-y-3">
                    {myRedemptions.filter(r => r.status === 'USED').slice(0, 5).sort((a,b) => new Date(b.validatedAt!).getTime() - new Date(a.validatedAt!).getTime()).map(redemption => (
                       <div key={redemption.id} className="flex items-center justify-between p-3 bg-surface/30 rounded-xl border border-border">
                          <div className="truncate pr-4">
                             <p className="text-sm font-bold text-text-main truncate" title={redemption.code}>TOKEN: ...{redemption.code.substring(0, 8)}</p>
                             <p className="text-xs text-text-muted">
                                {new Date(redemption.validatedAt!).toLocaleDateString('pt-BR')} às {new Date(redemption.validatedAt!).toLocaleTimeString('pt-BR', {hour: '2-digit', minute:'2-digit'})}
                             </p>
                          </div>
                          <span className="text-xs font-medium text-green-500 bg-green-500/10 px-2 py-1 rounded border border-green-500/20 whitespace-nowrap">Validado</span>
                       </div>
                    ))}
                    {myRedemptions.filter(r => r.status === 'USED').length === 0 && (
                      <div className="text-center py-8 text-text-muted text-sm border border-dashed border-border rounded-xl">
                        Nenhuma validação registrada ainda.
                      </div>
                    )}
                 </div>
              </div>
           </div>
        </div>
      )}

      {view === 'manage' && (
        <div className="animate-fade-in-up">
           <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-bold text-text-main">Todos os Cupons</h2>
              <Button onClick={() => setIsModalOpen(true)}>+ Criar Cupom</Button>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {myCoupons.map(coupon => (
                 <div key={coupon.id} className="glass-panel p-5 rounded-2xl shadow-sm hover:shadow-primary-500/10 hover:border-primary-500/30 transition-all group flex flex-col relative">
                    <button 
                      onClick={() => setCouponToDelete(coupon)}
                      className="absolute top-4 right-4 text-text-muted hover:text-red-500 transition-colors p-1"
                      title="Excluir Cupom"
                    >
                       <TrashIcon />
                    </button>

                    <h3 className="font-bold text-text-main mb-2 group-hover:text-primary-500 transition-colors line-clamp-1 pr-8">{coupon.title}</h3>
                    <p className="text-sm text-text-muted mb-4 line-clamp-2">{coupon.description}</p>

                    <div className="mt-auto pt-4 border-t border-border space-y-2">
                       <div className="flex justify-between text-sm">
                          <span className="text-text-muted">Desconto</span>
                          <span className="text-primary-500 font-bold">{coupon.discountValue}% OFF</span>
                       </div>
                       <div className="flex justify-between text-sm">
                          <span className="text-text-muted">Limite Usuário</span>
                          <span className="text-text-main">{coupon.maxUsesPerUser}x</span>
                       </div>
                       <div className="flex justify-between text-sm">
                          <span className="text-text-muted">Total Estoque</span>
                          <span className="text-text-main">{coupon.availableQuantity}</span>
                       </div>
                    </div>
                 </div>
              ))}
              <div 
                onClick={() => setIsModalOpen(true)}
                className="border-2 border-dashed border-border rounded-2xl flex flex-col items-center justify-center p-6 text-text-muted cursor-pointer hover:border-primary-500 hover:bg-primary-500/10 hover:text-primary-500 transition-all min-h-[200px]"
              >
                 <span className="text-4xl mb-2 font-light">+</span>
                 <span className="font-medium text-sm">Novo Cupom</span>
              </div>
           </div>
        </div>
      )}

      {view === 'validate' && (
        <div className="max-w-md mx-auto glass-panel p-8 rounded-3xl shadow-2xl animate-pop-in">
           <h2 className="text-xl font-bold text-text-main mb-6 text-center">Validar Cupom</h2>

           <div className="mb-6 flex justify-center">
              <button 
                type="button"
                onClick={() => setIsScannerOpen(true)}
                className="flex flex-col items-center justify-center w-full py-6 border-2 border-dashed border-primary-500/30 rounded-2xl bg-primary-500/5 hover:bg-primary-500/10 transition-colors group"
              >
                <div className="w-12 h-12 bg-surface rounded-full flex items-center justify-center shadow-sm mb-2 group-hover:scale-110 transition-transform">
                   <svg className="w-6 h-6 text-primary-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" />
                   </svg>
                </div>
                <span className="text-primary-500 font-semibold">Escanear QR Code</span>
                <span className="text-xs text-text-muted mt-1">Utilizar câmera do dispositivo</span>
              </button>
           </div>

           <div className="relative flex py-2 items-center mb-6">
              <div className="flex-grow border-t border-border"></div>
              <span className="flex-shrink-0 mx-4 text-text-muted text-xs uppercase">Ou cole o token</span>
              <div className="flex-grow border-t border-border"></div>
           </div>

           <form onSubmit={(e) => handleValidate(e)}>
             <label className="block text-sm font-medium text-text-muted mb-2">Token Seguro</label>
             <input 
               type="text" 
               className="input-base block w-full px-4 py-3 text-sm font-mono rounded-xl focus:ring-2 focus:ring-primary-500 focus:border-primary-500 mb-6"
               placeholder="Cole o token Base64..."
               value={validationCode}
               onChange={(e) => {
                 setValidationCode(e.target.value);
                 setValidationResult('idle');
               }}
             />
             <Button fullWidth type="submit" disabled={isValidating}>
                {isValidating ? <><Spinner /> Verificando...</> : 'Validar Agora'}
             </Button>
           </form>

           {validationResult !== 'idle' && (
             <div className={`mt-6 p-4 rounded-xl text-center border ${
                 validationResult === 'success' ? 'bg-green-500/20 text-green-500 border-green-500/30' : 
                 validationResult === 'expired' ? 'bg-orange-500/20 text-orange-500 border-orange-500/30' :
                 'bg-red-500/20 text-red-500 border-red-500/30'
               } animate-fade-in`}>
               {validationResult === 'success' ? (
                 <div className="flex flex-col items-center">
                    <div className="w-8 h-8 bg-green-500/20 rounded-full flex items-center justify-center mb-2">
                       <svg className="w-5 h-5 text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                    </div>
                    <p className="font-bold">{validationMessage}</p>
                 </div>
               ) : (
                 <div className="flex flex-col items-center">
                    <div className="w-8 h-8 bg-current opacity-20 rounded-full flex items-center justify-center mb-2">
                       <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                    </div>
                    <p className="font-bold">{validationMessage}</p>
                 </div>
               )}
             </div>
           )}
        </div>
      )}

      {/* Create Modal */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)}>
         <div className="p-6 bg-main">
            <h2 className="text-xl font-bold mb-6 text-text-main">Novo Cupom</h2>
            <form onSubmit={handleCreateSubmit} className="space-y-4">
               <div>
                 <label className="block text-sm text-text-muted mb-1">Título</label>
                 <input required className={inputClasses} value={newCoupon.title} onChange={e => setNewCoupon({...newCoupon, title: e.target.value})} />
               </div>
               <div>
                 <label className="block text-sm text-text-muted mb-1">Descrição</label>
                 <textarea required className={inputClasses} value={newCoupon.description} onChange={e => setNewCoupon({...newCoupon, description: e.target.value})} />
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm text-text-muted mb-1">Desconto (%)</label>
                    <input type="number" required className={inputClasses} value={newCoupon.discountValue} onChange={e => setNewCoupon({...newCoupon, discountValue: Number(e.target.value)})} />
                  </div>
                  <div>
                    <label className="block text-sm text-text-muted mb-1">Qtd Total</label>
                    <input type="number" required className={inputClasses} value={newCoupon.quantity} onChange={e => setNewCoupon({...newCoupon, quantity: Number(e.target.value)})} />
                  </div>
               </div>
               <div>
                 <label className="block text-sm text-text-muted mb-1">Limite por Usuário</label>
                 <input type="number" min="1" required className={inputClasses} value={newCoupon.maxUsesPerUser} onChange={e => setNewCoupon({...newCoupon, maxUsesPerUser: Number(e.target.value)})} />
                 <p className="text-xs text-text-muted mt-1">Quantas vezes o mesmo funcionário pode resgatar este cupom.</p>
               </div>
               <Button fullWidth type="submit" className="mt-4">Publicar Cupom</Button>
            </form>
         </div>
      </Modal>

      {/* Scanner Modal */}
      <Modal isOpen={isScannerOpen} onClose={() => setIsScannerOpen(false)}>
         <div className="p-6 bg-main">
            <h2 className="text-xl font-bold text-text-main mb-4 text-center">Escanear Cupom</h2>
            <div className="relative bg-black rounded-2xl overflow-hidden shadow-inner border border-border">
               <div id="reader" className="w-full"></div>
            </div>
            <p className="text-center text-sm text-text-muted mt-4">Aponte a câmera para o QR Code do funcionário.</p>
            <div className="mt-4 flex justify-center">
              <Button variant="secondary" onClick={() => setIsScannerOpen(false)}>Cancelar</Button>
            </div>
         </div>
      </Modal>

      {/* Confirmation Modal */}
      <ConfirmationModal
        isOpen={!!couponToDelete}
        onClose={() => setCouponToDelete(null)}
        onConfirm={handleDeleteConfirm}
        title="Excluir Cupom"
        message={`Tem certeza que deseja excluir "${couponToDelete?.title}"? Esta ação não pode ser desfeita.`}
        confirmText="Excluir Cupom"
      />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { STORES, COUPONS, MY_REDEMPTIONS, USERS } from './constants';
import { Coupon, Store, User, UserRole, Redemption } from './types';
import { LoginScreen } from './components/LoginScreen';
import { EmployeeDashboard } from './components/EmployeeDashboard';
import { ManagerDashboard } from './components/ManagerDashboard';
import { AdminDashboard } from './components/AdminDashboard';
import { ProfileModal } from './components/ProfileModal';

// Icons
const MoonIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" /></svg>;
const SunIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" /></svg>;
const SparklesIcon = () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z" /></svg>;

type Theme = 'dark' | 'emerald' | 'indigo';

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [theme, setTheme] = useState<Theme>('dark');

  // Global Data State
  const [coupons, setCoupons] = useState<Coupon[]>(COUPONS);
  const [redemptions, setRedemptions] = useState<Redemption[]>(MY_REDEMPTIONS);
  const [stores, setStores] = useState<Store[]>(STORES);
  const [users, setUsers] = useState<User[]>(USERS);

  // UI State
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [showThemeMenu, setShowThemeMenu] = useState(false);

  // Apply Theme
  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
  }, [theme]);

  const handleLogin = (identifier: string) => {
    const id = identifier.toLowerCase();
    const foundUser = users.find(u => u.email === id);

    if (foundUser) {
      setUser(foundUser);
    } else {
      if (id.includes('admin')) setUser(users.find(u => u.role === UserRole.ADMIN) || null);
      else if (id.includes('zara')) setUser(users.find(u => u.role === UserRole.MANAGER) || null);
      else setUser(users.find(u => u.role === UserRole.EMPLOYEE) || null);
    }
  };

  const handleLogout = () => setUser(null);

  // Store Management Actions
  const handleAddStore = (newStoreData: Omit<Store, 'id'>) => {
    const newStore: Store = { ...newStoreData, id: `s${Date.now()}` };
    setStores([...stores, newStore]);
  };

  const handleUpdateStore = (updatedStore: Store) => {
    setStores(stores.map(s => s.id === updatedStore.id ? updatedStore : s));
  };

  const handleDeleteStore = (storeId: string) => {
    setStores(stores.filter(s => s.id !== storeId));
  };

  // User Management Actions
  const handleAddUser = (newUserData: Omit<User, 'id'>) => {
    const newUser: User = { ...newUserData, id: `u${Date.now()}` };
    setUsers([...users, newUser]);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(users.map(u => u.id === updatedUser.id ? updatedUser : u));
    if (user && user.id === updatedUser.id) {
       setUser(updatedUser);
    }
  };

  const handleDeleteUser = (userId: string) => {
    setUsers(users.filter(u => u.id !== userId));
  };

  const handleProfileUpdate = (data: Partial<User> & { password?: string }) => {
    if (!user) return;
    const updatedUser = { ...user, ...data };
    delete (updatedUser as any).password;
    setUsers(users.map(u => u.id === user.id ? updatedUser : u));
    setUser(updatedUser);
  };

  const handleCreateCoupon = (couponData: Omit<Coupon, 'id'>) => {
    const newCoupon: Coupon = { ...couponData, id: `new_${Date.now()}` };
    setCoupons(prev => [newCoupon, ...prev]);
  };

  const handleDeleteCoupon = (couponId: string) => {
    setCoupons(prev => prev.filter(c => c.id !== couponId));
  };

  const handleRedeem = (couponId: string, token: string, redemptionId: string) => {
    if (user) {
      setRedemptions(prev => [{
        id: redemptionId, // Use the ID from the token
        couponId,
        userId: user.id,
        code: token, // Store the signed token as the code
        status: 'PENDING',
        redeemedAt: new Date().toISOString()
      }, ...prev]);
    }
  };

  const handleValidateRedemption = (redemptionId: string): boolean => {
    // In the new flow, we search by ID, not by the long token string which might change in UI display
    const redemption = redemptions.find(r => r.id === redemptionId && r.status === 'PENDING');

    if (redemption) {
      setRedemptions(prev => prev.map(r => 
        r.id === redemption.id ? { ...r, status: 'USED', validatedAt: new Date().toISOString(), validatedBy: user?.name } : r
      ));
      return true;
    }
    return false;
  };

  if (!user) {
    return <LoginScreen onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen font-sans selection:bg-primary-500 selection:text-white overflow-x-hidden relative">
      {/* Ambient Background Blobs for Glassmorphism */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none z-0">
         <div className="absolute top-0 -left-4 w-96 h-96 bg-primary-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob"></div>
         <div className="absolute top-0 -right-4 w-96 h-96 bg-purple-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob" style={{ animationDelay: '2s' }}></div>
         <div className="absolute -bottom-8 left-20 w-96 h-96 bg-pink-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob" style={{ animationDelay: '4s' }}></div>
      </div>

      <div className="relative z-10">
        {/* Global Navbar */}
        <nav className="glass-panel sticky top-4 mx-4 md:mx-auto max-w-6xl z-40 rounded-2xl shadow-lg mt-4 mb-4">
          <div className="px-6 h-16 flex justify-between items-center">
             <div className="flex items-center gap-2 cursor-pointer hover:opacity-80 transition-opacity">
                {/* Logo Enhancement: Added shadow and border for better visibility on light themes */}
                <div className="w-8 h-8 bg-gradient-to-br from-primary-400 to-primary-600 rounded-lg flex items-center justify-center text-white font-bold shadow-md border border-white/20">
                    <span className="drop-shadow-md">SP</span>
                </div>
                <span className="font-bold text-text-main tracking-tight hidden sm:block">ShopPerks</span>
             </div>
             <div className="flex items-center gap-4">
                {/* Theme Switcher */}
                <div className="relative">
                  <button 
                    onClick={() => setShowThemeMenu(!showThemeMenu)}
                    className="p-2 rounded-full text-text-muted hover:text-primary-500 hover:bg-surface/50 transition-colors"
                  >
                    {theme === 'dark' ? <MoonIcon /> : theme === 'emerald' ? <SunIcon /> : <SparklesIcon />}
                  </button>
                  {showThemeMenu && (
                    <div className="absolute top-full right-0 mt-2 w-48 glass-panel rounded-xl shadow-xl overflow-hidden animate-pop-in">
                       <button onClick={() => { setTheme('dark'); setShowThemeMenu(false); }} className={`w-full text-left px-4 py-3 text-sm flex items-center gap-2 hover:bg-primary-500/10 ${theme === 'dark' ? 'text-primary-500 font-bold' : 'text-text-main'}`}>
                          <div className="w-3 h-3 rounded-full bg-[#18181b] border border-gray-600"></div> Dark Gunmetal
                       </button>
                       <button onClick={() => { setTheme('emerald'); setShowThemeMenu(false); }} className={`w-full text-left px-4 py-3 text-sm flex items-center gap-2 hover:bg-primary-500/10 ${theme === 'emerald' ? 'text-primary-500 font-bold' : 'text-text-main'}`}>
                          <div className="w-3 h-3 rounded-full bg-[#00DC82]"></div> Emerald Light
                       </button>
                       <button onClick={() => { setTheme('indigo'); setShowThemeMenu(false); }} className={`w-full text-left px-4 py-3 text-sm flex items-center gap-2 hover:bg-primary-500/10 ${theme === 'indigo' ? 'text-primary-500 font-bold' : 'text-text-main'}`}>
                          <div className="w-3 h-3 rounded-full bg-[#6366F1]"></div> Indigo Light
                       </button>
                    </div>
                  )}
                </div>

                <span className="text-xs font-semibold text-primary-500 hidden sm:block bg-primary-900/10 px-3 py-1 rounded-full border border-primary-500/20 uppercase tracking-wide">
                   {user.role === 'ADMIN' ? 'Admin' : user.role === 'MANAGER' ? 'Gerente' : 'Funcionário'}
                </span>

                <div className="flex items-center gap-3 pl-3 border-l border-border">
                  <button onClick={() => setIsProfileOpen(true)} className="flex items-center gap-2 group">
                     <img src={user.avatarUrl || `https://ui-avatars.com/api/?name=${user.name}&background=random`} className="w-9 h-9 rounded-full border-2 border-surface shadow-sm transition-transform group-hover:scale-105 group-hover:border-primary-500" alt="avatar" />
                  </button>
                  <button onClick={handleLogout} className="text-sm font-semibold text-text-muted hover:text-red-400 transition-colors ml-2" title="Sair">
                     <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
                  </button>
                </div>
             </div>
          </div>
        </nav>

        {user.role === UserRole.EMPLOYEE && (
          <EmployeeDashboard 
            user={user} 
            stores={stores} 
            coupons={coupons} 
            redemptions={redemptions.filter(r => r.userId === user.id)}
            onRedeem={handleRedeem} 
          />
        )}

        {user.role === UserRole.MANAGER && user.storeId && (
          <ManagerDashboard 
            user={user}
            store={stores.find(s => s.id === user.storeId)!}
            coupons={coupons}
            redemptions={redemptions}
            onCreateCoupon={handleCreateCoupon}
            onDeleteCoupon={handleDeleteCoupon}
            onValidateRedemption={handleValidateRedemption}
          />
        )}

        {user.role === UserRole.ADMIN && (
          <AdminDashboard 
            stores={stores} 
            users={users} 
            coupons={coupons}
            redemptions={redemptions}
            onAddStore={handleAddStore}
            onUpdateStore={handleUpdateStore}
            onDeleteStore={handleDeleteStore}
            onAddUser={handleAddUser}
            onUpdateUser={handleUpdateUser}
            onDeleteUser={handleDeleteUser}
          />
        )}

        {/* Profile Modal */}
        {user && (
          <ProfileModal 
            user={user} 
            isOpen={isProfileOpen} 
            onClose={() => setIsProfileOpen(false)} 
            onUpdateUser={handleProfileUpdate}
          />
        )}
      </div>
    </div>
  );
}

